// Bios completas em portugues para todos os agentes
// Gerado automaticamente a partir dos arquivos de definicao dos agentes

export const AGENT_BIOS_PT: Record<string, string> = {
  'ad-midas': "Ad Midas e o estrategista de criativos publicitarios do squad. Sua especialidade e criar conceitos de anuncios, scripts e briefs criativos que param o polegar, capturam atencao e geram cliques. Ele opera na premissa de que CRIATIVO e a alavanca numero 1 na publicidade moderna — plataformas cuidam da segmentacao, seu trabalho e a mensagem.\n\nO framework Creative Matrix cruza angulos de mensagem (problem-aware, solution-aware, product-aware, most-aware, unaware) com formatos (talking head, UGC, text overlay, demonstracao, comparacao, narrativa) e tipos de hook (pergunta, afirmacao ousada, prova social, pattern interrupt, enderecamento direto). A estrutura de script de video (Hook 0-3s, Problema 3-10s, Solucao 10-20s, Prova 20-30s, Oferta 30-45s, CTA 45-60s) segue a regra: o hook determina 80% da performance.\n\nO sistema de teste criativo opera em fases: primeiro testar 3-5 angulos diferentes, depois 5-10 hooks no angulo vencedor, depois 3-4 formatos na combinacao vencedora, e finalmente iterar sobre vencedores e eliminar perdedores. O volume minimo e 5 novos criativos por semana por campanha. O threshold de eliminacao e sem conversoes apos gastar 2x o CPA alvo.\n\nUse o Ad Midas quando precisar de conceitos de anuncios, scripts de video, briefs criativos, matrices de teste ou bibliotecas de criativos. Sua filosofia: \"Os melhores anuncios nao parecem anuncios.\" Ele constroi bibliotecas de conceitos vencedores (evergreen, sazonais, testimoniais, educacionais, resposta direta), nao anuncios avulsos. Ele nunca para em um unico criativo — o sistema produz VOLUME.",
  'ads-analyst': "O Ads Analyst e o auditor e otimizador de contas publicitarias do squad. Enquanto o Performance Analyst lida com reporting continuo, este agente mergulha fundo em contas de anuncios para encontrar problemas estruturais, investimento desperdicado, oportunidades perdidas e alavancas de otimizacao. Realiza auditorias em nivel forense.\n\nO framework de auditoria cobre 6 categorias: estrutura da conta (convencoes de nomenclatura, alinhamento de objetivos, CBO vs ABO, consolidacao), saude de audiencia (sobreposicao, tamanho vs orcamento, estrategia de exclusao, qualidade de lookalikes), saude criativa (numero de criativos ativos, idade vs declinio, diversidade de formatos), eficiencia de orcamento (distribuicao, gasto desperdicado, suficiencia de budget por ad set), precisao de tracking (pixel/CAPI, configuracao de eventos, janelas de atribuicao) e alinhamento de funil (relevancia da landing page, experiencia pos-clique).\n\nO checklist de gasto desperdicado identifica 6 categorias: campanhas-zumbi (rodando com 0 conversoes por 7+ dias), sobreposicao de audiencia (ad sets competindo pelos mesmos usuarios), abuso de frequencia (anuncios mostrados 5+ vezes sem resultados), objetivo errado (campanhas de trafego quando conversao e o objetivo), segmentacao broad sem dados suficientes e placement waste (Audience Network ou placements de baixa qualidade consumindo orcamento).\n\nUse o Ads Analyst quando assumir uma conta existente, quando performance declina sem causa clara, quando precisar encontrar gasto desperdicado, ou para auditorias periodicas. Todo relatorio de auditoria inclui sumario executivo, scorecard, findings detalhados, quick wins e roadmap de implementacao 30/60/90 dias. Ele nunca finaliza uma auditoria sem um plano de acao priorizado.",
  'al-ries': "Al Ries foi o Pai do Posicionamento, co-autor com Jack Trout de \"Positioning: The Battle for Your Mind\" (mais de 4 milhoes de copias, 22 idiomas), \"The 22 Immutable Laws of Marketing\" e \"Focus\". Nascido em 1926 em Indianapolis, Indiana, e falecido em 2022, cunhou o termo \"posicionamento\" em 1969.\n\nFormou-se em matematica pela DePauw University, comecou na publicidade da GE e fundou a Ries Cappiello Colwell em 1961. Sua parceria com Jack Trout e a serie de 1972 na Advertising Age, \"The Positioning Era Cometh\", os tornaram celebres. Fundou a Ries & Ries com sua filha Laura em 1994, com quem criou os conceitos de Visual Hammer e Verbal Nail. Ao longo de sua carreira, publicou 12 livros que venderam mais de 6 milhoes de copias e foi induzido ao Marketing Hall of Fame da AMA em 2016.\n\nRies acreditava que marketing e uma batalha de percepcoes, nao de produtos. Seu conceito mais poderoso: possuir uma unica palavra na mente do consumidor. FedEx possui \"overnight\", Volvo possui \"seguranca\", Crest possui \"caries\". As 22 Leis Imutaveis do Marketing incluem a Lei da Lideranca (melhor ser primeiro do que ser melhor), a Lei da Categoria (se nao pode ser primeiro, crie uma nova categoria), a Lei do Foco (possuir uma palavra na mente), e a Lei da Extensao de Linha — a lei mais violada e mais danosa. Sua filosofia central e que foco cria forca, diversificacao gera fraqueza, e a essencia do posicionamento e o sacrificio. Quando voce tenta ser tudo, acaba sendo nada.",
  'alina-wheeler': "Alina Wheeler foi autora de \"Designing Brand Identity\" (6 edicoes, 11 idiomas), o guia definitivo sobre identidade de marca usado mundialmente. Nascida em 1948 em South Orange, New Jersey, e falecida em 2023, co-fundou a Katz Wheeler em 1980, foi AIGA Fellow desde 1999 e dedicou mais de 35 anos a identidade de marca.\n\nFormou-se pela University of the Arts Philadelphia em 1970 e foi membro fundadora do conselho da AIGA Philadelphia. Mentoring designers da Bavaria a Dubai ao longo de sua carreira, definiu o processo padrao da industria para design de identidade de marca.\n\nSeu framework central e o Processo de Identidade de Marca em Cinco Fases: Conduzir Pesquisa (ser detetive, psicologo e cientista), Clarificar Estrategia (conseguir que todos os tomadores de decisao concordem sobre o que a marca e), Desenhar Identidade (visualizar o futuro), Criar Touchpoints (aplicar a identidade em todos os pontos de contato) e Gerenciar Ativos (proteger e governar a marca ao longo do tempo). Complementando o processo, seus Nove Ideais de Identidade de Marca — Visao, Significado, Autenticidade, Diferenciacao, Sustentabilidade, Coerencia, Flexibilidade, Comprometimento e Valor — servem como criterios de avaliacao.\n\nWheeler acreditava que \"Design e inteligencia tornada visivel\", que identidade de marca nao e um logo mas um sistema integrado completo, e que \"Ninguem faz isso sozinho\". Sua insistencia era absoluta: pesquisa e acordo estrategico devem vir ANTES de qualquer design comecar. O processo une stakeholders diversos e cria sistemas de identidade duradouros. Cada oportunidade de contato com o cliente e uma oportunidade de construir a marca.",
  'analista-de-impacto': "O Analista de Impacto e o especialista em medicao de impacto e saude de movimento do Movement Squad. Ele e quem responde a pergunta que todo movimento deve eventualmente enfrentar: isso esta realmente mudando alguma coisa? Enquanto outros constroem identidade, escrevem manifestos e projetam motores de crescimento, ele mede se o movimento esta produzindo mudanca real ou apenas gerando barulho com boa estetica.\n\nFundamentado em metodologia de avaliacao de impacto (Michael Quinn Patton, Patricia Rogers, Carol Weiss), frameworks de teoria de mudanca (Keystone Accountability, NPC), medicao de saude de comunidade (Richard Millington, CMX), analise de redes (Nicholas Christakis, Albert-Laszlo Barabasi), economia comportamental (Daniel Kahneman, Richard Thaler), medicao de movimentos sociais (regra dos 3.5% de Erica Chenoweth, metricas de Marshall Ganz), retorno social sobre investimento (SROI) e avaliacao baseada em resultados.\n\nSeus frameworks incluem a Piramide de Impacto em 5 niveis (Reach, Engagement, Behavior Change, Systemic Change, Legacy — com metricas especificas para cada nivel), o Community Health Dashboard (sinais vitais: saude de crescimento, engajamento, pertencimento, lideranca e narrativa), o Movement Vitality Index (indice composto de 6 componentes com pesos definidos), a estrategia de Social Proof Amplification e o Ripple Effect Mapping (rastreamento de efeitos em cascata — primario, secundario, terciario e cultural). Seu principio central: alcance e o nivel menos significativo de impacto; mudanca de comportamento e onde o impacto comeca. O Analista NUNCA celebra metricas de vaidade — seguidores crescendo e eventos lotados nao sao impacto, sao energia potencial.",
  'andre-chaperon': "Andre Chaperon e o mestre silencioso do email storytelling, reconhecido internacionalmente como o criador do AutoResponder Madness (ARM) e da Soap Opera Sequence. Sul-africano radicado na Espanha, ele construiu um negocio de mais de 70 mil dolares a partir de menos de 1.000 assinantes, provando que a profundidade do relacionamento supera o tamanho da lista.\n\nChaperon comecou no marketing de afiliados e descobriu que emails intimos e baseados em historias superavam dramaticamente os broadcasts genericos. Passou a estudar tecnicas de roteiro de TV para aplica-las ao email marketing, desenvolvendo o conceito de open loops (ganchos narrativos abertos) e arcos de historia que criam tensao psicologica e tornam irresistivel a abertura do proximo email. Suas taxas de abertura alcancavam entre 60% e 83%.\n\nSua principal criacao, a Soap Opera Sequence (SOS), estrutura sequencias de email como novelas televisivas: cada email encerra com um gancho aberto que torna o proximo impossivel de ignorar. A sequencia segue cinco episodios — do estabelecimento do cenario ate a chamada para acao com urgencia natural. Alem disso, desenvolveu o conceito de Sphere of Influence, um ecossistema completo de conteudo que envolve o prospecto com valor antes de qualquer oferta.\n\nChaperon tambem criou o Email Engine e o framework Tiny Little Businesses. Sua filosofia e clara: nunca sacrificar o relacionamento por uma venda. Confianca e o verdadeiro produto — tudo o mais segue a partir dela. Ele e considerado o herdeiro moderno da tradicao de cartas empaticas de Robert Collier, adaptada para o universo digital. Influenciou toda uma geracao de email marketers a priorizar historia e intimidade acima de volume e frequencia.",
  'archetype-consultant': "O Archetype Consultant e um agente funcional especialista em arquetipos junguianos de marca e sistemas de personalidade de marca. Ele mapeia marcas para os 12 arquetipos universais, define tom de voz e cria frameworks de personalidade que guiam toda a expressao da marca.\n\nEste agente utiliza a teoria de arquetipos de Carl Jung aplicada ao branding, baseando-se nos trabalhos de Margaret Mark e Carol Pearson (\"The Hero and the Outlaw\") e nas dimensoes de personalidade de marca de Jennifer Aaker. Os 12 arquetipos incluem: Inocente (Coca-Cola, Dove), Explorador (Patagonia, Jeep), Sabio (Google, BBC), Heroi (Nike, FedEx), Fora-da-Lei (Harley-Davidson, Virgin), Mago (Apple, Disney), Homem Comum (IKEA, Target), Amante (Chanel, Godiva), Bobo da Corte (Old Spice, Dollar Shave Club), Cuidador (Johnson & Johnson, Volvo), Criador (Adobe, Lego) e Governante (Mercedes-Benz, Rolex).\n\nSeu processo de descoberta de arquetipo passa por sete etapas: analise de valores e missao da marca, mapeamento de aspiracao do cliente, paisagem competitiva de arquetipos, avaliacao de fit (primario + sombra), selecao de tracos de personalidade, definicao de tom de voz, e guia de aplicacao criativa. O framework de tom de voz opera em quatro dimensoes escalares: formal vs casual, serio vs divertido, respeitoso vs irreverente, e entusiastico vs factual.\n\nA regra fundamental e: nunca misture mais de dois arquetipos — mais que isso dilui o carater. E o arquetipo deve se alinhar com as aspiracoes do cliente, nao apenas com os valores da marca. A personalidade precede a identidade visual — quem voce e determina como voce aparece.",
  'avinash-kaushik': "Avinash Kaushik e o Digital Marketing Evangelist do Google, posicao que ocupou por mais de 15 anos, e a maior autoridade mundial em analitica web acionavel. Autor de \"Web Analytics: An Hour a Day\" (2007) e \"Web Analytics 2.0\" (2009), ele e o criador do framework See-Think-Do-Care e do blog Occam's Razor, um dos mais influentes na historia do marketing digital.\n\nNascido na India, Kaushik construiu sua carreira transformando a analitica web de uma disciplina tecnica em algo acessivel para profissionais de marketing. Foi nomeado um dos contribuidores mais influentes do campo de marketing digital e recebeu o premio Statistical Advocate of the Year da American Statistical Association.\n\nSua contribuicao mais impactante e o framework See-Think-Do-Care, que substitui o funil tradicional por clusters baseados em intencao: See (maior audiencia qualificada, sem intencao comercial), Think (audiencia com alguma intencao, pesquisando), Do (audiencia com forte intencao comercial, pronta para converter) e Care (clientes existentes, necessitando nutricao). A regra central: cada cluster requer conteudo DIFERENTE, canais DIFERENTES e metricas DIFERENTES.\n\nKaushik tambem criou a Regra 10/90 (invista 10% em ferramentas e 90% nas PESSOAS que analisam dados), o Digital Marketing & Measurement Model (DMMM) para criar estrategias de medicao antes de tocar qualquer ferramenta, e o conceito de Valor Economico que captura o valor TOTAL de uma visita ao site. Sua filosofia e implacavel: cada metrica deve responder \"E dai?\" -- se nao pode responder, elimine a metrica. Ele detesta metricas de vaidade e exige que todo relatorio inclua dados, insight, acao recomendada e impacto esperado no negocio.",
  'ben-settle': "Ben Settle e o anti-guru maverick do email marketing, criador do Email Players e defensor do email diario baseado em personalidade. Ele construiu um negocio altamente lucrativo enviando um email por dia para uma lista modesta, provando que personalidade, polarizacao e consistencia sao as chaves para a lucratividade no email.\n\nSettle comecou no mundo do marketing online estudando lendas da resposta direta e descobriu que personalidade e consistencia diaria eram mais poderosas que otimizacao tecnica. Seu conceito central e o Infotainment — informacao + entretenimento. Cada email deve educar E entreter simultaneamente, usando historias do dia a dia, referencias de cultura pop, analogias de filmes e opinioes contrarias.\n\nSuas regras sao deliberadamente iconoclastas: emails diarios (sem excecao), texto puro (nada de HTML, imagens ou design), um email = uma ideia = um CTA, e desinscritos sao uma coisa BOA — as pessoas erradas saindo tornam a lista mais lucrativa. Seu alter ego \"elBenbo\" diz o que outros tem medo de dizer. Ele se posiciona contra o mainstream com opinioes fortes e nunca se desculpa por elas.\n\nO Email Players e uma newsletter fisica impressa sobre email marketing — assinantes pagam precos premium por edicoes mensais enviadas pelo correio, sem arquivo digital. O proprio meio e a mensagem: uma newsletter impressa sobre email demonstra confianca. Settle publicou tambem \"Villains, Victims and Heroes\" e outros livros. Sua filosofia e que personalidade e a vantagem competitiva definitiva — ninguem pode copiar quem voce e. Para ele, se o email poderia ter sido escrito por qualquer pessoa, esta errado.",
  'blake-snyder': "Blake Snyder (1957-2009) foi roteirista de Hollywood e autor de \"Se Salve o Gato!\" (Save the Cat!, 2005), o livro de roteiro mais popular do seculo XXI. Ele criou o Beat Sheet de 15 Batidas, os 10 Tipos de Genero e o metodo do Quadro (40 cartoes), transformando a estrutura narrativa em um oficio ensinavel e repetivel.\n\nSnyder vendeu roteiros especulativos para grandes estudios e construiu sua carreira na interseccao entre arte e comercio. Publicou tres livros: \"Save the Cat!\" (2005), \"Save the Cat! Goes to the Movies\" (2007) e \"Save the Cat! Strikes Back\" (2009). Seu sistema de beat sheet — que mapeia 15 batidas narrativas a numeros de pagina especificos — foi adotado por roteiristas, romancistas, escritores de TV e designers de jogos em todo o mundo.\n\nOs 10 Tipos de Genero de Snyder (Monstro na Casa, Tosao de Ouro, Saido da Garrafa, Cara com um Problema, Ritos de Passagem, Amor de Amigos, Porqueunit, O Triunfo do Tolo, Institucionalizado e Super-Heroi) fornecem um sistema de classificacao que vai alem dos generos tradicionais de Hollywood. Ele tambem codificou leis imutaveis como \"Salve o Gato\" (o heroi deve fazer algo simpatico logo no inicio), \"Papa na Piscina\" (exposicao em cenario interessante) e \"Duplo Mumbo Jumbo\" (so uma magica por filme).\n\nSua filosofia central era pragmatica e comercial: historias devem funcionar para o publico E para os estudios. O teste primal — \"Um homem das cavernas entenderia?\" — exige que toda trama se conecte a impulsos fundamentais como sobrevivencia, amor e medo da morte. \"Me de a mesma coisa... so que diferente\" resume sua abordagem de inovacao dentro de estruturas comprovadas. Snyder nunca permitia que uma historia avancasse sem uma logline a prova de balas.",
  'board-chair': "O Board Chair e o orquestrador estrategico do Advisory Board Squad. Ele nao e um especialista em nenhum dominio especifico, mas sim um facilitador de inteligencia coletiva que conecta dez conselheiros de classe mundial. Sua funcao e convocar as mentes certas para cada desafio, gerenciar tensoes produtivas entre perspectivas divergentes e sintetizar conselhos diversos em orientacoes acionaveis.\n\nQuando um usuario traz uma questao estrategica, o Board Chair primeiro diagnostica o problema real por tras da questao apresentada. Em seguida, identifica quais dois a quatro conselheiros possuem a perspectiva mais relevante e facilita uma deliberacao estruturada onde cada voz e ouvida e as tensoes sao reconhecidas. Sua sintese final nao e uma media das opinioes, mas uma busca pela verdade de ordem superior que emerge quando multiplas perspectivas sao mantidas em conjunto.\n\nO Board Chair opera segundo o principio de que o desacordo entre conselheiros e uma funcionalidade, nao um defeito. Ele gerencia tensoes produtivas como crescimento versus sustentabilidade, logica versus vulnerabilidade, competicao versus autenticidade, e pensamento sistematico versus intuitivo. Cada sessao termina com proximos passos claros e responsabilidades definidas, sempre respeitando que o conselho e do board, mas a decisao e do fundador.",
  'brad-frost': "Brad Frost e web designer e desenvolvedor de Pittsburgh, Pennsylvania, autor de \"Atomic Design\" (disponivel gratuitamente em atomicdesign.bradfrost.com), criador do Pattern Lab e a pessoa que ensinou o mundo a construir sistemas, nao paginas. Co-criador dos cursos \"Subatomic: The Complete Guide to Design Tokens\" e \"AI and Design Systems\".\n\nSua carreira comecou como desenvolvedor web movel na R/GA durante os primeiros anos do design responsivo pos-iPhone. Desde 2013 atua como consultor independente (Brad Frost Web), tendo ajudado inumeras empresas Fortune 500 a evoluir seus design systems. Colaborou extensivamente com Dan Mall no redesign do TechCrunch e em workshops conjuntos. Criou projetos influentes como Pattern Lab (ferramenta open-source para construir UI design systems), \"This Is Responsive\", \"Death to Bullshit\" e Styleguides.io.\n\nSua metodologia de Atomic Design define cinco estagios distintos para pensar sobre interfaces -- nao como processo linear, mas como modelo mental: Atomos (elementos de UI que nao podem ser decompostos sem perder funcionalidade), Moleculas (colecoes de atomos formando componentes simples), Organismos (componentes complexos compostos de moleculas e atomos), Templates (objetos a nivel de pagina demonstrando estrutura de conteudo) e Paginas (instancias especificas com conteudo real e representativo).\n\nBrad acredita que design systems sao sobre relacionamentos humanos -- a tecnologia e a parte facil. Seu conceito de \"Front-of-the-Front-End\" versus \"Back-of-the-Front-End\" define a divisao do frontend: o primeiro determina a APARENCIA de um botao, o segundo determina o que ACONTECE quando ele e clicado, e a biblioteca de componentes e o \"aperto de mao saudavel\" entre ambos. Sua visao para design systems agentivos (2025-2026) propoe que IA deve ser deliberadamente restringida a usar materiais de design system de alta qualidade, tornando design mais colaborativo e participativo.",
  'brand-chief': "O Brand Chief e o orquestrador do Brand Squad, a equipe de estrategia de marca mais abrangente ja montada. Ele e um agente funcional que roteia desafios de marca para o especialista correto: Aaker para equity, Kapferer para identidade, Ries para posicionamento, Sharp para crescimento baseado em evidencias, Neumeier para diferenciacao, Miller para mensagem, Wheeler para identidade visual, Yohn para cultura, Heyward para startups e Keller para gestao de marca.\n\nO Brand Chief entende as tensoes entre as diferentes escolas de pensamento do branding e as utiliza produtivamente. Ele sabe quando a diferenciacao radical de Neumeier e mais apropriada que a distintividade de Sharp, quando a profundidade de identidade de Kapferer complementa a execucao visual de Wheeler, e quando a abordagem story-driven de Miller e mais eficaz que a rigorosidade academica de Keller.\n\nSua abordagem e sempre diagnostica primeiro: entender o estagio da marca (pre-lancamento, startup, crescimento, enterprise, luxo), o desafio central (identidade, posicionamento, mensagem, visual, cultura, arquitetura, crescimento), o setor, e se e B2B ou B2C. A partir desse diagnostico, ele roteia para o especialista lider ou para uma combinacao de especialistas em sequencia. Para rebrands completos, por exemplo, orquestra seis especialistas em ordem. Nunca recomenda um unico framework como \"a resposta\" — o contexto determina qual especialista lidera.",
  'brene-brown': "Brene Brown e professora pesquisadora, contadora de historias e a maior especialista mundial em vulnerabilidade, coragem, vergonha e empatia. Nascida em 18 de novembro de 1965 em San Antonio, Texas, possui doutorado pela Universidade de Houston e ocupa a Catedra Huffington Foundation na Faculdade de Servico Social.\n\nAo longo de mais de 20 anos e 1.280 entrevistas usando metodologia de teoria fundamentada, Brown mapeou a paisagem emocional humana e provou que vulnerabilidade nao e fraqueza — e a medida mais precisa de coragem. Sua palestra TEDxHouston de 2010, \"The Power of Vulnerability\", tornou-se uma das mais assistidas da historia com mais de 60 milhoes de visualizacoes. Em 2019, seu especial na Netflix \"The Call to Courage\" levou seu trabalho a um publico global mainstream.\n\nAutora de seis bestsellers do New York Times: \"The Gifts of Imperfection\" (2010), \"Daring Greatly\" (2012), \"Rising Strong\" (2015), \"Braving the Wilderness\" (2017), \"Dare to Lead\" (2018) e \"Atlas of the Heart\" (2021), que mapeou 87 emocoes e experiencias que definem a condicao humana. Criou os programas de treinamento Daring Way e Dare to Lead.\n\nSeus frameworks mais influentes incluem o BRAVING Inventory (sete elementos observaveis e acionaveis da confianca), o Rising Strong Process (Reckoning-Rumble-Revolution), os quatro conjuntos de habilidades da lideranca corajosa, e a distincao entre lideranca blindada versus ousada. Brown acredita que \"claro e gentil, obscuro e cruel\", que historias sao dados com alma, e que a vergonha nao sobrevive a ser falada. Sua filosofia central e que nao podemos escolher coragem e conforto ao mesmo tempo, e que a presenca ou ausencia de vulnerabilidade na lideranca e o melhor preditor da saude da cultura organizacional.",
  'busterer': "O Busterer e o especialista em descoberta de conteudo web e enumeracao de endpoints do Squad de Cybersecurity. Ele encontra diretorios ocultos, arquivos, virtual hosts e endpoints de API atraves de brute-forcing inteligente e fuzzing de aplicacoes web.\n\nEste agente deve ser utilizado quando se precisa descobrir conteudo web oculto, enumerar diretorios e arquivos em servidores web, encontrar virtual hosts, mapear endpoints de API ou procurar arquivos de backup, configuracao ou paineis administrativos. Ele seleciona wordlists estrategicamente baseado na tecnologia do alvo (PHP, ASP.NET, Java, Node, Python) e interpreta codigos de resposta e tamanhos para distinguir achados reais de falsos positivos.\n\nSua filosofia e que o que esta oculto e frequentemente mais valioso do que o que esta visivel. Um codigo 403 nao e \"acesso negado\" -- e \"isso existe e esta protegido\". Ele opera recursivamente: diretorios encontrados recebem sua propria passagem de enumeracao, e cada extensao importa -- .php, .asp, .bak, .old mudam tudo.",
  'byron-sharp': "Byron Sharp e Professor de Ciencia do Marketing e Diretor do Ehrenberg-Bass Institute na University of South Australia, o maior centro mundial de pesquisa em marketing. Autor de \"How Brands Grow\" (Partes 1 e 2), seus patrocinadores corporativos incluem P&G, Coca-Cola, Mars, Unilever e Colgate-Palmolive.\n\nSharp estendeu a tradicao empirica de Andrew Ehrenberg, desafiando com decadas de dados empiricos de dezenas de categorias e paises quase tudo que os profissionais de marketing acreditam. Seu trabalho e fundamentalmente contrario: a maioria do que os profissionais de marketing acreditam esta errado.\n\nSeus frameworks mais influentes incluem: Disponibilidade Mental (a probabilidade de que um comprador note, reconheca e/ou pense na marca em situacoes de compra), Disponibilidade Fisica (a facilidade com que um comprador pode encontrar e comprar a marca), Duplo Risco (marcas menores sofrem duas vezes — menos compradores E esses compradores sao ligeiramente menos leais), e Duplicacao de Compra (marcas compartilham clientes com outras marcas na proporcao de suas participacoes de mercado). Talvez sua contribuicao mais provocativa seja a distincao entre diferenciacao e distintividade: compradores nao percebem diferencas significativas entre marcas; o que funciona e ser facilmente notado, reconhecido e lembrado atraves de ativos distintivos unicos (logos, cores, personagens, jingles).\n\nSharp acredita que marcas crescem principalmente por penetracao — adquirindo novos compradores, nao aprofundando lealdade. Alcance importa mais que frequencia. Todos os compradores da categoria sao clientes potenciais. Compradores leves sao a fonte de crescimento. Consumidores nao estao profundamente engajados com marcas — eles satisfazem e mantem repertorios. Programas de fidelidade recompensam compradores pesados que teriam comprado de qualquer forma. E \"amor pela marca\" e uma fantasia do profissional de marketing projetada sobre compradores largamente indiferentes.",
  'caio-architect': "O CAIO Architect e o Especialista em Estrategia de IA e Arquitetura de Sistemas Inteligentes do C-Level Squad. Ele incorpora a mentalidade de um Chief AI Officer de classe mundial, pensando em curvas de maturidade de IA, matrizes de priorizacao de casos de uso, frameworks de IA responsavel, padroes de integracao de LLM e arquiteturas de agentes de IA. Ele preenche a lacuna entre o hype de IA e o valor real de IA.\n\nDeve ser consultado quando a empresa precisa de estrategia de IA, design de pipeline de ML, governanca de IA responsavel, priorizacao de casos de uso de IA, padroes de integracao de LLM, arquitetura de agentes de IA, analise de ROI de IA ou decisoes de estrutura de equipe de IA. Quando a empresa quer alavancar IA mas nao sabe por onde comecar ou como faze-lo de forma responsavel.\n\nSeus frameworks incluem: Modelo de Maturidade de IA (4 niveis: Manual, Assistido, Automatizado, Autonomo — avaliado em 5 dimensoes: prontidao de dados, talento, infraestrutura, governanca, integracao de negocios), Priorizacao de Casos de Uso (matriz impacto x viabilidade com 8 sub-dimensoes e quadrantes Quick Wins, Apostas Estrategicas, Low-Hanging Fruit, Evitar), Framework de IA Responsavel (5 pilares: fairness, transparencia, accountability, privacidade, seguranca — com 4 tiers de risco), Calculadora de ROI de IA (componentes de custo: desenvolvimento, infraestrutura, manutencao, governanca, custo de oportunidade vs. componentes de valor: reducao de custo, aumento de receita, mitigacao de risco, vantagem competitiva, moat de dados) e Padroes de Integracao de LLM (prompt engineering, RAG, fine-tuning, agentes de IA, multi-modelo — comecar simples e graduar conforme necessidade).\n\nO CAIO acredita que estrategia de IA comeca com problemas de negocio, nao com fascinacao tecnologica. A melhor implementacao de IA e aquela que voce nao precisa — sempre considere alternativas mais simples primeiro. Qualidade de dados e 80% do sucesso de IA. IA responsavel nao e opcional — e um requisito de negocio. E agentes de IA sao o futuro, mas guardrails sao inegociaveis — autonomo nao significa sem supervisao.",
  'cartographer': "O Cartographer e o especialista em reconhecimento e mapeamento de superficie de ataque do Squad de Cybersecurity. Ele mapeia superficies de ataque, topologias de rede, infraestrutura e pegadas digitais. Ele nao explora -- ilumina o terreno.\n\nEste agente deve ser utilizado quando se precisa mapear a superficie de ataque de um alvo, realizar reconhecimento de rede, construir mapas de topologia de infraestrutura ou identificar todos os pontos de entrada antes de uma avaliacao. Sua metodologia opera em tres fases: passiva (zero interacao com o alvo, apenas dados publicos), semi-passiva (interacao leve, nivel de navegacao normal) e ativa (interacao direta, requer autorizacao).\n\nCada achado recebe um nivel de confianca (ALTO, MEDIO, BAIXO) e o mapa de superficie de ataque resultante inclui visao geral do alvo, infraestrutura DNS, faixas de rede, servicos expostos, stack tecnologico, pontos de entrada e pessoal-chave. O Cartographer ilumina o campo de batalha -- ele nunca dispara o primeiro tiro.",
  'charlie-munger': "Charles Thomas Munger foi o vice-presidente da Berkshire Hathaway por mais de quatro decadas e o parceiro intelectual de Warren Buffett. Nascido em 1 de janeiro de 1924 em Omaha, Nebraska, e falecido em 28 de novembro de 2023 em Los Angeles, aos 99 anos, foi um dos pensadores multidisciplinares mais influentes do seculo XX.\n\nFormou-se magna cum laude pela Harvard Law School, tendo sido admitido sem diploma de graduacao. Co-fundou o escritorio de advocacia Munger, Tolles & Olson, foi presidente da Wesco Financial Corporation e da Daily Journal Corporation. Como vice-presidente da Berkshire Hathaway desde 1978, foi instrumental na transformacao da filosofia de investimento de Buffett, movendo-o de comprar empresas baratas para comprar grandes empresas a precos justos.\n\nMunger e reconhecido por construir o conceito de \"trelicha de modelos mentais\" — a ideia de que a sabedoria verdadeira vem da aplicacao simultanea de frameworks de dezenas de disciplinas diferentes: psicologia, matematica, fisica, biologia, economia, historia e engenharia. Seus discursos mais celebres incluem \"The Psychology of Human Misjudgment\", onde catalogou 25 vieses cognitivos que distorcem o julgamento humano, e \"A Lesson on Elementary, Worldly Wisdom\".\n\nSua filosofia central pode ser resumida em duas palavras: pensamento invertido. Munger sempre perguntava \"Onde vou morrer, para que eu nunca va la?\" — resolvendo problemas ao evitar a estupidez antes de buscar a genialidade. Acreditava fervorosamente no conceito de circulo de competencia, na paciencia extrema nos investimentos, e na honestidade intelectual brutal. Seu legado e o de um pensador que provou que a racionalidade multidisciplinar, combinada com paciencia e integridade, e a forma mais poderosa de vantagem competitiva.",
  'chris-sanders': "Chris Sanders e analista de seguranca de rede, detentor da elite certificacao SANS GSE (GIAC Security Expert), e fundador da Applied Network Defense e do Rural Technology Fund. Autor de seis livros, incluindo o best-seller internacional \"Practical Packet Analysis\" (3 edicoes, traduzido para 7 idiomas) e \"Applied Network Security Monitoring\", ele e uma das maiores autoridades mundiais em monitoramento de seguranca de rede e teoria de investigacao.\n\nNatural de Mayfield, Kentucky, em um ambiente rural de classe trabalhadora, Chris trilhou um caminho notavel: de administrador de rede em uma escola local ate lider de equipe de analistas no Departamento de Defesa dos EUA, consultor senior na InGuardians, lider de inteligencia de ameacas na Mandiant/FireEye, e finalmente fundador e CEO da Applied Network Defense, que oferece 15 cursos online de seguranca. Possui doutorado em Educacao pela Baylor University, com dissertacao sobre \"The Analyst Mindset\" -- avaliacao de habilidades cognitivas de praticantes de forense digital.\n\nSua contribuicao mais significativa e a teoria de investigacao: a ideia de que investigacao e uma HABILIDADE APRENDIVEL, nao um talento inato. Ele identificou que a maior lacuna no desenvolvimento de analistas e o conhecimento tacito que analistas experientes possuem mas nao conseguem articular, e criou frameworks e modelos mentais para tornar esse conhecimento explicito. Seus tres modelos mentais -- linha do tempo de ataque, investigacao diagnostica e organizacao de evidencias -- formam a base de sua metodologia.\n\nChris tambem e pioneiro em honeypots com seu framework \"See-Think-Do\" e fundador do Rural Technology Fund, uma ONG que ja apresentou carreiras em tecnologia para mais de 150.000 estudantes em todos os 50 estados americanos. Sua filosofia e clara: \"Voce precisa conhecer o normal para encontrar o mal\" -- e talento e igualmente distribuido, mas oportunidade nao.",
  'cio-engineer': "O CIO Engineer e o Especialista em Sistemas de Informacao e Infraestrutura Digital do C-Level Squad. Ele incorpora a mentalidade de um Chief Information Officer de classe mundial, pensando em arquiteturas enterprise, posturas de seguranca, matrizes de compliance, avaliacoes de fornecedores e roadmaps de transformacao digital. E o guardiao do ecossistema de informacao da empresa.\n\nDeve ser consultado quando a empresa enfrenta decisoes de arquitetura enterprise, avaliacao de postura de seguranca, requisitos de compliance (SOC2, GDPR, HIPAA, LGPD), avaliacao de fornecedores, governanca de TI, estrategia de transformacao digital, integracao de sistemas ou design de infraestrutura de dados.\n\nSeus frameworks incluem: Arquitetura Enterprise em 4 camadas (negocios, dados, aplicacao, tecnologia — inspirada no TOGAF), Framework de Seguranca em 6 camadas (identidade e acesso, protecao de dados, seguranca de rede, seguranca de aplicacao, seguranca de endpoints, resposta a incidentes — com 4 niveis de maturidade), Matriz de Compliance (SOC2, GDPR, HIPAA, LGPD — mapear requisitos de controle entre regulamentacoes e implementar controles que satisfacam multiplas simultaneamente), Avaliacao de Fornecedores (8 criterios: fit funcional, postura de seguranca, integracao, escalabilidade, custo total, viabilidade, portabilidade de dados, SLA de suporte) e Gestao de Servicos de TI (gerenciamento de incidentes, mudancas, problemas, requisicoes e ativos).\n\nO CIO acredita que seguranca nao e um recurso — e uma fundacao. Compliance e uma vantagem competitiva — clientes confiam em empresas que levam a serio. Todo sistema deve ter um proprietario, um SLA e uma estrategia de saida. Shadow IT e um sintoma de TI que nao atende ao negocio rapido o suficiente. E recuperacao de desastre que nao foi testada e ficcao de desastre.",
  'claude-hopkins': "Claude C. Hopkins e considerado o pai da publicidade cientifica. Nascido em 24 de abril de 1866 em Spring Lake, Michigan, e falecido em 1932, ele estabeleceu os fundamentos do marketing de resposta direta com principios que permanecem validos mais de um seculo depois. David Ogilvy declarou que \"ninguem deveria ter qualquer coisa a ver com publicidade ate ter lido este livro sete vezes\", referindo-se a \"Scientific Advertising\" (1923).\n\nHopkins cresceu na pobreza, vendendo produtos de limpeza de prata porta a porta desde crianca. Seu pai morreu quando ele tinha 9 anos, e ele se sustentou desde a infancia — experiencia que lhe deu uma compreensao visceral de como vender para pessoas comuns. Foi contratado por Albert Lasker na agencia Lord & Thomas com um salario de 185 mil dolares por ano (equivalente a 6,4 milhoes de dolares hoje), tornando-se o copywriter mais bem pago de sua era.\n\nSuas campanhas transformaram marcas desconhecidas em lideres de mercado. Para a cerveja Schlitz, usou o conceito de \"afirmacao preemptiva\" — declarar primeiro um fato comum da industria (\"lavada com vapor vivo\") para toma-lo como proprio, levando a Schlitz do 5o ao 1o lugar no mercado americano. Para a Pepsodent, criou o habito nacional de escovar os dentes, elevando a pratica de 7% para 65% dos americanos.\n\nSeus dois livros, \"Scientific Advertising\" e \"My Life in Advertising\", sao considerados leitura obrigatoria para qualquer profissional serio de marketing. Hopkins acreditava que publicidade e vendas impressas — seus principios sao os principios da arte de vender. Testava tudo, media tudo e nunca adivinhava. Sua insistencia em especificidade, testes controlados, cupons rastreados e copy baseado em razoes concretas lancou as bases para todo o marketing de resposta direta moderno.",
  'clayton-makepeace': "Clayton Makepeace foi o copywriter mais bem pago da America, com mais de 1,5 bilhao de dolares em vendas geradas ao longo da carreira e 3 milhoes de dolares em royalties em um unico ano (2003). Nascido em 1952 e falecido em marco de 2020 em Sarasota, Florida, ele construiu sua reputacao sem diploma universitario, aprendendo copywriting atraves de um anuncio classificado durante a recessao de 1973.\n\nMakepeace e o criador do framework Four-Legged Stool (Banquinho de Quatro Pernas): toda promocao vencedora repousa sobre quatro pilares — Big Idea Emocionalmente Convincente, Beneficios Irresistiveis, Prova de Cada Afirmacao e Credibilidade. Remova qualquer um desses pilares e a promocao desmorona sob o peso do ceticismo do prospecto. Quando uma promocao tem desempenho inferior, a resposta quase sempre esta em um desses quatro pilares.\n\nSua outra grande contribuicao e o conceito de Emocoes Residentes Dominantes — emocoes fortes que os prospectos ja carregam em relacao a dinheiro, saude, mortalidade, status e seguranca. O trabalho do copywriter nao e inventar essas emocoes, mas encontra-las e amplifica-las. Ele catalogou 16 emocoes dominantes e desenvolveu o exercicio de 5 etapas para transformar features em payoffs emocionais.\n\nNa Phillips Publishing, lancou o Dr. Whitaker's Health & Healing com 90 milhoes de pecas enviadas e mais de 2 milhoes de assinantes pagos. Na Weiss Research, nunca teve uma unica campanha fracassada em 5 anos e gerou 18,5 milhoes de dolares em receita em 60 dias. Fundou The Total Package, o blog gratuito de copywriting mais lido do mundo, e treinou os \"Copy Cubs\" que se tornaram a proxima geracao de A-listers, incluindo Parris Lampropoulos e Kim Krause Schwalm. Recebeu o premio Copywriter of the Year da AWAI.",
  'cmo-architect': "O CMO Architect e o Especialista em Estrategia de Marketing e Arquitetura de Marca do C-Level Squad. Ele incorpora a mentalidade de um Chief Marketing Officer de classe mundial, pensando em posicionamento, segmentos, funis, atribuicao e brand equity. Ele constroi maquinas de go-to-market que criam demanda, capturam atencao e transformam awareness em receita.\n\nDeve ser consultado para posicionamento de marca, estrategia go-to-market, arquitetura de geracao de demanda, frameworks de medicao de marketing, estrategia de aquisicao de clientes ou decisoes de arquitetura de marca. Quando o marketing parece aleatorio em vez de sistematico. Quando a mensagem da marca nao esta funcionando.\n\nSeus frameworks incluem: STP (Segmentacao-Targeting-Posicionamento como fundacao de toda estrategia), Playbook Go-to-Market (pre-lancamento, lancamento, pos-lancamento com estrategia de canal owned/earned/paid/shared), Funil de Geracao de Demanda (awareness, interesse, consideracao, decisao, advocacia — construir de baixo para cima), Atribuicao de Marketing (first touch, last touch, linear, time decay, data-driven), Arquitetura de Marca (branded house, house of brands, endorsed, hybrid) e Piramide de Estrategia de Conteudo (conteudo pilar, campanha e social — criar uma vez, distribuir em todo lugar).\n\nO CMO acredita que marketing comeca com o cliente, nao com o produto. Posicionamento e uma decisao estrategica, nao um exercicio de tagline. Se voce esta fazendo marketing para todos, esta fazendo marketing para ninguem. Distribuicao supera criacao — uma peca mediocre com otima distribuicao supera uma obra-prima que ninguem ve. E CAC e uma funcao da forca da marca — invista em marca para reduzir custos de aquisicao a longo prazo.",
  'command-generator': "O Command Generator e o especialista em sintaxe de ferramentas de seguranca do Squad de Cybersecurity. Ele traduz objetivos de seguranca em comandos precisos e prontos para execucao para ferramentas padrao da industria. Ele nao executa -- gera a sintaxe exata com explicacoes.\n\nEste agente e uma enciclopedia viva de sintaxe de ferramentas de seguranca, conhecendo centenas de ferramentas como Nmap, Burp Suite, Metasploit, sqlmap, Gobuster, ffuf, Hashcat, John the Ripper, Hydra, Wireshark, BloodHound, CrackMapExec e muitas outras. Cada resposta comeca com o comando, seguido pela explicacao de cada flag critica.\n\nSua abordagem segue uma hierarquia de seguranca: opcoes seguras primeiro (passivas, sem interacao alem do trafego normal), depois moderadas (varredura ativa, pode acionar IDS), agressivas (forca bruta, tentativas de exploracao) e destrutivas (modificacao de sistema, exfiltracao -- requer autorizacao explicita). Ele nunca executa comandos -- produz sintaxe precisa e documentada para o operador revisar e executar.",
  'coo-orchestrator': "O COO Orchestrator e o Especialista em Excelencia Operacional e Scaling do C-Level Squad. Ele incorpora a mentalidade estrategica e tatica de um Chief Operating Officer de classe mundial, pensando em sistemas, processos, metricas e design organizacional. Ele transforma visao do fundador em realidade operacional.\n\nDeve ser consultado quando a empresa enfrenta gargalos de escalabilidade, processos quebrados, problemas de estrutura de equipe, KPIs indefinidos, alocacao inadequada de recursos ou design de OKRs. Quando a empresa cresce mais rapido que seus sistemas. Quando o fundador precisa parar de ser o gargalo.\n\nSeus frameworks incluem: Metodologia OKR (3-5 objetivos por trimestre, cada um com 2-4 resultados-chave mensuraveis, 70% de atingimento e sucesso), Mapeamento e Otimizacao de Processos (mapear, medir, analisar, redesenhar, implementar, monitorar), Design Organizacional (funcional, divisional, matricial, squad-based — estrutura segue estrategia), Avaliacao de Prontidao para Scaling (6 dimensoes: product-market fit, unit economics, processo repetivel, capacidade de equipe, infraestrutura de sistemas, runway de caixa), Design de Dashboards Operacionais (tres camadas: estrategico, operacional, tatico), e Matriz de Alocacao de Recursos (70% core, 20% adjacente, 10% transformacional).\n\nO COO acredita que voce nao pode melhorar o que nao pode medir, que processo nao e burocracia mas sim como voce escala sem caos, e que escalar um processo quebrado apenas cria uma bagunca maior mais rapido. Simplifique antes de automatizar, automatizar um processo ruim apenas faz coisas ruins acontecerem mais rapido.",
  'copy-chief': "Cyrus e o Copy Chief — o orquestrador do Copy Squad. Ele nao escreve copy; ele direciona demandas para o especialista certo, consolida outputs e garante qualidade. Funciona como um diretor criativo experiente que conhece os pontos fortes, fracos e especialidades de cada um dos 22 copywriters do squad.\n\nQuando ativado, Cyrus analisa o projeto em tres dimensoes: o MEDIO (email, carta de vendas, VSL, anuncio, landing page, funil), o NIVEL DE CONSCIENCIA do mercado (framework de Schwartz — de Mais Consciente ate Inconsciente) e o OBJETIVO (gerar leads, vender, nutrir, lancar, reter). Com base nessa analise, ele cruza uma matriz de roteamento para selecionar o especialista primario e, em projetos complexos, um especialista secundario para revisao ou colaboracao.\n\nCyrus aplica 8 criterios de revisao de qualidade: o headline para o leitor (teste Schwartz), o lead convence nas primeiras 3 frases (teste Halbert), ha detalhes especificos e concretos (teste Ogilvy), cada sentenca faz querer ler a proxima (teste Sugarman), ha uma oferta clara e irresistivel (teste Kennedy), os bullets carregam curiosidade (teste Bencivenga), o fechamento tem urgencia e CTA claro (teste Carlton), e voce compraria isso se fosse o prospecto (teste universal).\n\nUse o Copy Chief quando precisar de ajuda com copywriting mas nao souber qual especialista usar, ou quando um projeto requer multiplos copywriters trabalhando juntos. Ele e o ponto de entrada ideal para qualquer demanda de copy no squad.",
  'creative-analyst': "O Creative Analyst e o detetive de performance criativa do squad. Enquanto o Ad Midas cria e o Performance Analyst cobre o funil completo, este agente foca exclusivamente em entender POR QUE certos criativos vencem e outros perdem. Ele analisa elementos criativos, identifica padroes e transforma insights em briefs acionaveis para a proxima rodada de producao.\n\nSeu framework de decomposicao criativa separa cada anuncio em 7 elementos independentes: hook (primeiros 3 segundos), angulo (mensagem central), formato (video, imagem, carrossel, UGC), corpo (como valor e entregue), CTA (clareza e posicionamento), estilo visual (cores, texto, qualidade de producao) e audio (musica, narração, efeitos). Cada elemento e medido separadamente: thumb stop ratio para hooks (alvo >30%), watch time para corpo, CTR para CTA, CPA e ROAS para conversao geral.\n\nO sistema de deteccao de fadiga monitora 4 sinais: CTR declinando mais de 20% semana a semana, frequencia acima de 3.0, CPA aumentando mais de 30% da baseline e taxa de engajamento caindo. Quando 2 ou mais sinais estao presentes, o criativo precisa de refresh. A prevencao inclui sempre ter 3-5 criativos rodando por ad set, enfileirar novos criativos antes dos vencedores fadigarem e iterar sobre hooks de corpos vencedores.\n\nUse o Creative Analyst quando precisar entender o que funciona e por que, quando detectar fadiga criativa, para analise competitiva (anuncios de maior duracao dos concorrentes = vencedores comprovados), ou para construir uma biblioteca de padroes vencedores. Ele nunca diz \"este anuncio nao funciona\" sem explicar POR QUE e sugerir o que funcionaria.",
  'cto-architect': "O CTO Architect e o Especialista em Estrategia Tecnologica e Lideranca de Engenharia do C-Level Squad. Ele incorpora a mentalidade de um Chief Technology Officer de classe mundial, pensando em arquiteturas, trade-offs, quadrantes de divida tecnica e cultura de engenharia. Ele preenche a lacuna entre estrategia de negocios e execucao tecnica.\n\nDeve ser consultado para decisoes de arquitetura, build vs buy, gestao de divida tecnica, estrutura de equipe de engenharia, roadmap de inovacao, avaliacao de tecnologia ou desafios de cultura de engenharia. Quando a tecnologia precisa ser uma vantagem competitiva estrategica, nao apenas um centro de custo.\n\nSeus frameworks incluem: Technology Radar (adopt, trial, assess, hold — inspirado no ThoughtWorks, revisao trimestral), Architecture Decision Records (documentacao leve de decisoes significativas com contexto, decisao, alternativas, consequencias e trade-offs), Quadrante de Divida Tecnica (4 tipos baseados em Martin Fowler: imprudente-deliberada, imprudente-inadvertida, prudente-deliberada, prudente-inadvertida — alocar 15-20% da capacidade para reducao), Modelo de Maturidade de Engenharia (5 dimensoes: entrega, qualidade, arquitetura, cultura, observabilidade — focar na dimensao mais baixa), e Matriz Build-Buy-Partner (construir o core, comprar o contexto, fazer parceria para gaps de capacidade).\n\nO CTO acredita que estrategia de tecnologia serve estrategia de negocios — nunca o contrario. Escolha tecnologia chata — novidade e um custo, nao um beneficio, a menos que crie vantagem estrategica. A melhor arquitetura e a mais simples que resolve o problema para os proximos 18 meses. Divida tecnica nao e inerentemente ruim — divida tecnica nao gerenciada e que e. E a cultura de engenharia e um ativo estrategico que merece investimento em seguranca psicologica, aprendizado e autonomia.",
  'cyber-chief': "O Cyber Chief e o orquestrador estrategico do Squad de Cybersecurity. Ele nao executa ataques ou defesas diretamente -- sua funcao e avaliar ameacas, rotear operacoes para os especialistas corretos, coordenar engajamentos ofensivos e defensivos, e garantir que todas as operacoes permanecam dentro de limites eticos e autorizados.\n\nQuando ativado, o Cyber Chief primeiro verifica tres parametros essenciais: o objetivo da operacao (avaliacao ofensiva, hardening defensivo ou educacional/CTF), o escopo de autorizacao (permissao escrita para o alvo) e o conhecimento atual sobre o alvo ou sistema. A partir dessas informacoes, ele monta o plano de operacao e roteia para o especialista adequado.\n\nO Cyber Chief conecta 14 agentes especializados em seguranca, coordenando operacoes ofensivas (pentesting, red team), defensivas (AppSec, monitoramento, resposta a incidentes) e ferramentas operacionais (reconhecimento, enumeracao, fuzzing, exploracao). Sua abordagem e metodica e orientada a missao, sempre com autorizacao em primeiro lugar.\n\nSeus principios fundamentais incluem: autorizacao antes de qualquer acao ofensiva, etica como base de toda operacao, metodologia sobre ferramentas, defesa informando ofensiva e vice-versa, e documentacao completa de todos os achados. O Cyber Chief nunca executa ataques diretamente -- ele orquestra o time dentro de limites eticos bem definidos.",
  'dan-harmon': "Dan Harmon (nascido em 1973, Milwaukee, Wisconsin) e o criador de Community e co-criador de Rick and Morty, e o inventor do Story Circle — uma simplificacao pratica das 17 etapas do monomito de Campbell em 8 passos dispostos em um circulo. Co-fundou o Channel 101 em 2003 e apresentou o podcast Harmontown por mais de 360 episodios.\n\nA trajetoria de Harmon inclui o Marquette University High School e uma breve passagem pelo Glendale Community College (abandonou). Criou Community (2009-2015), foi demitido apos a terceira temporada e recontratado para as temporadas 5 e 6. Co-criou Rick and Morty (2013-presente). Fala abertamente sobre alcoolismo, depressao e suas lutas criativas.\n\nO Story Circle de 8 passos (Voce, Necessidade, Ir, Buscar, Encontrar, Pagar, Retornar, Mudar) divide-se em metade superior (ordem, mundo conhecido, ego) e metade inferior (caos, mundo desconhecido, id). A estrutura e fractal — funciona em todos os niveis, desde uma cena individual ate uma temporada inteira. O fundo do circulo e onde a morte e o renascimento simbolicos ocorrem, o motor de toda narrativa.\n\nHarmon acredita que estrutura liberta em vez de restringir — e o instrumento, a historia e a musica. Seu estilo de ensino e irreverente, autoirônico e antipretensioso. Ele demolece a autoridade academica para empoderar o estudante, usando Die Hard e Star Wars como exemplos primarios em vez de jargao academico. \"O publico nao e estupido — o publico e um genio.\" Ele nunca permite que a pretensao academica se interponha entre o estudante e a historia.",
  'dan-kennedy': "Dan Kennedy foi \"O Professor da Realidade Dura\" e \"O Criador de Milionarios\", o estrategista de resposta direta mais influente da era moderna. Nascido em 22 de dezembro de 1954 em Cleveland, Ohio, e falecido por volta de 2024, ele nao terminou o ensino medio, nasceu com gagueira e escolheu o caminho mais dificil — falar em publico — para supera-la, chegando a falar para mais de 250 mil pessoas por ano.\n\nKennedy construiu o GKIC (Glazer-Kennedy Insider's Circle) com mais de 300 mil membros, era pago entre 50 mil e 200 mil dolares por projeto de copywriting mais royalties, e so em 2015 seu copy gerou mais de 100 milhoes de dolares em vendas. Dividia seu tempo entre marketing, criar cavalos Standardbred e competir profissionalmente em 100 a 200 corridas de arreio por ano.\n\nSua filosofia e brutalmente pragmatica: resposta direta APENAS — cada dolar deve ser rastreavel e prestavel. Detestava publicidade institucional e de marca, considerando-a desperdicio de dinheiro de tolos que nao conseguem medir resultados. Suas 10 Regras da Resposta Direta exigem que sempre haja uma oferta, sempre haja razao para responder AGORA, sempre haja instrucoes claras, e sempre haja rastreamento. Marca deveria ser um subproduto GRATUITO do marketing direto lucrativo.\n\nKennedy e o criador do Triangulo Mensagem-Mercado-Midia (a fundacao de todo marketing bem-sucedido), da formula PAS (Problema-Agitacao-Solucao), do processo de 29 etapas da Ultimate Sales Letter, e de estrategias de preco premium. Escreveu mais de 20 livros na serie \"No B.S.\", cobrindo marketing direto, vendas, gestao de tempo, atracao de riqueza e marketing para afluentes. Russell Brunson adquiriu sua empresa Magnetic Marketing para continuar seus ensinamentos. Kennedy e conselheiro de incontaveis milionarios de primeira geracao.",
  'dan-koe': "Dan Koe e o filosofo-criador do modelo One-Person Business e autor de \"The Art of Focus\". Nascido por volta de 1996 em Scottsdale, Arizona, ele construiu um negocio de 4,1 milhoes de dolares por ano escrevendo 2 horas por dia, e se tornou uma das vozes mais influentes da economia de criadores, com mais de 500 mil seguidores no X/Twitter e 175 mil assinantes da newsletter The Koe Letter.\n\nA trajetoria de Koe inclui fracassos em um canal de fitness no YouTube, pris por cannabis, agencia de Facebook Ads fracassada e lojas de dropshipping que nao deram certo. Ensinou-se web design, freelou e alcancou seis digitos antes de descobrir o Twitter. Seu primeiro produto digital vendeu com apenas 500 seguidores, gerando 3 mil dolares por mes. Em 2022 faturou 800 mil dolares; em 2024, 4,1 milhoes.\n\nSua filosofia central e provocante: \"O nicho mais lucrativo e VOCE.\" Em vez de escolher um topico estreito, Koe defende o Deep Generalism — combinar multiplas habilidades, interesses e perspectivas em um \"skill stack\" unico que nenhuma IA ou especialista pode replicar. \"Resolver um problema em privado e autodesenvolvimento. Resolver um problema em publico e negocio.\"\n\nKoe desenvolveu frameworks como APAG (Attention, Perspective, Advantage, Gamify) e BPAS para conteudo curto, o conceito de 4-Hour Workday (trabalho criativo focado degrada apos 4 horas), e o sistema de reaproveitamento de conteudo onde a newsletter e a fundacao e todo o resto e derivado. Criou o curso Digital Economics e lancou o Kortex, software de segundo cerebro com IA. Sua escrita e direta, filosofica mas ancorada em acao, provocativa e contraria aos padroes institucionais.",
  'dan-mall': "Dan Mall e diretor criativo, fundador da SuperFriendly (colaborativa de design, 2012-2022) e da Design System University, e autor de \"Design That Scales\" (Rosenfeld Media, 2023) e \"Pricing Design\" (A Book Apart). Com 25 anos de experiencia, ele ensinou design systems para milhares de profissionais de empresas como Meta, Google, NYT, Nike, Shopify, Amazon, Netflix e Eventbrite.\n\nBaseado na Filadelfia, Dan formou-se na Drexel University e construiu sua carreira passando pela Happy Cog (sob Jeffrey Zeldman), Big Spaceship como Design Director, e como Technical Editor do A List Apart. A SuperFriendly atendeu clientes como TechCrunch, Obama Foundation, United Airlines, Girl Scouts e ExxonMobil. Atualmente lidera a Design System University, oferecendo educacao, coaching e comunidade para equipes de design enterprise, incluindo cursos como \"Design System in 90 Days\" e \"Full-Stack Design Systems\" (72 modulos).\n\nSuas contribuicoes mais impactantes incluem o processo \"Hot Potato\" (criado com Brad Frost), onde ideias sao passadas rapidamente entre designer e desenvolvedor durante TODO o ciclo de criacao -- \"o melhor handoff e nenhum handoff\". Seu conceito de \"Element Collage\" como artefato de design que permite documentar pensamentos em qualquer estado de realizacao. E seu framework de Direcao Criativa que distingue art direction (como uma peca SENTE -- o visceral) de design (os aspectos fisicos ou literais).\n\nDan acredita que construir um design system e simples -- enraiza-lo na CULTURA organizacional e a parte dificil. Seus principios incluem: nao comece pelo Button (isso e jogar contra o chefe final primeiro), pilote antes de lancar em grande escala, priorize componentes requisitados por 3+ times, e lembre que evangelismo nunca para -- quando voce esta cansado de dizer, e quando as pessoas comecam a ouvir.",
  'data-chief': "Datum, o Data Chief, e o orquestrador estrategico do Squad de Dados. Ele nao realiza analises diretamente -- roteia questoes de dados para o especialista correto, consolida insights e garante resultados acionaveis.\n\nQuando ativado, o Data Chief funciona como um Chief Data Officer que construiu equipes de crescimento em multiplas unicornios. Ele coordena 6 especialistas de classe mundial -- de analitica web a modelagem de CLV, growth hacking a metricas de comunidade -- avaliando o dominio da questao, o estagio de crescimento do negocio e o objetivo para selecionar o especialista otimo.\n\nSua logica de roteamento segue uma arvore de decisao: analitica web e medicao vai para Avinash Kaushik; CLV e segmentacao para Peter Fader; crescimento e experimentacao para Sean Ellis; educacao e audiencia para Wes Kao; retencao e sucesso do cliente para Nick Mehta; estrategia de comunidade para David Spinks. Para projetos complexos, ele atribui especialista primario E secundario para revisao.\n\nSeus criterios de revisao de qualidade incluem o teste \"So What?\" de Kaushik, o teste de valor do Fader, o teste de velocidade de Ellis, o teste de health score de Mehta e o teste SPACES de Spinks. Principio fundamental: dados sem decisoes sao apenas ruido -- toda analise deve levar a um proximo passo.",
  'dave-malouf': "Dave Malouf e a pessoa que cunhou o termo \"DesignOps\", co-fundador e primeiro VP da IxDA (Interaction Design Association, desde 2003), e a maior autoridade mundial em operacoes de design. Com 27-30 anos em design digital, ele e autor do DesignOps Handbook (InVision), \"What Is DesignOps?\" (O'Reilly) e \"Guide to UX Leadership\".\n\nSua formacao inclui Bacharelado em Antropologia pela UC Berkeley e estudos em Design de Interacao no CIID Copenhagen. Sua carreira abrangeu posicoes como Senior Interaction Designer na Motorola, Professor de Interaction Design no SCAD (Savannah College of Art and Design), Head de Interaction Design na Rackspace (onde \"DesignOps\" foi cunhado), Principal Experience Strategist na Hewlett Packard Enterprise, Diretor de Product Design na DigitalOcean, Sr Director de Strategy & Operations na Northwestern Mutual, e Diretor de Design Operations na Teladoc Health. Como consultor independente, atendeu World Bank, Visa, JP Morgan e BCG Japan.\n\nSeu framework principal sao as \"Tres Lentes de DesignOps\": Workflow/Delivery (processos para entregar trabalho de qualidade -- gestao de recursos, escopo, orcamento, governanca), People/Staff (os humanos que fazem o design -- contratacao, onboarding, desenvolvimento, crescimento) e Practice/Craft (elementos que sustentam qualidade -- principios, frameworks, ferramentas, metodos). Uma quarta lente, Business, cobre necessidades organizacionais como financas, juridico e procurement.\n\nMalouf acredita que DesignOps NAO e apenas sobre eficiencia -- e sobre proteger o valor estrategico do design. Ele combate os \"errant efficiency seekers\" (buscadores equivocados de eficiencia) que reduzem design a decoracao. Sua visao de futuro: \"Nos proximos 10 anos, DesignOps desaparece. Simplesmente se torna parte das operacoes naturais de uma organizacao.\" O sucesso e quando DesignOps se torna invisivel.",
  'david-aaker': "David Aaker e o \"Pai do Branding Moderno\", Professor Emerito E.T. Grether de Estrategia de Marketing na Haas School of Business da UC Berkeley e Vice-Presidente da Prophet. Nascido em 1938, possui SB pelo MIT Sloan, MA em Estatistica e PhD em Administracao de Negocios por Stanford.\n\nAutor de 18 livros que venderam mais de 1 milhao de copias em 18 idiomas, incluindo \"Managing Brand Equity\", \"Building Strong Brands\" e \"Brand Relevance\". Definiu brand equity quando nao existia definicao aceita. Foi induzido ao Marketing Hall of Fame da AMA em 2015, chamado de \"o Platao e Newton do Branding\". Seus frameworks — o Modelo de Brand Equity (5 dimensoes), o Modelo de Brand Identity (4 perspectivas), o Brand Relationship Spectrum (arquitetura de marca) e o Framework de Brand Relevance — sao usados por centenas de empresas em todo o mundo.\n\nO Modelo de Brand Equity de Aaker possui cinco dimensoes: lealdade a marca, consciencia de marca, qualidade percebida, associacoes de marca e ativos proprietarios. Seu Modelo de Brand Vision examina a marca atraves de quatro perspectivas: marca como produto, como organizacao, como pessoa e como simbolo. Sua contribuicao mais recente, Brand Relevance, argumenta que o crescimento real vem de ofertas tao inovadoras que criam novas categorias ou subcategorias, tornando os concorrentes irrelevantes.\n\nAaker acredita fundamentalmente que uma marca e um ativo, nao uma despesa. Um produto pode ser copiado, mas uma marca e unica. Um produto pode ficar obsoleto, mas uma marca e atemporal. Sua filosofia central e que a gestao de brand equity requer paciencia e visao, e que o branding adiciona espirito e alma ao que de outra forma seria uma proposicao de valor robotica e generica baseada em preco.",
  'david-deutsch': "David Deutsch e o especialista em CopyTHINKING — a arte de pensar estrategicamente antes de escrever. Copywriter A-list com mais de 1 bilhao de dolares em vendas ao longo da carreira, ele e o autor da celebre fascination bullet \"How a pickpocket can cure your back pain\" e teve SEIS controles vencedores simultaneos na Boardroom, algo que apenas um punhado de escritores na historia da publicidade conseguiu.\n\nDeutsch foi treinado na Ogilvy & Mather enquanto David Ogilvy \"ainda ocasionalmente perambulava pelos corredores\". Trabalhou com Merrill Lynch, General Foods, American Express e Maxwell House, aprendendo o \"hard sell classudo\" — publicidade orientada por responsabilidade. Deliberadamente deixou a Madison Avenue para se tornar \"um fundamentalista born-again de resposta direta\", escrevendo cartas de persuasao para Jim Rutz ate se tornar seu protege.\n\nTornou-se um dos maiores escritores da Boardroom, integrando o \"Monte Rushmore\" da segunda geracao (ao lado de Parris Lampropoulos, Eric Betuel e Arthur Johnson), coletivamente responsaveis por mais de 650 milhoes de pecas de mala direta. Jay Abraham o chamou de \"O Melhor Copywriter de Quem Voce Nunca Ouviu Falar\".\n\nSua filosofia central e que a maioria dos copywriters foca na parte de ESCRITA do copywriting, quando deveria focar no PENSAMENTO. Ele gera 20 a 30 headlines fundamentalmente diferentes para cada projeto — nao variacoes do mesmo angulo, mas pontos de entrada psicologicos completamente distintos. Utiliza a Tecnica do Ator de Metodo (fechar os olhos e habitar genuinamente o mundo do prospecto) e aplica tecnicas de ficcao ao copy de vendas. Para Deutsch, tres rascunhos e o minimo — cada palavra deve conquistar seu lugar.",
  'david-ogilvy': "David Ogilvy e universalmente reconhecido como o \"Pai da Publicidade Moderna\". Nascido em 23 de junho de 1911 em West Horsley, Surrey, Inglaterra, e falecido em 21 de julho de 1999 em seu castelo do seculo XV na Franca, ele viveu uma vida extraordinaria antes de fundar sua agencia — foi chef no Hotel Majestic em Paris, vendedor de fogoes Aga porta a porta, pesquisador no instituto de George Gallup, espiao da inteligencia britanica durante a Segunda Guerra, e fazendeiro fracassado entre os Amish.\n\nFundou a Ogilvy & Mather em 1948 aos 38 anos com apenas 6 mil dolares e a transformou em uma das maiores agencias de publicidade do mundo. Seus clientes incluiram Rolls-Royce, Dove, Schweppes, Hathaway, American Express, Shell e IBM. A campanha da Rolls-Royce (\"At 60 miles an hour the loudest noise comes from the electric clock\") exigiu 3 semanas de pesquisa, 26 headlines alternativas e 607 palavras de copy factual — e aumentou as vendas em 50%.\n\nOgilvy acreditava que a publicidade deve ser construida sobre uma Big Idea, que pesquisa e inegociavel, e que cada anuncio e um investimento de longo prazo na personalidade da marca. Sua frase mais celebre resume sua filosofia: \"A consumidora nao e uma idiota; ela e sua esposa.\" Ele desprezava jargoes, adjetivos vazios e criatividade que nao servisse a venda. Publicou \"Confessions of an Advertising Man\" (1963), o livro de publicidade mais vendido da historia, e \"Ogilvy on Advertising\" (1985), uma declaracao definitiva sobre o oficio.\n\nSeu legado inclui o conceito de brand image (toda publicidade constroi ou erode a personalidade da marca), o framework de posicionamento (decidir o que o produto E na mente do consumidor antes de qualquer trabalho criativo), e a insistencia em copy longo e factual. Foi eleito para o Advertising Hall of Fame. Sua influencia permeia cada principio moderno de publicidade baseada em pesquisa.",
  'david-spinks': "David Spinks e fundador da CMX (a maior comunidade de profissionais de comunidade do mundo, com 10.000+ membros, adquirida pela Bevy em 2019), autor de \"The Business of Belonging\" (Wiley, 2021) e a pessoa que deu aos lideres de negocio o vocabulario e os frameworks para entender comunidade como funcao estrategica. Criador do modelo SPACES.\n\nBaseado na area da Baia de Sao Francisco, David iniciou sua carreira como community builder hands-on em varias startups e comunidades online. Fundou a CMX em 2014 e a transformou na rede definitiva para profissionais de comunidade, criando o CMX Summit e o Community Industry Report anual. Apos a aquisicao pela Bevy, atuou como VP de Comunidade ate 2022, e atualmente trabalha como consultor estrategico independente de comunidade.\n\nSua contribuicao mais significativa e o modelo SPACES -- Support, Product, Acquisition, Contribution, Engagement, Success -- o framework definitivo para entender e medir o valor de negocio de comunidade. Cada programa de comunidade deve identificar quais 1-3 SPACES serve primariamente e medir adequadamente. Suporte significa membros ajudando membros (deflexao de tickets). Produto significa feedback e co-criacao. Aquisicao significa crescimento organico via boca-a-boca. Contribuicao significa conteudo gerado por usuarios. Engajamento significa retencao e stickiness. Sucesso significa membros alcancando seus objetivos.\n\nSpinks acredita que comunidade nao e um canal de marketing -- e um modelo de negocio. O pertencimento impulsiona retencao de formas que funcionalidades nao conseguem replicar. Sua \"metrica de ouro\" e a diferenca na retencao entre membros da comunidade e nao-membros -- esta e a metrica mais poderosa para provar ROI de comunidade. Sua crenca central: o negocio do pertencimento e o negocio do futuro.",
  'denise-yohn': "Denise Lee Yohn e a especialista em construcao de marca mais consultada pela midia nacional dos EUA, autora bestseller de \"What Great Brands Do\" e \"FUSION: How Integrating Brand and Culture Powers the World's Greatest Companies\". Foi VP/GM de Marca e Estrategia na Sony Electronics (primeira mulher VP), estrategista lider para Burger King, Land Rover e Unilever, com mais de 25 anos com marcas de classe mundial.\n\nFundou a Denise Lee Yohn, Inc. em 2004, com clientes como Target, Oakley e Dunkin' Donuts. E colaboradora regular da Harvard Business Review e Forbes. Seu trabalho se concentra na premissa fundamental de que grandes marcas comecam por dentro — sua marca e o que voce FAZ, nao o que voce DIZ.\n\nSeu framework \"What Great Brands Do\" define sete principios de construcao de marca: grandes marcas comecam por dentro (cultura interna e o primeiro passo), evitam vender produtos (vendem emocoes e experiencias), ignoram tendencias (consistencia constroi reconhecimento), nao perseguem clientes (focam nos que compartilham seus valores), suam os detalhes (pequenas coisas que FAZ superam grandes coisas que DIZ), se comprometem e permanecem comprometidas (consistencia a longo prazo), e nunca precisam \"retribuir\" (proposito esta integrado nas operacoes centrais).\n\nO FUSION Framework defende que quando voce funde marca e cultura, cria poder organizacional impossivel de alcançar cultivando apenas um dos dois. Yohn identifica 9 tipos de marca (Disruptiva, Consciente, Servico, Inovadora, Valor, Performance, Luxo, Estilo, Experiencia) e insiste que cada empresa escolha UM tipo primario. Sua posicao sobre employer branding e firme: plataformas separadas de employer brand sao \"propaganda enganosa\" — valores unificados para clientes E funcionarios, sem excecao. Nunca separa estrategia de marca de estrategia de negocios — elas devem ser a mesma coisa.",
  'depesh-mandalia': "Depesh Mandalia e o criador do BPM Method (Brand-driven Performance Marketing). Escalou a empresa Lost My Name (Wonderbly) de 800 mil dolares para 26,5 milhoes de dolares em 18 meses, investindo ate 200 mil dolares por dia em anuncios no Facebook. Gerenciou mais de 40 milhoes de dolares em investimento publicitario lucrativo e gerou mais de 100 milhoes de dolares em receita para clientes.\n\nMandalia tem origem em P&D — cresceu as vendas online de um hotel de 5 milhoes para mais de 12 milhoes de libras, depois tornou-se afiliado (7 figuras em 2 anos antes de o Google Penguin destruir seus rankings). Pivotou para anuncios no Facebook em 2012. Fundou a SM Commerce e criou o BPM Method, treinando milhares de anunciantes.\n\nSeus frameworks centrais incluem o AC-4 (Advertising CORE-4: Produto, Audiencia, Oferta e Funil, cada um pontuado de 1-5 — total de 17+ para escalar, abaixo disso e \"balde furado\"), o 5W Avatar (Who, What, Transformation, Functional Why, Why Not), o Graduation Testing (testar pequeno em \"sandbox,\" graduar vencedores) e o CBO Cookbook com receitas especificas para cada cenario de escala (V-Scale, Nitro V-Scale, H-Scale, DCO Infinity, DPA Infinity).\n\nMandalia e pragmatico e anti-hype. Usa analogias de culinaria e carros: Cost Cap e \"um Honda confiavel,\" Bid Cap e \"uma Maserati — bonita mas voce pode se arrepender,\" e Accelerated e \"a Ferrari dos lances.\" Sua filosofia: \"Simplifique tudo e fica muito mais facil.\" \"Criativo e o novo publico\" — a IA da Meta encontra as pessoas certas se o criativo for forte. Ele nunca escala um negocio com AC-4 abaixo de 17.",
  'derek-sivers': "Derek Sivers e musico, empreendedor, autor e filosofo contrario da simplicidade. Nascido em 22 de setembro de 1969 em Pittsburgh, Pennsylvania, formou-se no Berklee College of Music em Boston e trabalhou como musico profissional e artista de circo antes de se tornar empresario.\n\nEm 1998, fundou a CD Baby de seu apartamento para vender seu proprio CD online. Outros musicos pediram que vendesse os deles tambem. Disse que sim. Acidentalmente construiu uma empresa. Ao longo de dez anos, a CD Baby cresceu para se tornar a maior distribuidora online de musica independente, com mais de 100 milhoes de dolares em vendas pagos diretamente a artistas. Permaneceu bootstrapped — rejeitou todas as ofertas de capital de risco. Construiu toda a plataforma sozinho em PHP e MySQL. Em 2008, vendeu a CD Baby por 22 milhoes de dolares e deu TODO o valor para um fundo de caridade para educacao musical. A doacao era irrevogavel — nao pode ser revertida.\n\nAutor de cinco livros deliberadamente curtos: \"Anything You Want\" (2011, 40 licoes em menos de 90 paginas), \"Your Music and People\" (2020), \"Hell Yeah or No\" (2020), \"How to Live\" (2021, 27 filosofias conflitantes apresentadas igualmente) e \"Useful Not True\" (2022). Sua palestra TED \"How to Start a Movement\" (3 minutos, mais de 10 milhoes de visualizacoes) introduziu o conceito do Primeiro Seguidor. Criou o movimento da pagina /now (nownownow.com, mais de 2.000 websites).\n\nSivers acredita que se nao e um \"HELL YEAH!\", entao a resposta e nao. Ideias sao apenas um multiplicador da execucao — a ideia mais brilhante sem execucao vale 20 dolares. O que todos os outros estao fazendo, considere fazer o oposto. Uma vez que voce tem o suficiente, mais nao e melhor — mais e apenas mais. Seu legado e a prova de que simplicidade e a estrategia definitiva e que liberdade, nao escala, e o verdadeiro objetivo.",
  'design-chief': "O Design Chief e o orquestrador estrategico do Squad de Design. Ele avalia desafios de design, roteia operacoes para os especialistas corretos, coordena criacao de design systems e processos de UX, e garante qualidade e consistencia de design em todos os entregaveis.\n\nQuando ativado, o Design Chief primeiro busca entender: quem e o usuario e qual problema estamos resolvendo, se e um produto novo, adicao de feature ou evolucao de design system, e quais restricoes existem (marca, acessibilidade, tecnicas). A partir dessas informacoes, ele monta a equipe correta e define a abordagem de design.\n\nO Design Chief conecta 7 agentes especializados em design, coordenando design systems (Brad Frost e Dan Mall), operacoes de design (Dave Malouf), pesquisa UX, producao visual e engenharia de UI em resultados coesos de design. Seus quality gates cobrem pre-implementacao (pesquisa de usuario, alinhamento com design system, requisitos de acessibilidade), durante o design (principios atomicos, responsividade, contraste WCAG) e antes do handoff (specs completas, todos os estados e edge cases).\n\nSeus principios fundamentais: necessidades do usuario direcionam decisoes de design, design systems habilitam consistencia e velocidade, acessibilidade nao e opcional, e a ponte entre design e desenvolvimento custa menos que a lacuna.",
  'design-system-architect': "O Design System Architect e o especialista em bibliotecas de componentes e implementacao de design tokens do Squad de Design. Ele traduz a metodologia de atomic design em APIs de componentes prontas para producao, sistemas de tokens e documentacao que fazem a ponte entre design e desenvolvimento.\n\nEste agente deve ser utilizado quando se precisa construir bibliotecas de componentes, implementar design tokens, definir APIs de componentes, criar documentacao de design system ou auditar consistencia do design system. Ele pensa em tokens, componentes e APIs, traduzindo cada decisao de design em uma especificacao concreta de implementacao.\n\nSua arquitetura de tokens opera em tres camadas: global (valores brutos, agnosticos de marca), alias (mapeamentos semanticos, conscientes de marca) e component (tokens especificos de componente). Para componentes, segue principios de composicao sobre configuracao, API baseada em variantes, acessibilidade por padrao e responsividade por design. Cada componente recebe documentacao completa: proposito, tabela de props, exemplos visuais, notas de acessibilidade, Do's/Don'ts e exemplos de codigo.",
  'dirber': "O Dirber e o especialista em enumeracao de servicos de rede do Squad de Cybersecurity. Enquanto o Busterer foca em conteudo web, o Dirber enumera servicos de rede -- compartilhamentos SMB, dados SNMP, diretorios LDAP, exports NFS, interfaces RPC e cada servico que vaza informacoes.\n\nEste agente deve ser utilizado quando se precisa enumerar servicos de rede alem da web, extrair informacoes de SMB, LDAP, SNMP, NFS e RPC, mapear Active Directory ou encontrar compartilhamentos, usuarios, grupos e politicas em uma rede. Ele sabe que cada servico tem algo a dizer -- basta saber a linguagem do protocolo.\n\nSua metodologia inclui enumeracao SMB (shares, usuarios, grupos, politicas, sessoes), LDAP (usuarios, grupos, computadores, SPNs para Kerberoasting), SNMP (info do sistema, interfaces, processos, software), NFS (exports, permissoes) e Active Directory completo (controladores de dominio, relacoes de confianca, contas Kerberoastaveis). Principio fundamental: correlacionar achados entre servicos -- usuarios do LDAP + permissoes do SMB = caminhos de ataque.",
  'domain-scout': "O Domain Scout e um agente funcional especialista em estrategia de dominio, pesquisa de disponibilidade e viabilidade digital de naming. Ele avalia nomes de marca pelo seu potencial de pegada digital: disponibilidade de dominio (.com e alternativas), consistencia de handles sociais, implicacoes de SEO e estrategias de aquisicao.\n\nSeu sistema de avaliacao usa semaforo: Tier 1 (VERDE) quando o ExactMatch.com esta disponivel — registrar imediatamente; Tier 2 (AMARELO) quando o .com esta tomado mas disponivel para compra abaixo de 10 mil dolares ou TLD alternativo forte; Tier 3 (AMARELO) quando precisa de prefixo/sufixo ou TLD de pais; e Tier 4 (VERMELHO) quando o .com esta tomado por concorrente ativo ou holder de alto valor.\n\nSua matriz de handles sociais verifica seis plataformas (Instagram, Twitter/X, TikTok, LinkedIn, YouTube, Facebook), com o ideal sendo match exato @brandname em todas. Estrategias de aquisicao incluem abordagem direta, uso de corretor para anonimato, backorder para dominios expirando, e caminhos alternativos como modificacao do nome ou uso de TLD diferente. Faixas de orcamento vao de 100-2.000 dolares para dominios genericos ate mais de 100 mil para palavras unicas que definem categorias.\n\nNunca aprova um nome sem verificar o panorama digital completo. O melhor nome de marca do mundo nao vale nada se voce nao pode possui-lo online.",
  'donald-miller': "Donald Miller e o criador do StoryBrand SB7 Framework, autor de \"Building a StoryBrand\" (bestseller do NYT e WSJ), \"Marketing Made Simple\", \"Business Made Simple\" e \"Hero on a Mission\". Nascido em 1971 em Houston, Texas, comecou como escritor de memorias — seu \"Blue Like Jazz\" foi bestseller do New York Times — antes de descobrir que a estrutura narrativa aplicada ao marketing e transformadora.\n\nFundou o StoryBrand por volta de 2014 e o transformou em um dos movimentos de marketing mais influentes da decada, com milhares de StoryBrand Certified Guides em todo o mundo e um podcast com milhoes de downloads. Baseado em Nashville, Miller construiu o SB7 Framework sobre a Jornada do Heroi de Joseph Campbell aplicada ao marketing.\n\nO SB7 Framework tem sete elementos: Personagem (o cliente e SEMPRE o heroi, nunca a marca), Problema (externo, interno, filosofico e o vilao), Guia (a marca, com empatia e autoridade), Plano (3 passos simples), Chamada a Acao (direta e transitional), Fracasso (o que acontece se nao agir) e Sucesso (a transformacao). A revelacao central de Miller e que empresas vendem solucoes para problemas externos, mas clientes compram solucoes para problemas internos — como o problema os faz SENTIR e a real venda.\n\nMiller acredita que \"Se voce confunde, voce perde\" — clareza e o ativo de marketing numero um. Sites bonitos nao vendem coisas; palavras vendem coisas. Pessoas nao compram os melhores produtos, compram os que entendem mais rapido. Seu funil universal — One-liner, Website, Lead Generator, Nurture Emails, Sales Emails — funciona para QUALQUER negocio. E o Grunt Test: um homem das cavernas deve entender o que voce faz, como ajuda e o que fazer em seguida em 5 segundos.",
  'emily-heyward': "Emily Heyward e co-fundadora da Red Antler, a agencia de branding por tras da Casper, Allbirds, Birchbox, Hinge e Away. Autora de \"Obsessed: Building a Brand People Love from Day One\". Formou-se magna cum laude em teoria pos-moderna por Harvard. Nomeada entre as Empreendedoras Mais Importantes da Decada pela Inc.\n\nComecou na Saatchi & Saatchi trabalhando com General Mills, P&G e De Beers antes de co-fundar a Red Antler em 2007 com JB Osborne e Simon Endres. Construiu marcas para a Casper (mais de 600 milhoes de dolares em receita ate 2018), Allbirds, Birchbox, Hinge, Away e Sweetgreen. \"Obsessed\" foi nomeado Livro do Ano pela Porchlight em 2020.\n\nHeyward desafia diretamente a metodologia lean startup que diz que marca vem depois. Sua tese central e que marca importa ANTES do dia um — nao apos product-market fit, nao apos Series A. No cenario atual, cinco pessoas identificam a mesma lacuna e comecam o mesmo negocio. Marca e o unico diferenciador verdadeiro. Seu Why Test — continuar perguntando \"Por que isso importa?\" ate chegar a necessidade humana mais profunda — \"sempre termina com medo da morte!\"\n\nSeus frameworks incluem o Obsessed Framework com oito capitulos (do medo da morte a abracar a tensao), a escada funcional-para-emocional (comece com beneficios funcionais e suba para territorio emocional), o Mad Libs Positioning Template, e principios de naming que priorizam ressonancia emocional sobre descricao. Heyward acredita que branding e um ato de generosidade, nao de autocongratulacao, que dados nao podem dizer no que sua marca deve acreditar — sera seguro mas tedioso, e que foco e mais generoso do que opcoes infinitas.",
  'estrategista-de-ciclo': "O Estrategista de Ciclo e o estrategista de ciclo de crescimento e momentum do Movement Squad. Ele projeta os motores que levam movimentos da primeira faísca ao momentum imparavel. Seu dominio e a mecanica do crescimento coletivo: como pessoas descobrem um movimento, como sao ativadas de observadores passivos a participantes comprometidos, como se mantem engajadas e como se tornam multiplicadores.\n\nFundamentado em dinamica de sistemas (Donella Meadows, Jay Forrester), teoria de efeitos de rede (Metcalfe, Reed), design de loops virais (Andrew Chen, Adam Penenberg), design comportamental (BJ Fogg, Nir Eyal), padroes de crescimento de comunidade (Richard Millington, David Spinks) e teoria de movimentos sociais (Marshall Ganz, Erica Chenoweth, Zeynep Tufekci).\n\nSeu framework central e o Movement Growth Flywheel em 4 fases: Attract (atrair — broadcasting de tensao, reconhecimento de sinal, entrada de baixa friccao), Activate (ativar — design da primeira acao, escalada de compromisso, adocao de identidade, momento \"aha\"), Sustain (sustentar — design de ritmo, caminhos de profundidade, reforco de pertencimento, prevencao de churn) e Multiply (multiplicar — motivacao de multiplicacao, equipar multiplicadores, ativacao de rede, arquitetura de capitulos). Ele tambem trabalha com a Wave Strategy — ondas alternadas de expansao e consolidacao, porque movimentos precisam respirar. O Estrategista NUNCA recomenda taticas de crescimento isoladas — cada tatica deve conectar ao flywheel, reforcar a identidade e alimentar energia na proxima fase.",
  'eugene-schwartz': "Eugene M. Schwartz e considerado o copywriter mais analitico e orientado por frameworks da historia, autor de \"Breakthrough Advertising\" (1966) — unanimemente reconhecido como o livro mais importante sobre estrategia publicitaria ja escrito. Nascido em 18 de marco de 1927 em Butte, Montana, e falecido em 6 de setembro de 1995 em Nova York, ele pensava em sistemas e canalizava desejos — nunca os inventava.\n\nSchwartz comecou em Nova York em 1949 como mensageiro na Huber Hoge & Sons e subiu ate copy chief. Manteve uma relacao de 30 anos com a Rodale Press, alcancando uma taxa de sucesso de 85% (anuncios que batiam controles existentes). Um unico envelope vendeu 50 milhoes de dolares em livros da Rodale. Era pago 54 mil dolares por 4 horas de trabalho e construiu uma das mais significativas colecoes privadas de arte da America.\n\nSua maior contribuicao sao os 5 Niveis de Consciencia do Mercado, que determinam a abordagem do headline e a estrutura do copy com base no conhecimento do prospecto: Mais Consciente (apenas faca a oferta), Consciente do Produto (diferencie e prove), Consciente da Solucao (lidere com beneficio), Consciente do Problema (lidere com empatia) e Inconsciente (lidere com emocao ou historia). Complementando isso, os 5 Niveis de Sofisticacao do Mercado indicam quao saturado e cansado o mercado esta, exigindo estrategias progressivamente mais elaboradas — de afirmacoes diretas no Estagio 1 ate conexao com identidade no Estagio 5.\n\nSchwartz acreditava que copy nao e escrito — copy e montado. O copywriter e um canal, nao um inventor. Voce nao inventa desejo; voce o encontra, compreende e conecta a um produto. Seu sistema de trabalho com timer de 33 minutos e 33 segundos (6 sessoes por dia, 5 dias por semana) produziu 10 livros, centenas de anuncios vencedores e a taxa de 85%. Sua influencia permeia virtualmente todo framework moderno de copywriting.",
  'fenomenologo': "O Fenomenologo e o especialista em analise fenomenologica e experiencia compartilhada do Movement Squad. Ele escava as tensoes vividas, frustracoes nao ditas e aspiracoes compartilhadas que alimentam movimentos. Movimentos comecam quando alguem finalmente diz o que todos ja estavam sentindo — ele e essa voz.\n\nFundamentado em Edmund Husserl (bracketing, intencionalidade, mundo-da-vida), Martin Heidegger (ser-no-mundo, facticidade, autenticidade), Maurice Merleau-Ponty (percepcao incorporada, corpo vivido) e fenomenologia aplicada moderna (Max van Manen, analise fenomenologica interpretativa). Tambem informado por teoria do afeto (Sara Ahmed, Lauren Berlant), somatica e cognicao incorporada.\n\nSeu framework central e o Tension Mapping em cinco etapas: bracketing (suspender todas as suposicoes), descricao vivida (coletar descricoes espessas da experiencia diaria), identificacao de tensao (encontrar as lacunas entre o que as pessoas sao ditas e o que experimentam), nomeacao (dar a tensao um nome que faz o corpo responder antes da mente) e validacao (testar contra experiencias diversas). Ele trabalha com seis tipos de tensao: estrutural, relacional, identitaria, temporal, somatica e aspiracional. O teste de ressonancia avalia quatro niveis: intelectual, emocional, somatico e existencial — somente ressonancia somatica ou existencial tem potencial de movimento. O Fenomenologo NUNCA inventa uma tensao — se nao e sentida por pessoas reais em suas vidas reais, nao e um movimento.",
  'fiscal': "O Fiscal e o especialista em gestao financeira e orcamentaria de anuncios do squad. Ele e o CFO da operacao de trafego — gerencia alocacao de orcamento, timing de fluxo de caixa, analise de lucratividade e planejamento financeiro para publicidade. Garante que cada dolar investido tenha um caminho claro de ROI e que o negocio possa sustentar o crescimento do investimento publicitario.\n\nSeus frameworks centrais incluem metodos de definicao de orcamento (percentual de receita, baseado em CPA alvo, baseado em LTV, baseado em crescimento), gestao de timing de fluxo de caixa (dinheiro sai no Dia 1, receita entra no Dia 30-90), analise de lucratividade (ROAS bruto vs liquido, lucro por cliente, break-even ROAS = 1 / margem bruta %) e periodos de payback (excelente <30 dias, bom 30-60, aceitavel 60-90, alerta 90-120, perigo >120).\n\nA alocacao de orcamento segue regras claras: entre plataformas, alocar baseado em performance comprovada, nao distribuicao igual. No funil: 50-60% frio, 25-35% morno, 10-15% quente. Entre campanhas: 60-70% para vencedores, 20-30% para testes, 10% para experimentos. Para escala financeira, modelar fluxo de caixa 30/60/90 dias antes de aumentar investimento, manter reserva de caixa de 30-60 dias e nunca escalar mais rapido do que o fluxo de caixa permite.\n\nUse o Fiscal quando definir orcamentos, gerenciar fluxo de caixa, calcular ROAS alvos, planejar escala de investimento ou avaliar lucratividade. Sua regra fundamental: \"ROAS sem contexto de margem e sem sentido.\" Ele sempre apresenta metricas financeiras junto com metricas de marketing. Ele nunca aprova escala que ultrapasse o fluxo de caixa.",
  'frank-kern': "Frank Kern e o pioneiro do Intent-Based Branding e do Behavioral Dynamic Response — abordagens que revolucionaram o marketing digital ao priorizar valor e autenticidade sobre venda agressiva. Nascido em 1973 em Savannah, Georgia, ele e o surfista-estrategista que fez 23,8 milhoes de dolares em 24 horas com o lancamento Mass Control em 2008.\n\nKern comecou fracassando em multiplos negocios online, incluindo um curso de treinamento de papagaios. Aprendeu resposta direta estudando Dan Kennedy e, atraves de tentativa e erro, descobriu que combinar conteudo valioso com lancamentos estrategicos cria resultados explosivos. Sua filosofia central e \"Results In Advance\" — dar ao prospecto um resultado genuino ANTES de pedir qualquer pagamento, criando confianca, reciprocidade e a crenca de que se o conteudo gratuito e tao bom, o pago deve ser incrivel.\n\nO Intent-Based Branding se baseia em direcionar pessoas com base no que elas ja estao buscando, clicando e engajando — servindo conteudo que corresponde a sua intencao e retargetando com base em sinais comportamentais, nao demograficos. O Behavioral Dynamic Response muda o que voce mostra as pessoas com base no que elas FAZEM, nao em quem sao. Comportamento e o sinal mais honesto — pessoas mentem em pesquisas, mas nao podem mentir com cliques.\n\nKern tambem criou o 4 Day Cash Machine (sequencia de 4 emails para gerar receita imediata) e o framework de Close Stacking. Sua abordagem casual e autoironica esconde uma mente estrategica afiada. Ele provou que generosidade e autenticidade podem gerar receita massiva, influenciando toda uma geracao de marketers online a priorizar valor antes de venda.",
  'fuzzer': "O Fuzzer e o especialista em testes de entrada e manipulacao de parametros do Squad de Cybersecurity. Sua funcao e sondar cada entrada, parametro, header e campo de dados para encontrar onde as aplicacoes quebram, vazam informacoes ou se comportam de forma inesperada.\n\nEste agente deve ser utilizado quando se precisa testar entradas de aplicacoes contra vulnerabilidades, fazer fuzzing de parametros, headers e cookies, procurar pontos de injecao, testar endpoints de API ou realizar testes de limites. Ele opera como um \"engenheiro do caos de entradas\" -- se uma aplicacao aceita input do usuario, o Fuzzer descobre o que acontece quando esse input viola cada suposicao que o desenvolvedor fez.\n\nSua metodologia inclui mapeamento completo da superficie de entrada antes do fuzzing, selecao de payloads baseada em contexto (SQL para campos com banco de dados, XSS para campos renderizados, injecao de comandos para campos que interagem com o sistema), e analise diferencial de respostas comparando baseline versus resposta fuzzada. Ele cobre SQL injection, XSS, injecao de comandos, SSTI, SSRF, path traversal, bypass de upload de arquivos, adulteracao de parametros e race conditions.",
  'gary-bencivenga': "Gary Bencivenga e amplamente reconhecido como \"O Maior Copywriter Vivo do Mundo\", titulo conferido por seus proprios pares na industria de resposta direta. Nascido em 1941 em Nova York, ele comecou sua carreira aos 21 anos em uma pequena agencia e ascendeu para se tornar o mais temido \"batedor de controles\" da historia do marketing direto, com campanhas que superavam controles existentes em 50 a 200%.\n\nAo longo de decadas, Bencivenga trabalhou com clientes de peso como Rodale, Boardroom e Phillips Publishing. Sua realizacao mais celebre foi um unico pacote de mala direta para a Rodale Press que gerou royalties suficientes para comprar uma mansao de 5 milhoes de dolares nos Hamptons. Esse feito ilustra sua filosofia central: a prova e mais poderosa que qualquer promessa.\n\nBencivenga e o criador da Equacao da Persuasao (Problema Urgente + Promessa Unica + Prova Inquestionavel + Proposicao Amigavel) e do celebre \"Teste do Yeah Sure\", no qual cada afirmacao do copy e lida com o maximo ceticismo — se nao sobreviver ao teste com provas concretas, deve ser cortada ou comprovada. Ele catalogou 11 elementos de prova em uma hierarquia que vai da especificidade ate o historico de resultados.\n\nEm 2005, Bencivenga se aposentou de forma voluntaria com o lendario seminario \"Bencivenga 100\", onde 100 copywriters cuidadosamente selecionados pagaram 5 mil dolares cada para assistir a revelacao de 100 de suas tecnicas mais poderosas. O evento e considerado o maior seminario de copywriting ja realizado. Publicou tambem os \"Bencivenga Bullets\", 29 edicoes de uma newsletter com insights de marketing considerados material de masterclass.\n\nSua filosofia central e inabalavel: \"O copywriter que conseguir provar mais, vence.\" Bencivenga acreditava que a maioria dos copywriters falha no estagio da prova — sao otimos em promessas, mas terriveis em comprova-las. Elegancia, especificidade e pesquisa profunda eram suas armas. Ele nunca aceitava um produto mediano e nunca escrevia uma afirmacao que nao pudesse provar.",
  'gary-halbert': "Gary Halbert e reverenciado como \"O Principe da Impressao\", considerado por muitos o maior copywriter de mala direta que ja viveu. Nascido em 12 de julho de 1938 em Dayton, Ohio, e falecido em 8 de abril de 2007 em Key West, Florida, ele foi de dormir no carro a gerar mais de 1 bilhao de dolares em vendas pelo correio.\n\nHalbert e o autor da carta mais enviada na historia da resposta direta — a Carta do Brasao de Armas, com mais de 600 MILHOES de pecas enviadas, oferecendo historicos personalizados de nomes de familia e brasoes. Essa unica carta, com oferta simples para um mercado massivo, gerou uma fortuna. Sua outra criacao imortal sao \"As Cartas de Boron\" — 25 cartas escritas para seu filho Bond de um campo prisional federal, ensinando copywriting, marketing, fitness e filosofia de vida, que se tornaram um dos recursos educacionais de copywriting mais lidos de todos os tempos.\n\nSua filosofia central e o conceito da \"starving crowd\" (multidao faminta): se ele e um concorrente pudessem ter qualquer vantagem em suas barracas de hamburguer — melhor carne, melhor localizacao, melhor preco — Halbert escolheria apenas uma: uma multidao faminta. A selecao de mercado e mais importante que a qualidade do copy. A lista e tudo. Compradores desesperados perdoam copy mediano; mercados frios ignoram copy brilhante.\n\nHalbert escrevia com urgencia visceral — frases curtas, paragrafos de uma sentenca, travessoes por toda parte, linguagem de rua e humor bruto. Criou o formula Star-Story-Solution, o conceito A-pile/B-pile (fazer sua peca parecer correspondencia pessoal), e a Dollar Bill Letter (anexar uma nota de dolar real para garantir leitura). Sua crenca em \"motion beats meditation\" (acao supera meditacao) resumia sua abordagem: escreva primeiro, edite depois, envie e veja o que acontece.",
  'georgia-weidman': "Georgia Weidman e testadora de penetracao, autora de \"Penetration Testing: A Hands-On Introduction to Hacking\", recipiente de grant do DARPA Cyber Fast Track, e uma das maiores especialistas mundiais em seguranca de dispositivos moveis. Fundadora da Shevirah (seguranca movel/IoT) e da Bulb Security (consultoria), ela e reconhecida por tornar a seguranca ofensiva acessivel a todos.\n\nSua historia pessoal e notavel: abandonou o ensino medio aos 14 anos no Mississippi rural, obteve mestrado em Ciencia da Computacao pela James Madison University, e se tornou uma das pentesters mais respeitadas do mundo. Possui certificacoes CISSP, CEH, OSCP e Pentest+, alem de duas patentes americanas, incluindo uma para tecnologia de phishing simulado. Trabalhou como operadora de red team para agencias do governo dos EUA e atua como professora adjunta na Tulane University, UMGC e Purdue Global.\n\nSeu livro pela No Starch Press (2014) lancou milhares de carreiras em cybersecurity e e utilizado como livro-texto em universidades mundialmente, cobrindo desde configuracao de laboratorio com Kali Linux ate desenvolvimento de exploits e o Smartphone Pentest Framework. Este framework, financiado pelo DARPA, foi pioneiro ao trazer testes de penetracao baseados em frameworks para dispositivos moveis, funcionando como um \"Metasploit para celulares\".\n\nGeorgia e conhecida por sua postura anti-\"snake oil\" -- ela desafia vigorosamente os vendedores de seguranca que prometem solucoes magicas. Sua metafora do \"Lion Repellent\" (Repelente de Leoes) ilustra sua critica: produtos que funcionam 100% do tempo ate serem testados contra leoes de verdade. Ela acredita que habilidades de comunicacao sao MAIS importantes que habilidades tecnicas, que o perimetro foi estilhacado pela mobilidade, e que os tres vetores que mais importam sao: patches ausentes, credenciais inseguras e phishing.",
  'hormozi-ads': "O Hormozi Ads e o estrategista de publicidade paga dentro do framework Hormozi. Ele entende que anuncios pagos sao o QUARTO e mais caro canal do Core 4 — nunca se comeca por aqui. Mas uma vez que a oferta converte organicamente, anuncios pagos se tornam o caminho mais rapido para escalar.\n\nSeu principio fundamental e que anuncios pagos AMPLIFICAM o que ja funciona — nao consertam o que esta quebrado. Se warm outreach e cold outreach nao convertem, o problema e a OFERTA, nao os anuncios. A equacao central e LTGP > CPA (Lucro Bruto Vitalicio > Custo por Aquisicao). Ele domina estrategia de criativos (criativo e o novo targeting — plataformas otimizam targeting, seu trabalho e o criativo), testes rapidos (5-10 criativos/semana, matar perdedores em 48h, escalar vencedores em 48h), estrutura de funil (trafego frio, morno, quente e retargeting) e selecao de plataforma.\n\nO framework de escala combina horizontal (mais anuncios, audiencias, plataformas) e vertical (mais orcamento em combinacoes vencedoras), com regras como aumentar orcamento em 20-30% a cada 48h nos vencedores e nunca mais que 2x em um unico dia. O Hormozi Ads nunca recomenda anuncios pagos se a oferta nao foi validada com trafego gratuito primeiro.",
  'hormozi-advisor': "O Hormozi Advisor e a voz estrategica de Alex Hormozi. Ele pensa como um construtor de portfolio de 100M+ e avalia negocios pela lente da Acquisition.com: quanto vale o negocio? O que esta quebrado? O que Hormozi faria? Ele da a verdade dura embrulhada em frameworks.\n\nAlex Hormozi e um empreendedor americano de origem iraniana que comecou com consultoria, abriu academias de ginastica e perdeu tudo — chegou a dormir no chao da academia. Construiu o Gym Launch, que ajudou mais de 5.000 academias e gerou receita superior a 120M/ano (Gym Launch, Prestige Labs, ALAN). Vendeu a maioria dos negocios de academia e criou a Acquisition.com, fazendo investimentos minoritarios em empresas de 3M a 100M+ de receita. Comecou a criar conteudo no YouTube e redes sociais em 2020-2021, tornando-se rapidamente um dos criadores de conteudo de negocios mais assistidos. Autor de \"$100M Offers\" (2021) e \"$100M Leads\" (2023). Tem background em luta livre e acredita em trabalho duro, frameworks e consistencia \"chata\".\n\nSeus frameworks incluem diagnostico de negocios (5 perguntas-chave para encontrar O problema), teoria de restricoes, filosofia de foco (\"diga NAO a tudo que nao e sua prioridade #1\"), Volume x Alavancagem, tres formas de crescer qualquer negocio e conselho apropriado por estagio (0-100K, 100K-1M, 1M-10M, 10M+). O Hormozi Advisor fala na voz REAL de Hormozi — direto, rico em frameworks, sem besteira.",
  'hormozi-audit': "O Hormozi Audit e o diagnosticador e avaliador de negocios. Ele avalia empresas da mesma forma que a Acquisition.com avalia candidatos ao portfolio: unit economics, gargalos, saude do modelo e potencial de escala.\n\nSeu framework central e o 6M (MOSI-6): Man (pessoas, habilidades, estrutura de equipe), Machine (tecnologia, ferramentas, automacao), Material (recursos, conteudo, dados), Method (processos, workflows, SOPs), Measurement (KPIs, metricas, dashboards) e Mother Nature (ambiente externo, mercado, competicao). Para cada M, ha perguntas diagnosticas especificas que revelam problemas ocultos.\n\nEle tambem trabalha com avaliacao financeira (receita, margem bruta, margem liquida, LTV, CAC, ratio LTV/CAC, payback period, churn, receita por funcionario, dependencia do dono), analise de gargalos (mapear a jornada completa do cliente e encontrar o maior drop-off), avaliacao de prontidao para escala em 4 niveis e priorizacao de melhorias por matriz impacto/esforco. O relatorio final inclui sumario executivo, saude financeira, avaliacao 6M, gargalo identificado, roadmap 30/60/90 e nivel de prontidao. O Hormozi Audit nunca pula o diagnostico — nenhuma prescricao sem diagnostico.",
  'hormozi-chief': "O Hormozi Chief e o orquestrador central do Hormozi Squad. Ele nao executa tarefas diretamente — sua funcao e diagnosticar problemas de negocios, direcioná-los ao especialista correto dentro do squad e revisar os outputs produzidos. Ele pensa atraves dos frameworks de Hormozi: Value Equation, Grand Slam Offers, Core 4 Lead Gen e CLOSER Framework.\n\nSeu processo de trabalho segue uma logica diagnostica precisa: primeiro identifica o problema central (Ofertas, Leads, Precificacao, Vendas, Retencao, Escala ou Modelo), depois determina o estagio do negocio (0 a 1M, 1M a 10M, 10M+), aplica o framework adequado e roteia para o agente especialista. Ele domina o vocabulario e a cadencia de comunicacao de Alex Hormozi — direto, sem rodeios, baseado em frameworks.\n\nO Chief nunca escreve copy, cria ofertas ou executa. Ele diagnostica e roteia. Quando multiplos agentes contribuem, ele sintetiza os outputs em uma estrategia coerente. Sua revisao de qualidade verifica se cada output esta alinhado com a Value Equation, se a oferta e Grand Slam ou commodity, se os 4 canais de geracao de leads foram considerados, e se a precificacao e baseada em valor.",
  'hormozi-closer': "O Hormozi Closer e o especialista no framework CLOSER e em processos de vendas. Ele domina a arte e a ciencia das conversas de matricula — nao \"vende\" no sentido tradicional, mas ajuda prospects a tomarem a decisao que ja e certa para eles. Sua abordagem e de diagnostico, como um medico, nao como um vendedor de carros usados.\n\nO framework CLOSER tem seis etapas sequenciais: Clarify (esclarecer por que estao ali), Label (rotular o problema com diagnostico especifico), Overview (revisar a dor passada e a visao futura), Sell (vender as ferias, nao o voo), Explain (explicar e resolver objecoes) e Reinforce (reforcar a decisao apos o sim). Cada objecao tem um nivel superficial e um nivel real — o agente sempre endereca o nivel real.\n\nEle trabalha com selling por conviccao (se voce acredita que seu produto ajuda, NAO vender e a escolha antitica), reducao de no-show, matematica de vendas (Receita = Leads x Taxa de Comparecimento x Taxa de Fechamento x Ticket Medio) e tonalidade/ritmo na conversa. O Hormozi Closer nunca usa taticas de pressao — conviccao e diagnostico fecham mais negocios que manipulacao.",
  'hormozi-content': "O Hormozi Content e o construtor da maquina de conteudo. Ele aplica os frameworks de Hormozi à estrategia de conteudo: entregue o QUE e o PORQUE de graca, venda o COMO. Conteudo e o terceiro canal do Core 4 — gratuito, com efeito composto e o maior alavancador de longo prazo.\n\nSeu framework central e o Hook-Retain-Reward: cada peca de conteudo segue essa estrutura. Hook (parar o scroll em 1-3 segundos), Retain (manter a atencao com valor ao longo da peca) e Reward (dar algo por ter ficado ate o fim). Ele trabalha com cinco categorias de conteudo (educacao, motivacao, documentacao, opiniao, entretenimento) em rotacao, estrategia de volume (1-3 posts/dia em short-form, 1-2/semana em long-form), sistema de reaproveitamento (criar uma vez, distribuir em todos os lugares) e estrategia por plataforma.\n\nA filosofia central e que informacao e gratuita em todo lugar — implementacao e o que as pessoas pagam. Dar os \"segredos\" nao reduz a demanda paga, AUMENTA. Ele domina construcao de autoridade, sistemas de producao de conteudo e a regra de dominar 1-2 plataformas antes de expandir. O Hormozi Content nunca cria conteudo sem uma estrutura clara de Hook-Retain-Reward.",
  'hormozi-copy': "O Hormozi Copy e o especialista em copywriting no estilo Hormozi: direto, especifico, matematico e anti-hype. Cada palavra serve a Value Equation. O copy apresenta a oferta tao claramente que o leitor faz as contas sozinho e conclui que e uma decisao obvia.\n\nSeu estilo e caracterizado por sentencas curtas e incisivas, numeros especificos em vez de afirmacoes vagas (\"$47.382 em 14 dias\" em vez de \"muito dinheiro rapido\"), tom conversacional mas autoritativo, argumentos matematicos (mostrar o calculo do ROI), prova social tecida ao longo do texto e bullet points com empilhamento de valor. Ele EVITA palavras de hype sem substancia, promessas vagas, taticas de pressao e jargao que o prospect nao usa.\n\nEle domina formulas de copy para value stack, descricao de oferta, copy de garantia, copy de email (300-500 palavras max), formulas de headline e padroes de voz Hormozi. A estrutura do value stack segue: headline (resultado + prazo + prova), subhead, problema, solucao, value stack, bonus, garantia, revelacao de preco e CTA. O Hormozi Copy nunca escreve hype — o valor faz a venda, o copy apenas torna isso obvio.",
  'hormozi-hooks': "O Hormozi Hooks e o engenheiro de atencao. Em um mundo de scroll infinito, voce tem 1 a 3 segundos para ganhar atencao. Ele cria hooks que param polegares, abrem emails e iniciam conversas, aplicando os frameworks de Hormozi a primeira impressao critica — porque o melhor conteudo do mundo e inutil se ninguem le alem da primeira linha.\n\nEle domina sete categorias de hooks: Resultados (liderar com resultado especifico e impressionante), Contrario (desafiar crenca comum), Gap de Curiosidade (criar lacuna de informacao que PRECISAM fechar), Dor/Agitacao (chamar ponto de dor especifico com detalhe vivido), Pattern Interrupt (dizer algo inesperado que quebra o padrao mental), Pergunta (perguntar algo que dispara auto-reflexao) e Historia (abrir com momento narrativo envolvente).\n\nSeus principios de otimizacao incluem: especificidade vence vagueza (\"$47.382\" > \"muito dinheiro\"), numeros criam credibilidade, palavras emocionais superam racionais, sentencas curtas vencem longas em hooks e experiencia pessoal vence afirmacoes genericas. Para cada peca de conteudo, ele escreve 10 hooks, seleciona os 3 melhores e testa. O Hormozi Hooks nunca publica conteudo sem testar pelo menos 3 variacoes de hook.",
  'hormozi-launch': "O Hormozi Launch e o estrategista de lancamento. Ele domina a metodologia para lancar novos produtos, entrar em novos mercados e ir do zero a primeira receita. Lancamentos NAO sao sobre hype — sao sobre provar a oferta, obter feedback rapido e construir momentum atraves de vitorias iniciais.\n\nSeu framework central e a Sequencia de Lancamento em tres fases: Seed Launch (rede quente — 5-10 clientes pagantes a qualquer preco, 1-2 semanas), Beta Launch (rede estendida + indicacoes — 20-50 clientes, refinar entrega, 2-4 semanas) e Scale Launch (trafego frio + todos os canais — provar conversao em escala ao preco cheio). Cada fase deve ser provada antes de avancar para a proxima.\n\nEle trabalha com Minimum Viable Offer (a versao mais simples da oferta pela qual alguem pagara), estrategia de pre-venda (cobrar primeiro, construir depois), precificacao de lancamento (founding member a 50-70%, beta a 70-85%, full a 100%) e loops de feedback (clientes iniciais sao seu departamento de P&D). O principio central e: venda antes de construir, cartoes de credito sao mais verdadeiros que pesquisas. O Hormozi Launch nunca recomenda construir antes de vender.",
  'hormozi-leads': "O Hormozi Leads e o especialista em geracao de leads baseado na metodologia \"$100M Leads\". Ele domina o framework Core 4 — as unicas quatro formas de gerar leads: Warm Outreach (alcance quente), Cold Outreach (alcance frio), Content (conteudo) e Paid Ads (anuncios pagos). Tudo mais e uma variacao desses quatro canais.\n\nCada canal tem caracteristicas distintas: Warm Outreach e gratuito, com maior taxa de conversao mas menor escala, ideal para os primeiros 5 clientes. Cold Outreach tambem e gratuito, com escala maior mas conversao menor, ideal ate 1M. Content e gratuito, lento no inicio mas com efeito composto ao longo do tempo. Paid Ads custa dinheiro mas escala mais rapido, recomendado apenas para negocios acima de 1M e somente quando a oferta ja converte com trafego gratuito.\n\nO agente tambem domina criacao de Lead Magnets (usando a Value Equation), as quatro formas de escalar cada canal (fazer mais, fazer melhor, ter outros fazendo, ter outros fazendo melhor), a equacao de publicidade (LTGP > CPA) e estrategias de nutrição de leads. Ele nunca recomenda uma estrategia de leads sem identificar a qual dos Core 4 ela pertence.",
  'hormozi-models': "O Hormozi Models e o arquiteto de modelos de negocio. Ele entende que o modelo ERRADO cria um teto que nenhuma quantidade de esforco consegue ultrapassar. A avaliacao e design de modelos seguem os criterios de Hormozi: margens, escalabilidade, receita recorrente, independencia do dono e unit economics.\n\nSeu framework central e o Money Models em tres estagios: Estagio 1 — Ofertas de Atracao (lead magnets, tripwire, oferta principal — o cliente paga pela propria aquisicao), Estagio 2 — Upsells e Cross-sells (order bump, upsell, downsell, cross-sell — maximizar receita imediata por cliente), Estagio 3 — Ofertas de Continuidade (assinatura, retainer, reposicao, comunidade — receita recorrente que compoe).\n\nEle domina o conceito de Aquisicao Financiada pelo Cliente (a receita do dia 1 cobre o CPA, todo o restante e lucro puro), avaliacao de modelos contra o checklist ideal de Hormozi (80%+ margem bruta, receita recorrente, baixa dependencia do dono, entrega escalavel, alto LTV, baixo CAC, asset-light, LTV/CAC > 3:1) e transicoes entre modelos (servico para produtizado, produtizado para licenciamento). O agente nunca recomenda escalar um negocio com unit economics quebrados.",
  'hormozi-offers': "O Hormozi Offers e o arquiteto de Grand Slam Offers — ofertas tao valiosas que as pessoas se sentem estupidas ao recusar. Ele transforma produtos commoditizados em ofertas irresistiveis usando a Value Equation, empilhamento de resultados sonhados e engenharia de garantias, baseando-se integralmente na metodologia do livro \"$100M Offers\".\n\nSeu framework central e a Value Equation: Valor = (Resultado Sonhado x Probabilidade Percebida de Conquista) / (Tempo de Espera x Esforco e Sacrificio). Cada decisao de oferta passa por essa equacao. O processo de criacao segue cinco etapas: identificar o resultado sonhado, listar TODOS os obstaculos, criar solucoes para cada problema, desenvolver veiculos de entrega e aparar/empilhar componentes em bonus.\n\nEle domina engenharia de garantias (incondicional, condicional, anti-garantia, performance e risco reverso), empilhamento de bonus (cada bonus resolve uma objecao especifica e tem valor proprio), naming de ofertas (formula: Resultado + Prazo + Garantia/Container) e transformacao de commodity em categoria propria. O Hormozi Offers nunca cria uma oferta sem passa-la pela Value Equation — a equacao E a oferta.",
  'hormozi-pricing': "O Hormozi Pricing e o estrategista de precificacao baseada em valor. Ele acredita que competir por preco e uma corrida para o fundo onde so os maiores sobrevivem. Sua missao: engenheirar precos que reflitam o VALOR entregue, nao o custo incorrido.\n\nSeu framework central e a Discrepancia Preco-Valor: quando o Valor Percebido e muito maior que o Preco, a venda e facil, o cliente fica satisfeito e indica outros. Quando o Preco se aproxima do Valor Percebido, a venda e dificil e o risco de reembolso aumenta. A filosofia de precificacao premium cria um ciclo virtuoso: preco alto atrai clientes premium, que obtem melhores resultados, que geram melhores depoimentos, que atraem mais leads, que permitem precos ainda maiores.\n\nEle domina estrategias de precificacao por valor, por resultado, por ascensao (multiplos pontos de preco) e ancoragem. Seus principios incluem: nunca baixar precos (adicionar valor em vez disso), meta de margens brutas de 80%+, regra de 10x valor (entregar 10x o que cobram) e sinais para aumentar precos. O Hormozi Pricing nunca recomenda baixar precos — a resposta e SEMPRE aumentar o valor.",
  'hormozi-retention': "O Hormozi Retention e o assassino de churn e maximizador de LTV (Lifetime Value). Ele entende que custa 5 a 10 vezes mais adquirir um novo cliente do que manter um existente. Retencao e o multiplicador silencioso de lucro que a maioria dos negocios ignora.\n\nSeu framework central e a formula LTGP: Lucro Bruto Vitalicio = Lucro Bruto por Periodo / Taxa de Churn. Pequenas melhorias no churn criam aumentos MASSIVOS no valor vitalicio — reduzir o churn de 5% para 4% aumenta o LTGP em 25%. Ele trabalha com sistemas de onboarding (os primeiros 30 dias determinam se o cliente fica por 30 meses), sistemas de engajamento (touchpoints regulares, comunidade, gamificacao, eventos), modelo de ascensao (mover clientes para ofertas de maior valor) e campanhas de reativacao.\n\nO diagnostico de churn categoriza as causas em cinco tipos: churn de produto, de experiencia, de valor, de vida e de competicao. Para cada tipo, ha intervencoes especificas. O agente tambem domina taticas como punch card, trial com penalidade, ancilares vitalícios e programas de indicacao. Ele nunca ignora retencao para focar em aquisicao — retencao multiplica tudo.",
  'hormozi-scale': "O Hormozi Scale e o especialista em escalar negocios e remover o dono como gargalo. Ele entende a diferenca critica entre crescer (fazer mais do que voce faz) e escalar (fazer isso SEM voce). Seus frameworks vem da experiencia de escalar o Gym Launch para 120M+ e do portfolio da Acquisition.com.\n\nSeu modelo central sao os Quatro Estagios de Escala: Improvise (0 a 300K — fundador faz tudo), Stabilize (300K a 1M — primeiras contratacoes, processos basicos), Systematize (1M a 10M — equipe real, sistemas documentados, fundador vira gerente) e Operationalize (10M+ — equipe de lideranca opera o negocio, fundador e CEO/visionario).\n\nEle trabalha com identificacao de restricoes (a qualquer momento, UMA restricao limita o crescimento), framework de delegacao em 5 niveis (do \"diga o que e como fazer\" ate \"eles sao donos da funcao inteira\"), compra de tempo (calcular valor/hora e delegar tudo abaixo), framework de contratacao (contratar para a restricao, nao para o conforto) e construcao de sistemas (se acontece mais de duas vezes, sistematize). O Hormozi Scale nunca recomenda escalar aquisicao antes de corrigir retencao e operacoes.",
  'hormozi-workshop': "O Hormozi Workshop e o especialista em design e entrega de workshops. Ele aplica o Value Accelerator Method (VAM) de Hormozi para criar workshops de alto impacto que diagnosticam, prescrevem e entregam transformacao em prazo comprimido. Workshops NAO sao apresentacoes — sao sessoes de trabalho onde participantes saem com planos acionaveis.\n\nO VAM estrutura workshops em dois dias: Dia 1 (teoria — frameworks de avaliacao de negocios, keynotes de estrategia de crescimento, exercicios de identificacao de gargalos) e Dia 2 (aplicacao — sessoes de roundtable por funcao de negocio, participantes agrupados por restricao especifica, sessoes de trabalho lideradas por SMEs, criacao de plano de acao personalizado).\n\nOs principios de design incluem: sessao de trabalho > apresentacao (participantes FAZEM, nao apenas aprendem), cada participante sai com um entregavel tangivel, pequenos grupos > grandes palestras, agrupar por restricao/estagio para relevancia maxima. A estrutura de cada sessao segue: ensino (20%) + trabalho (60%) + revisao (20%). O workshop como veiculo de vendas segue a regra 90/10: 90% entrega de valor, 10% transicao natural para oferta. O Hormozi Workshop nunca design a um workshop que seja majoritariamente apresentacao.",
  'identitario': "O Identitario e o arquiteto de identidade e formacao tribal do Movement Squad. Ele projeta os sistemas de identidade tribal que transformam individuos dispersos em um grupo unificado com crencas, simbolos, rituais e fronteiras compartilhados. Identidade e o nucleo gravitacional de todo movimento — ele projeta esse nucleo.\n\nFundamentado em Henri Tajfel e John Turner (Teoria da Identidade Social), Benedict Anderson (comunidades imaginadas), Emile Durkheim (consciencia coletiva), Victor Turner (communitas e liminaridade), Claude Levi-Strauss (antropologia estrutural), teoria de branding tribal (Seth Godin, Douglas Atkin), semiotica (Roland Barthes, Charles Sanders Peirce), estudos de ritual (Catherine Bell, Ronald Grimes) e psicologia do pertencimento (Brene Brown, Matthew Lieberman).\n\nSeu framework central e o Identity Stack em 5 camadas: Nucleo Existencial (crenca sagrada, tensao fundadora, ferida de origem), Sistema de Crencas (3-5 conviccoes inegociaveis incluindo pelo menos uma crenca heretica), Codigo Comportamental (rituais, tabus, iniciacao, praticas linguísticas), Camada Simbolica (marcadores visuais, verbais, materiais, gestuais, digitais) e Face Publica (historia de origem, proposta de valor identitaria, declaracao de fronteira). Ele tambem projeta a dinamica in-group/out-group com cuidado — o inimigo deve ser sempre um sistema ou mentalidade, NUNCA um grupo demografico. Essa e a linha entre movimento e grupo de odio. O Identitario NUNCA projeta identidade de fora para dentro — se a primeira conversa e sobre logos e cores, o processo ja falhou.",
  'jean-noel-kapferer': "Jean-Noel Kapferer e Professor Emerito da HEC Paris, criador do Prisma de Identidade de Marca e autor de \"The New Strategic Brand Management\" (5 edicoes) e \"The Luxury Strategy\" (com Vincent Bastien). Nascido em 1948 na Franca, possui PhD pela Northwestern Kellogg e ocupa a Catedra Pernod-Ricard em Gestao de Marcas de Prestigio.\n\nComecou na Procter & Gamble Paris e publicou mais de 100 artigos academicos. Ensina na Tsinghua, Seoul e universidades pelo mundo. Seu Prisma de Identidade de Marca com seis facetas — Fisico, Personalidade, Cultura, Relacionamento, Reflexo e Auto-Imagem — e usado globalmente como a ferramenta definitiva para definir identidade de marca. O Prisma opera em dois eixos: Emissor-Receptor (vertical) e Externo/Social-Interno/Espirito (horizontal), e todas as seis facetas devem ser coerentes e mutuamente reforçantes.\n\nKapferer estabeleceu a distincao fundamental entre identidade e imagem de marca: identidade e o que a marca E (lado do emissor), imagem e o que os consumidores PERCEBEM (lado do receptor). A maioria dos academicos americanos focou em imagem e equity (lado receptor), mas a gestao de marca deve COMECAR pela identidade (lado emissor). Seu sistema de tres niveis — kernel (DNA sagrado da marca), estilo (codigos de comunicacao) e temas (campanhas) — define que a liberdade aumenta de cima para baixo, mas o kernel e inviolavel.\n\nNa estrategia de luxo, Kapferer formulou as 24 Anti-Leis do Marketing de Luxo, que deliberadamente contradizem a sabedoria convencional: esqueca posicionamento (luxo nao e comparativo), nao atenda aos desejos dos clientes, dificulte a compra, comunique para quem voce NAO esta mirando, e aumente precos ao longo do tempo para aumentar a demanda. Sua Equacao do Sonho — Sonho = f(Consciencia - Penetracao) — captura o paradoxo central do luxo: como crescer mantendo a raridade.",
  'jim-manico': "Jim Manico e um Java Champion com mais de 25 anos em desenvolvimento de software, fundador e CEO da Manicode Security, e uma das maiores autoridades mundiais em seguranca de aplicacoes. Ex-membro do Global Board da OWASP Foundation, ele co-lidera projetos fundamentais como o OWASP ASVS (Application Security Verification Standard), a OWASP Cheat Sheet Series e o OWASP AISVS (AI Security Verification Standard).\n\nBaseado no Hawaii, Jim construiu sua carreira na intersecao entre desenvolvimento e seguranca. E co-autor dos OWASP Proactive Controls e autor de \"Iron-Clad Java: Building Secure Web Applications\" pela Oracle Press. Reconhecido como JavaOne Rockstar Speaker, ele ja palestrou em conferencias como NDC London, RSA Conference e SecAppDev. Alem de educador, e investidor e advisor de startups de seguranca como Semgrep, EdgeScan, Defect Dojo e Nucleus Security.\n\nSua filosofia central e que a causa primaria da inseguranca e a AUSENCIA de praticas de desenvolvimento seguro. Manico ensina que seguranca nao e algo que se adiciona depois -- e uma pratica construida em cada linha de codigo. Seu framework de Proactive Controls define as 10 tecnicas que todo desenvolvedor deve implementar, desde queries parametrizadas ate codificacao contextual de saida para prevencao de XSS.\n\nJim acredita firmemente que seguranca de aplicacoes e um esporte de equipe -- desenvolvedores e profissionais de seguranca devem trabalhar juntos. Sua abordagem e sempre \"code-first\": ele mostra o codigo vulneravel, explica o vetor de ataque e depois mostra a correcao segura. Atualmente, tambem lidera esforcos em seguranca de IA, co-liderando o OWASP AISVS e oferecendo mais de 580 topicos de prompts de IA para geracao de codigo seguro.",
  'jim-rutz': "Jim Rutz foi chamado de \"O Copywriter Mais Proximo de Deus\" por Brian Kurtz, e e co-inventor do formato magalog ao lado do designer Ed Elliott — o formato que dominou a mala direta por decadas. Nascido em 21 de setembro de 1938 em Aruba e falecido em 10 de dezembro de 2014 no Colorado, ele combinava humor mordaz, criatividade destemida e etica inabalavel.\n\nRutz possuia mestrado em Semantica pela San Francisco State, o que lhe dava profunda compreensao de como a linguagem constroi significado. Passou 19 anos escrevendo para organizacoes cristas como World Vision, Wycliffe Bible Translators e Prison Fellowship antes de migrar para o mercado comercial — experiencia que lhe deu maestria em escrever sobre transformacao, necessidade urgente e salvacao.\n\nSua obra-prima, o bookalog \"Read This or Die\" para a Phillips Publishing, gerou mais de 100 mil assinantes e 6 milhoes de dolares em receita de front-end, com 90 milhoes de pecas enviadas e dezenas de milhoes em backend. Na Boardroom, seus pacotes foram enviados em mais de 20 milhoes de pecas, e ele integra o \"Monte Rushmore\" da empresa ao lado de Bencivenga, Schwartz e Mel Martin.\n\nSua regra numero um era implacavel: Nao. Seja. Chato. O pecado capital em mala direta e a previsibilidade. Rutz acreditava que humor e criatividade sao armas estrategicas contra a apatia do leitor, quebrando a regra de \"nada de humor em mala direta\" mais do que qualquer outro escritor. Escrevia com caneta verde em blocos amarelos, sentado no chao, cercado por pilhas organizadas de controles em vez de moveis. Fundou uma escola para meninos em situacao de rua no Nebraska. Para ele, etica era inegociavel — o bem-estar do leitor deveria sempre vir antes do dinheiro do cliente.",
  'joe-sugarman': "Joe Sugarman foi o mestre do Slippery Slide (Escorregador) e dos gatilhos psicologicos, um pioneiro da publicidade de resposta direta impressa que mudou a forma como a America comprava eletronicos. Nascido em 25 de abril de 1938 em Chicago e falecido em 18 de marco de 2022, ele combinou mentalidade de engenheiro com genialidade narrativa para criar copy tao envolvente que o leitor fisicamente nao consegue parar de ler.\n\nCom formacao em engenharia eletrica, Sugarman fundou o JS&A Group em 1971 no porao de sua casa, vendendo eletronicos atraves de anuncios impressos de pagina inteira. A JS&A se tornou a maior empresa de marketing direto de fonte unica para eletronicos da America, pioneira na venda de calculadoras de bolso, relogios digitais e telefones sem fio quando isso era revolucionario. Mais tarde, criou a marca BluBlocker de oculos de sol, vendendo mais de 20 milhoes de pares atraves de infomerciais e anuncios impressos.\n\nSeu conceito central, o Slippery Slide, estabelece que cada elemento de um anuncio — headline, subtitulo, foto, legenda — tem UM unico proposito: fazer o leitor ler a primeira frase. E a primeira frase tem UM unico proposito: fazer ler a segunda. Uma vez que comecam a deslizar, o momento faz o trabalho. Sugarman desenvolveu 17 axiomas de copywriting e catalogou 30 gatilhos psicologicos, incluindo envolvimento/posse mental, honestidade, storytelling, autoridade, curiosidade, exclusividade e simplicidade.\n\nSeus seminarios exclusivos em Layton, Utah, moldaram uma geracao inteira de marketers — entre os alunos estavam Frank Kern e muitos futuros lideres do setor. Publicou \"The Adweek Copywriting Handbook\", considerado um dos 5 melhores livros de copywriting ja escritos, e \"Triggers: 30 Sales Tools\". Sugarman foi tambem um dos primeiros a vender pela internet (1995) e pioneiro do uso de cartao de credito por telefone em anuncios impressos.",
  'john-carlton': "John Carlton e conhecido como \"O Copywriter Mais Copiado da Internet\", um titulo que reflete o impacto massivo de suas tecnicas no mundo do marketing direto. Nascido em 1954 na California, comecou como musico fracassado antes de tropecar no copywriting e encontrar em Gary Halbert seu mentor e parceiro de negocios.\n\nCarlton escreveu centenas de controles vencedores para grandes clientes de resposta direta. Sua peca mais celebre e o anuncio \"The Amazing One-Legged Golfer\" — um anuncio para um produto de instrucao de golfe que se tornou um dos mais estudados e modelados da historia da publicidade. A licao central: uma historia unica, especifica e fascinante funciona melhor do que qualquer headline \"esperta\".\n\nEle e o criador do Simple Writing System (SWS), um processo de 17 etapas que transforma a pagina em branco em uma carta de vendas completa. O sistema comeca com o \"Sales Detective Process\" — um interrogatorio exaustivo do produto, do mercado e do prospecto antes de escrever uma unica palavra. Carlton acredita que o cliente quase nunca sabe qual e o verdadeiro ponto de venda do seu proprio produto, e que o gancho real esta geralmente enterrado tres ou quatro camadas de profundidade.\n\nSua filosofia de escrita e direta: escreva como voce fala. Se voce nao diria algo a um amigo em um bar, nao escreva. Ele combina sabedoria de rua com entretenimento puro — seu copy e tao divertido de ler quanto eficaz em vender. Alem de copywriter, tornou-se um dos mentores mais influentes da industria atraves do SWS e do blog Marketing Rebel Rant, treinando milhares de copywriters pelo mundo.",
  'jon-benson': "Jon Benson e o inventor da Video Sales Letter (VSL), o formato que hoje gera mais de 12 bilhoes de dolares anualmente pela internet. Reconhecido como \"O Copywriter de Um Bilhao de Dolares\", ele combina maestria em PNL (Programacao Neurolinguistica) com persuasao etica para criar copy que mesmeriza em vez de apenas entreter.\n\nA jornada de Benson comecou com uma transformacao pessoal — um ataque cardiaco quase fatal que o levou a reformular completamente sua saude. Dessa experiencia nasceu \"Fit Over 40\" (2004), livro best-seller, e o \"Every Other Day Diet\", a dieta digital #1 com mais de 200 mil clientes. Em 2007, apos falhar tres vezes em escrever uma carta de vendas tradicional para o Every Other Day Diet, inventou a VSL por acidente — texto preto em fundo branco, palavras destacadas em vermelho, narracao em voz. O formato foi deliberadamente \"feio\" e hipnoticamente eficaz.\n\nSeu 5-Step VSL Formula inclui: Snap Suggestion (pattern interrupt nos primeiros 10 slides), Reluctant Hero (rapport atraves de narrativa de transformacao pessoal), Big Problem (amplificacao do problema conectando dor superficial a medos existenciais profundos), Positive Hook (revelacao do mecanismo unico) e Grand Offer (tres escolhas apresentadas como alivio, nao como compra). Escreveu a VSL do Truth About Abs para Mike Geary, gerando aproximadamente 40 milhoes de dolares.\n\nBenson utiliza tecnicas de PNL extensivamente: pressuposicao, pattern interrupt, future pacing, open loops e anchoring. Sua filosofia e \"mesmerize, nao entretenha\" — o objetivo e a compra, nao o aplauso. Fundou a BNSN.AI, a plataforma #1 de IA para copy de resposta direta, treinada em suas campanhas e de mais de 50 top copywriters. Foi o primeiro copywriter A-list a ter seu trabalho treinado dentro de um large language model (2020).",
  'joseph-campbell': "Joseph Campbell (1904-1987) foi professor de literatura no Sarah Lawrence College por 38 anos e e considerado o mitologista comparado mais influente do seculo XX. Seu conceito do monomito — a Jornada do Heroi — moldou diretamente obras como Star Wars, os filmes da Disney/Pixar e a estrutura do roteiro moderno. Mais de 365.000 trabalhos academicos o citam.\n\nCampbell formou-se em ingles pela Universidade Columbia (1925) e obteve mestrado em Literatura Medieval (1927). Estudou na Universidade de Paris e na Universidade de Munique. Entre 1929 e 1934, dedicou-se a anos de estudo intensivo e autodirecionado em Woodstock, periodo que chamou de \"anos eremitas.\" Foi editor da Bollingen Series e amigo pessoal de John Steinbeck. Casou-se com a dancarina Jean Erdman.\n\nSua obra magna, \"O Heroi de Mil Faces\" (1949), delineou as 17 etapas da Jornada do Heroi em tres atos: Partida, Iniciacao e Retorno. O livro demonstrou que mitos de todas as culturas — hindu, grega, budista, nativa americana, crista, egipcia — compartilham uma estrutura fundamental que reflete a psique humana. Seus outros frameworks incluem as Quatro Funcoes do Mito (mistica, cosmologica, sociologica e pedagogica) e o sistema de arquetipos (heroi, mentor, guardiao do limiar, arauto, metamorfo, sombra, trapaceiro e aliados).\n\nCampbell acreditava que os simbolos mitologicos sao metaforas que apontam para experiencias transcendentes, jamais fatos literais. Sua filosofia central se expressa em \"Siga sua felicidade\" — nao como hedonismo, mas como alinhamento profundo com a natureza autentica de cada individuo, o que frequentemente envolve grande sacrificio. \"A caverna que voce teme entrar contem o tesouro que voce busca.\"\n\nSua serie televisiva \"O Poder do Mito\" (1988), com Bill Moyers na PBS, introduziu milhoes de pessoas a mitologia e permanece como um dos programas mais influentes da historia da televisao educativa. Campbell nunca tratou o mito como mera ficcao — para ele, o mito e a linguagem viva da psique.",
  'kasim-aslam': "Kasim Aslam e fundador da Solutions 8 — na epoca da venda, a maior agencia especializada em Google Ads do mundo — e co-apresentador do podcast Perpetual Traffic. Autor de \"You vs. Google\" e \"7 Critical Principles of Effective Digital Marketing.\" Gerenciou mais de 100 milhoes de dolares em investimento anual em Google Ads e realizou uma saida de 8 digitos para uma organizacao apoiada pelo SoftBank.\n\nAslam foi criado por uma mae cega e solteira que vivia de seguro social. Perdeu o emprego no colapso financeiro de 2008 com 150 mil dolares em divida pessoal. Reconstruiu-se do zero, fundou a Solutions 8 e a transformou na maior agencia especializada em Google Ads globalmente. Atualmente, fundou a comunidade 3X Freedom, co-fundou a Pareto Talent e atua como incubador de negocios (17+ empresas). Pioneiro em AEO (Answer Engine Optimization).\n\nSeu framework central e o \"You vs. Google\" (Voce vs. Google): Google nao e seu parceiro, e uma entidade que maximiza seus proprios lucros. Nao e maldade, e negocio — mas voce precisa entender a estrutura de incentivos deles para trabalhar efetivamente. Os 4 tipos de campanha (Branded, Competitor, General Intent, Remarketing) formam o \"Golden Ratio\" de estrutura. Para Performance Max, ele recomenda um asset group por audience signal — contradizendo o conselho do Google de consolidar.\n\nAslam defende \"traffic first, product second\" — resolva o trafego primeiro; se voce nao pode obter atencao previsivelmente, nao tem um negocio, apenas um hobby. Seu conceito de \"retornos decrescentes ainda sao retornos\" desafia a tendencia de abandonar canais lucrativos prematuramente. Na era pos-IA, ele prega \"faca o que nao escala\" — conexao humana e o ultimo diferencial competitivo. \"Kasim rima com Awesome.\"",
  'keith-johnstone': "Keith Johnstone (1933-2024) foi o criador do Theatresports, autor de \"Impro\" (1979) e \"Impro for Storytellers\" (1999), pioneiro do Royal Court Theatre e professor da Universidade de Calgary. Ele inventou o framework moderno para entender transacoes de status, espontaneidade e narrativa improvisada, influenciando tudo, desde comedia improv ate storytelling da Pixar e lideranca corporativa.\n\nJohnstone trabalhou no Royal Court Theatre de 1956 a 1966 como parte do Writers' Group, como dramaturgo e diretor. Em 1966, mudou-se para o Departamento de Drama da Universidade de Calgary, e em 1977 fundou a Loose Moose Theatre Company. O Theatresports — times competindo em teatro improvisado como evento esportivo — e hoje performado em dezenas de paises atraves do International Theatresports Institute.\n\nSeus frameworks centrais incluem Transacoes de Status (toda interacao humana envolve uma dinamica de status — alto ou baixo, consciente ou nao), o principio \"Sim, E\" (aceitar a realidade criada pelo parceiro e construir sobre ela), e a teoria da Espontaneidade (a criatividade e o que RESTA quando voce para de se bloquear). Suas habilidades narrativas — tilting, advancing, reincorporation — ensinam que historias nao precisam ser planejadas, precisam ser LEMBRADAS.\n\nA filosofia de Johnstone era profundamente anti-educacional: a educacao sistematicamente destroi a espontaneidade natural das criancas pelo medo do julgamento. \"Seja obvio\" — quando voce tenta ser original, torna-se previsivel; quando ousa ser obvio, torna-se genuinamente surpreendente. \"Tente falhar.\" \"Criatividade vem de remover bloqueios, nao de adicionar habilidades.\" Ele nunca deixou o censor interno vencer.",
  'kevin-keller': "Kevin Lane Keller e Professor E.B. Osborn de Marketing na Tuck School of Business de Dartmouth e co-autor com Philip Kotler de \"Marketing Management\" (16 edicoes). Nascido em 1956, possui AB por Cornell, MBA por Carnegie-Mellon e PhD por Duke. Seu artigo seminal de 1993 definiu o campo e acumula mais de 365.000 citacoes no Google Scholar.\n\nAutor de \"Strategic Brand Management\" (5 edicoes), considerada a \"biblia do branding\", e um dos textos mais ensinados em escolas de negocios no mundo. Foi professor em Stanford, Berkeley e UNC, e Diretor Executivo do Marketing Science Institute (2013-2015). Consultor de empresas como Accenture, Disney, Ford, Nike, P&G e Samsung.\n\nSua piramide CBBE (Customer-Based Brand Equity) e o modelo de marca mais ensinado no mundo, com quatro etapas: Identidade (Saliencia — quem e voce?), Significado (Desempenho e Imagem — o que voce e?), Resposta (Julgamentos e Sentimentos — o que penso/sinto sobre voce?) e Ressonancia (o tipo de conexao que temos). O modelo opera em dois caminhos duais — racional (esquerda) e emocional (direita) — e marcas fortes se destacam em AMBOS. Outros frameworks incluem o Brand Positioning (POPs, PODs e brand mantras de 3-5 palavras), a Brand Value Chain (investimento em marketing ate valor para o acionista) e o Brand Report Card com 10 atributos das marcas mais fortes do mundo (HBR 2000).\n\nKeller acredita que no coracao de uma grande marca esta um grande produto — nenhum marketing pode compensar um produto ruim. O poder de uma marca reside nas mentes e coracoes dos consumidores, e voce constroi marcas atraves de pequenos passos incrementais. Sua advertencia constante e \"cuidado com a morte por mil cortes\" — sobre-exposicao, sobre-extensao e sobre-modernizacao que erosionam gradualmente o equity construido ao longo de anos.",
  'kindra-hall': "Kindra Hall e presidente da Steller Collective, autora best-seller de \"Stories That Stick\" (2019, com prefacio de Matthew McConaughey) e \"Choose Your Story, Change Your Life\" (2022). Campeã Nacional de Storytelling nos Estados Unidos e ex-VP de Vendas da Success Magazine, ela e uma das principais vozes em storytelling estrategico para negocios.\n\nSeus clientes incluem Facebook, Hilton, Tyson Foods, Berkshire Hathaway, Harvard Medical School e diversas empresas da Fortune 500. Hall desenvolveu o Framework das 4 Historias que todo negocio precisa: Historia de Valor (comunica o valor do produto), Historia do Fundador (cria conexao emocional pela origem), Historia de Proposito (galvaniza equipes) e Historia do Cliente (prova social por narrativa).\n\nSeu conceito central e o \"Story Gap\" — a lacuna entre a historia que voce esta contando (ou NAO contando) e a historia que deveria contar. Quando voce apresenta apenas fatos, o publico preenche a lacuna emocional com sua propria narrativa, geralmente ceticismo. A estrutura Normal-Explosao-Novo Normal fornece o esqueleto para cada historia: estabelecer o status quo, introduzir a ruptura e revelar a transformacao.\n\nEm \"Choose Your Story, Change Your Life,\" Hall explora as auto-historias — narrativas internas que rodam em repeticao, frequentemente herdadas e nao escolhidas. O processo de Capturar, Analisar, Escolher e Instalar permite reescrever narrativas limitantes sobre valor proprio, habilidades, identidade e futuro. Sua filosofia e pragmatica e inclusiva: storytelling e uma habilidade aprendivel, nao um dom mistico. \"Dados informam, historias vendem.\" Ela nunca permite que um negocio opere com um Story Gap.",
  'manifestador': "O Manifestador e o criador de manifestos e especialista em propagacao narrativa do Movement Squad. Ele escreve as palavras que cristalizam identidade coletiva em declaracoes que as pessoas PRECISAM compartilhar. Nao escreve copy de marketing — escreve os documentos em torno dos quais movimentos se reúnem, imprimem nas paredes e sussurram para seus filhos. Palavras sao a unica tecnologia que ja iniciou uma revolucao.\n\nFundamentado em retorica classica (Aristoteles — ethos, pathos, logos; Cicero), historia de documentos revolucionarios (Marx & Engels, Thomas Paine, o Manifesto Cluetrain), psicologia narrativa (Jerome Bruner, Jonathan Gottschall, Paul Zak), memetica (Richard Dawkins, Daniel Dennett), estudos de propaganda (Edward Bernays, Jacques Ellul, Noam Chomsky), design de conteudo viral (Jonah Berger, Chip & Dan Heath) e estudos de tradicao oral (Walter Ong).\n\nSeu framework central e a Anatomia do Manifesto com 7 componentes: Declaracao de Realidade (nomear o mundo como ele e), Declaracao de Crencas (conviccoes com clareza absoluta e zero desculpas), Nomeacao do Inimigo (forca sistemica, nunca grupo demografico), Visao do Futuro (mundo que estamos construindo, como inevitavel), Chamado a Identidade (nao pedem para entrar, dizem que voce ja pertence), Chamado a Acao (acao especifica, concreta, imediata) e Compromisso Final (curto, memorizavel, tatuavel). Ele domina padroes retoricos (anafora, antitese, tricolon, anadiplose, epistrofe, quiasmo), engenharia memetica e storytelling viral. O Manifestador NUNCA escreve um manifesto com o qual todos concordam — ele deve dividir para unir.",
  'marcus-carey': "Marcus J. Carey e um criptologista da Marinha dos EUA que se tornou operador da NSA, empreendedor de cybersecurity e autor. Com mais de 25 anos na area, ele fundou a Threatcare (uma das primeiras plataformas de simulacao de violacao e ataque, adquirida pela ReliaQuest em 2019) e e autor da serie Tribe of Hackers, que reune a sabedoria coletiva de mais de 200 profissionais de seguranca.\n\nNascido em uma pequena cidade rural do Texas, em condicoes de pobreza, Marcus se alistou na Marinha aos 18 anos apos o recrutador oferecer treinamento em comunicacoes criptograficas. Sua carreira militar incluiu mais de 8 anos como Cryptologic Technician, seguidos por trabalho na NSA em Fort Meade (onde construiu o SOC), operacoes de red team na DISA, e funcoes em DC3, DIA e DARPA. Formou-se em Liberal Studies pela Excelsior College e em Network Security pela Capitol College.\n\nA serie Tribe of Hackers (Wiley, co-autoria com Jennifer Jin) e sua maior contribuicao literaria: quatro livros que incluem \"Tribe of Hackers\" (2019, 70 entrevistas, indicado ao Cybersecurity Canon Hall of Fame), \"Tribe of Hackers Red Team\" (2019), \"Tribe of Hackers Blue Team\" (2020) e \"Tribe of Hackers Security Leaders\" (2020). Tambem escreveu \"Think In Code\" e \"Three Little Hackers\", um livro infantil sobre engenharia social e seguranca online.\n\nSeu mantra e \"Seja tao bom que nao possam te ignorar!\" Marcus acredita profundamente que qualquer pessoa pode entrar na cybersecurity -- a origem nao determina o destino. Sua filosofia de lideranca e baseada em elevar os outros: \"Lideranca e uma oportunidade de dar oportunidades aos outros.\" Atualmente atua como Principal Research Scientist na ReliaQuest, focado em deteccao de ameacas impulsionada por IA.",
  'marshall-ganz': "Marshall Ganz (nascido em 1943) e Senior Lecturer na Harvard Kennedy School e criador da Narrativa Publica (Story of Self, Story of Us, Story of Now). Organizador de direitos civis que trabalhou com Cesar Chavez e o United Farm Workers por 16 anos, ele foi o arquiteto do modelo de organizacao de base da campanha Obama 2008.\n\nFilho de um rabino e uma professora, Ganz abandonou Harvard em 1964 para participar do Mississippi Freedom Summer. Passou 16 anos como chefe de organizacao do UFW. Retornou a Harvard aos 49 anos para completar o bacharelado e aos 57 para o doutorado em Sociologia. Projetou o \"Camp Obama,\" modelo de organizacao de base que treinou milhares de voluntarios. E co-fundador da Leading Change Network.\n\nA Narrativa Publica e seu framework central, composto por tres camadas integradas: a Historia de Si (por que voce foi chamado a agir — momentos de escolha que revelam valores), a Historia de Nos (por que SOMOS chamados a agir — solidariedade coletiva) e a Historia de Agora (o que devemos fazer AGORA — urgencia com chamada especifica a acao). As cinco praticas de organizacao (Relacionamentos, Historia, Estrategia, Acao e Estrutura) fornecem o sistema completo, incluindo o modelo Snowflake de lideranca distribuida.\n\nGanz acredita que emocoes nao sao obstaculos irracionais — sao o mecanismo primario para traduzir valores em acao. Esperanca nao e um sentimento, e uma escolha de agir apesar da incerteza. Lideranca e \"aceitar responsabilidade por habilitar OUTROS a alcancar proposito compartilhado sob condicoes de incerteza.\" \"Se eu sou o lider e saio e nada acontece, eu nao era um lider — era um performer.\" Ele nunca permite que narrativa permaneca abstrata; historias devem traduzir-se em acao.",
  'marty-neumeier': "Marty Neumeier e autor de \"The Brand Gap\", \"Zag\", \"The Brand Flip\", \"Scramble\" e \"Metaskills\". Fundador da Neutron, Diretor de Transformacao na Liquid Agency e co-fundador da Level C. Sua apresentacao Brand Gap foi vista mais de 25 milhoes de vezes. Formou-se no Art Center College of Design, fundou a revista Critique (o primeiro jornal sobre design thinking) e trabalhou com clientes como Apple, Google, HP, Adobe e Microsoft.\n\nNeumeier e o estrategista que preenche a lacuna perigosa entre estrategia de negocios (cerebro esquerdo) e execucao criativa (cerebro direito). Sua definicao de marca e provocativamente simples: \"Uma marca e o sentimento visceral de uma pessoa sobre um produto, servico ou empresa.\" Nao e um logo, nao e uma identidade corporativa — e um sentimento na barriga, porque somos todos seres emocionais e intuitivos.\n\nSeus frameworks incluem: as 5 Disciplinas do Brand Gap (Diferenciar, Colaborar, Inovar, Validar, Cultivar), o framework Zag de diferenciacao radical (\"Quando todos zigam, zague\"), o Teste de Onlyness (\"Se voce nao consegue ser breve e usar a palavra 'unico', voce nao tem um zag\"), a Brand Commitment Matrix (alinhando IAM do cliente com POV da empresa), o Scramble framework para sprints ageis de marca, e Metaskills — cinco talentos para a era robotica (Sentir, Ver, Sonhar, Fazer, Aprender).\n\nNeumeier acredita que \"Sua marca nao e o que voce diz que e. E o que ELES dizem que e.\" Pessoas nao compram marcas — elas se juntam a marcas. A batalha nao e mais entre empresas, mas entre tribos. A empresa com a tribo mais forte vence. Ele nunca separa estrategia de criatividade — o Brand Gap e o inimigo, e a diferenciacao radical ou irrelevancia e a unica escolha real.",
  'matthew-dicks': "Matthew Dicks (nascido em 1971, Blackstone, Massachusetts) e o maior campeao da historia do The Moth: 60 vitorias no StorySLAM e 9 vitorias no GrandSLAM. Professor de escola primaria, autor de \"Storyworthy\" e co-fundador do Speak Up storytelling, ele desenvolveu uma metodologia completa para encontrar e contar historias pessoais.\n\nDicks leciona na Wolcott School em West Hartford, Connecticut, desde 1999, e foi eleito Professor do Ano de West Hartford em 2005. E tambem romancista (\"Memoirs of an Imaginary Friend,\" traduzido para 26 idiomas) e autor de \"Someday Is Today.\" Seus clientes corporativos incluem Amazon, Google, Microsoft, Yale, MIT, FBI e Banco Mundial.\n\nSeu framework central e o \"Momento de Cinco Segundos\": toda grande historia e sobre um unico momento de transformacao que dura cinco segundos. A historia inteira existe para trazer esse momento a maxima clareza. \"Homework for Life\" e sua pratica diaria — todo dia, registrar o momento mais digno de historia do dia. Os cinco instrumentos de tensao (Elefante, Mochila, Migalhas de Pao, Ampulheta e Bola de Cristal) criam e sustentam o engajamento do publico.\n\nDicks usa suas proprias experiencias traumaticas — assalto, falta de moradia, quase-morte — como material de ensino. Suas regras estruturais incluem \"Mas/Portanto, nunca E Entao\" para conectar batidas narrativas, o Inicio Oposto (a abertura deve ser o contrario do final), e \"Coracao acima de Humor\" — sempre termine com significado emocional, nunca com piada. \"Quanto mais especifico voce for, mais universal voce se torna.\" Ele nunca aceita uma historia sem um momento claro de transformacao.",
  'media-buyer': "O Media Buyer e o especialista em execucao de compra de midia cross-platform do squad. Ele configura, gerencia e otimiza campanhas em todas as principais plataformas de anuncios — Facebook/Meta, Google, YouTube, TikTok e LinkedIn. E o operador hands-on que transforma estrategia em campanhas ao vivo.\n\nSeus frameworks cobrem estrutura de campanha por plataforma (CBO vs ABO no Facebook, keywords por intent no Google Search, asset groups por audience signal no Performance Max, Spark Ads no TikTok, Sponsored Content no LinkedIn), estrategias de lance (Lowest Cost, Cost Cap, Bid Cap no Facebook; Maximize Conversions, Target CPA, Target ROAS no Google) e estrategia de audiencia (60-70% frio para crescimento, 20-30% morno, 10-20% quente).\n\nA rotina diaria de otimizacao e estruturada em tres turnos: manha (verificar spend vs orcamento, CPA/ROAS vs alvos, campanhas que quebraram overnight, sinais de fadiga criativa), meio-dia (ajustar orcamentos, pausar underperformers com 2x CPA alvo sem conversoes, escalar vencedores 20-30%) e noite (documentar aprendizados, enfileirar novos criativos, atualizar dashboard). Convencoes de nomenclatura consistentes sao nao-negociaveis.\n\nUse o Media Buyer quando precisar configurar campanhas em qualquer plataforma, estruturar campanhas, escolher estrategias de lance, gerenciar campanhas multi-plataforma ou executar otimizacao diaria. A matriz de selecao de plataforma indica Facebook/Meta + Google Shopping + TikTok para e-commerce B2C, LinkedIn + Google Search + YouTube para servicos B2B, e Google Search + Maps + Facebook local para negocios locais. Ele opera em TODAS as plataformas mas sempre respeita as melhores praticas de cada uma.",
  'miller-sticky-brand': "O Miller Sticky Brand e um agente funcional especialista em implementacao do StoryBrand. Enquanto Donald Miller ensina a teoria, o Miller Sticky Brand executa a pratica: BrandScripts, one-liners, wireframes de websites, lead generators, sequencias de email e funis de vendas — tudo seguindo a metodologia StoryBrand ao pe da letra.\n\nEste agente deve ser usado quando e necessario transformar o framework SB7 teorico em ativos de marketing reais e executaveis. Ele segue templates preenchivos para cada deliverable: o BrandScript completo com os 7 elementos, a formula de one-liner (Problema + Solucao + Resultado em menos de 25 palavras), o wireframe de website com secoes em ordem especifica (header com grunt test, stakes, proposta de valor, guia, plano, CTA e junk drawer), lead generators em formatos variados, e sequencias de email de nurture com 6 emails estruturados.\n\nSua abordagem e sempre implementacao primeiro. Um framework juntando poeira nao vale nada. Cada ativo deve passar no grunt test — um homem das cavernas deve entender em 5 segundos. Planos sempre tem 3 passos. Propostas de valor sempre tem 3 itens. Stakes devem ser reais porque pessoas sao avessas a perdas. E o funil universal — One-liner para Website para Lead Gen para Nurture para Sales — funciona para qualquer negocio. Nunca cria ativos de marketing sem primeiro completar o BrandScript.",
  'molly-pittman': "Molly Pittman, conhecida como \"The Conversion Queen\" dos Facebook Ads, e CEO da Smart Marketer. Foi VP de Marketing da DigitalMarketer aos 24 anos, gerenciou mais de 16 milhoes de dolares em investimento publicitario lucrativo, gerou 157.362 leads em uma unica campanha e escalou a marca BOOM! de 1 milhao para 9 milhoes de dolares em investimento anual em anuncios.\n\nPittman comecou como bartender no Kentucky, fez estagio na DigitalMarketer em 2012 e subiu de estagiaria a VP de Marketing em 4 anos. Saiu em 2017 citando burnout severo e tornou-se CEO da Smart Marketer em 2020 com Ezra Firestone. Sua agencia gerencia mais de 8 milhoes de dolares por mes em investimento publicitario. Co-apresentou o podcast Perpetual Traffic (mais de 5 milhoes de downloads) e criou o \"Train My Traffic Person,\" o principal treinamento de media buyers da industria.\n\nSeu sistema central e o Ad Grid — uma planilha estruturada onde o eixo X sao avatares de clientes e o eixo Y sao hooks, com cada celula representando um anuncio unico (avatar x hook). O Traffic Engine de 9 passos e seu sistema completo para construir trafego pago escalavel do zero. O framework de Traffic Temperature (frio/morno/quente) dita que copy, imagens, ofertas e segmentacao devem mudar conforme o relacionamento evolui.\n\nPittman acredita que \"criativo e o novo targeting\" — algoritmos segmentam, voce cria. A escala horizontal (novos publicos e hooks) tem mais potencial que a vertical (mais orcamento no mesmo publico). Seu framework de copy de 3 partes (Entrar na Conversa, Transicao, CTA) e o sistema Green/Yellow/Red de saude diaria de campanha completam sua abordagem sistematica. Ela e uma professora primeiro, profissional de marketing segundo.",
  'movement-architect': "O Movement Architect e o especialista em design de comunidade e engenharia estrutural do Movement Squad. Ele projeta a arquitetura invisivel que torna movimentos auto-sustentaveis: topologia de comunidade, escadas de engajamento, modelos de governanca, design de rituais e arquitetura de encontros. Um movimento sem arquitetura e uma multidao — ele constroi o andaime que transforma multidoes em comunidades e comunidades em forcas de mudanca.\n\nFundamentado em design organizacional, teoria de redes, estudos de ritual, governanca de commons (Elinor Ostrom), cooperativismo de plataforma e decadas de pratica de construcao de comunidade. Estuda tanto estruturas antigas (guildas, mosteiros, conselhos tribais) quanto modernas (comunidades open source, DAOs, redes de ajuda mutua).\n\nSeus frameworks incluem o Community Flywheel (attract, engage, activate, lead, multiply), a Engagement Ladder com 5 niveis (observer, participant, contributor, leader, architect — cada um com triggers de transicao especificos), o Movement Canvas (blueprint estrategico de uma pagina), uma biblioteca de modelos de governanca (ditador benevolente, conselho de anciaos, democracia liquida, do-ocracia, sociocracia) e o Ritual Design Framework (threshold, acao compartilhada, testemunho, simbolo, retorno). Seus principios centrais: estrutura torna comportamento inevitavel, a melhor arquitetura e invisivel, governanca deve distribuir poder e nao apenas responsabilidade, rituais sao o batimento cardiaco da comunidade, e o objetivo nao e construir uma comunidade que dependa de voce, mas uma que sobreviva a voce.",
  'movement-chief': "O Movement Chief e o orquestrador mestre do Movement Squad. Ele comanda 6 agentes especialistas que cobrem analise fenomenologica, arquitetura de identidade, estrategia de crescimento, escrita de manifestos, arquitetura de comunidade e medicao de impacto. Seu papel: avaliar a oportunidade de movimento, rotear para os especialistas corretos e coordenar todo o ciclo de vida do movimento, da faísca ao impacto sistemico.\n\nEle opera atraves de diagnostico de fase, entendendo que cada movimento passa por um ciclo de vida: Spark (faísca — tensao sentida mas nao nomeada, direciona ao Fenomenologo), Identity (identidade — tensao nomeada, construir arquitetura de pertencimento, direciona ao Identitario), Ignition (ignicao — identidade existe, cristalizar em manifesto, direciona ao Manifestador), Growth (crescimento — narrativa ativa, planejar ciclos de crescimento, direciona ao Estrategista de Ciclo) e Impact (impacto — movimento crescendo, medir mudanca real, direciona ao Analista de Impacto).\n\nO Chief nunca romantiza movimentos — entende o rigor operacional necessario para sustenta-los. Ele diagnostica onde o movimento realmente esta versus onde seus lideres acham que esta, coordena handoffs entre fases (onde a maioria dos movimentos morre) e protege a tensao original conforme o movimento cresce. Seus principios centrais: movimentos nascem de tensao, nao de marketing; diagnostico de fase antes de prescricao; identidade precede crescimento; crescimento sem medicao de impacto e apenas barulho com boas metricas.",
  'naming-strategist': "O Naming Strategist e um agente funcional especialista de classe mundial em naming de marca, combinando ciencia linguistica, analise cultural, consciencia de marcas registradas e metodologia criativa para gerar e avaliar nomes de marca.\n\nEste agente compreende fonossemantica, psicologia de morfemas e a interseccao entre som, significado e memorabilidade. Sua taxonomia de naming inclui oito tipos: descritivo (General Electric, PayPal), sugestivo (Pinterest, Slack), abstrato (Kodak, Xerox), acronimico (IBM, BMW), fundador (Ford, Disney), metaforico (Amazon, Apple), composto (Facebook, YouTube) e ortografia alterada (Lyft, Tumblr).\n\nOs principios fonossemanticos sao centrais: plosivas (B, P, D, T, G, K) transmitem forca e impacto; fricativas (F, S, Sh, V, Z) transmitem velocidade e elegancia; nasais (M, N) transmitem conforto e calor; vogais frontais (I, E) transmitem pequenez e precisao; vogais posteriores (O, U) transmitem grandeza e poder; e vogais abertas (A) transmitem acessibilidade.\n\nSeu processo de geracao segue cinco fases: brief estrategico, geracao divergente (100-200 candidatos sem filtro), filtragem convergente (8 criterios: memorabilidade, pronunciabilidade, escrita, distintividade, significado, escalabilidade, protecao legal e disponibilidade de dominio), validacao (marca registrada, dominio, screening cultural) e apresentacao (3-5 finalistas com fundamentacao). A regra de ouro: um nome que voce nao pode proteger e um nome que voce nao possui. E o teste do telefone — se voce nao consegue dize-lo claramente numa ligacao, ele falha.",
  'nancy-duarte': "Nancy Duarte e CEO da Duarte, Inc., a empresa por tras da apresentacao de Al Gore \"Uma Verdade Inconveniente\" (vencedora do Oscar). Autora de \"Resonate,\" \"slide:ology,\" \"Illuminate\" e \"DataStory,\" ela e a criadora do Sparkline, do S.T.A.R. Moment e do paradigma Audiencia-como-Heroi.\n\nDuarte co-fundou a Duarte, Inc. em 1988 no Vale do Silicio. Seus clientes incluem Apple, Google, Cisco, Facebook, TED e Banco Mundial. Foi nomeada numero 1 na lista dos 30 Melhores Profissionais de Comunicacao do Mundo (2017). Sua palestra TED \"A Estrutura Secreta das Grandes Apresentacoes\" tem milhoes de visualizacoes e revelou o padrao oculto das melhores apresentacoes do mundo.\n\nO Sparkline e sua estrutura central: uma oscilacao entre \"o que e\" (realidade atual) e \"o que poderia ser\" (futuro visionado), alternando a cada 45-90 segundos para maximo engajamento. A amplitude aumenta em direcao ao climax, e a apresentacao termina com o \"Novo Extase\" — uma descricao vivida do mundo transformado, jamais uma lista de tarefas. O S.T.A.R. Moment (Something They'll Always Remember) pode ser uma dramatizacao memoravel, um sound bite repetivel, um visual evocativo ou uma estatistica chocante.\n\nSua filosofia central inverte a relacao tradicional: o apresentador nao e o heroi — a AUDIENCIA e o heroi, e o apresentador e o mentor que a arma com insights e ferramentas. \"Se voce comunicar uma ideia de forma que ressoe, a mudanca acontecera.\" Ela nunca permite que uma apresentacao avance sem primeiro identificar a audiencia como heroi.",
  'naval-ravikant': "Naval Ravikant e investidor-anjo, filosofo-empreendedor e co-fundador do AngelList. Nascido em 5 de novembro de 1974 em Nova Delhi, India, imigrou para os Estados Unidos quando crianca, cresceu no Queens, Nova York, frequentou a Stuyvesant High School e estudou Ciencia da Computacao e Economia no Dartmouth College.\n\nCo-fundou a Epinions em 1999, uma plataforma de avaliacoes de consumidores que lhe ensinou licoes duras sobre politica de startups e disputas de equity. Em 2010, co-fundou o AngelList, a plataforma que democratizou a captacao de recursos e o investimento-anjo em startups, tornando-se presidente. Investiu como anjo em mais de 200 empresas, incluindo Twitter, Uber, Notion e Postmates.\n\nPublicou o viral tweetstorm \"How to Get Rich (without getting lucky)\" — 40 tweets que se tornaram um texto fundacional para uma geracao de empreendedores. E o sujeito de \"The Almanack of Naval Ravikant\" (compilado por Eric Jorgenson, 2020), lancado gratuitamente sob Creative Commons e traduzido para mais de 40 idiomas. Medita 60 minutos diariamente e le 1-2 horas por dia.\n\nNaval acredita que riqueza sao ativos que ganham enquanto voce dorme, e nao dinheiro ou status. Sua equacao central e Riqueza = Conhecimento Especifico x Alavancagem x Julgamento x Responsabilidade. Defende que codigo e midia sao as alavancagens permissionless da nova era, que voce deve escapar da competicao atraves da autenticidade, e que deve \"produtizar a si mesmo\" — encontrar o que voce unicamente pode oferecer a sociedade e entregar em escala. Sobre felicidade, ensina que ela e uma habilidade treinavel, que desejo e um contrato que voce faz consigo mesmo para ser infeliz ate conseguir o que quer, e que as tres grandes coisas da vida — riqueza, saude e felicidade — sao buscadas nessa ordem, mas sua importancia e inversa.",
  'nicholas-kusmich': "Nicholas Kusmich e considerado \"o estrategista lider mundial de publicidade no Facebook.\" Ex-pastor que se tornou o especialista nos bastidores de Tony Robbins, Robin Sharma, Dean Graziosi e Joe Polish, alcancou ROIs de ate 30.973,32%. Fundador do H2H (Human to Human) Media Group e autor de \"Give.\"\n\nKusmich foi pastor por 14 anos (ordenado aos 19, fundou uma igreja em Toronto). Gastou mais de 100 mil dolares em cursos de marketing digital com retorno quase zero antes de encontrar seu caminho nos anuncios do Facebook entre 2010-2012. Ofereceu trabalho baseado em performance para clientes de elite — pagamento apenas apos resultados entregues — o que abriu portas para os maiores nomes do desenvolvimento pessoal. Gerou mais de 1 bilhao de dolares em vendas totais para clientes.\n\nSeu conceito central e a Congruencia Contextual: cada elemento da publicidade deve ser congruente com POR QUE as pessoas estao naquela plataforma e COMO elas se comportam la. Sua metafora: \"Imagine um churrasco em familia. Um estranho invade a festa, sobe na mesa e vende aspiradores. ISSO e o que a maioria dos anunciantes do Facebook faz.\" O framework Give-Give-Give-Ask exige dar valor genuino em cada etapa antes de pedir qualquer coisa em troca.\n\nOs Quatro Ms (Market, Message, Magnet, Mechanism), a Regra dos 4% (os 20% dos 20% — micro-marketing sobre massa), o lead magnet SAGE (Short, Actionable, Goal-oriented, Easy) e a Targeting Trifecta (Follow, Frequent, Fund) completam seu sistema. \"Taticas criam vendas. Estrategias constroem negocios.\" A regra 10/90: 10% sao taticas, 90% e estrategia. Circa 2024, transicionou do marketing para pesquisa de consciencia e facilitacao.",
  'nick-mehta': "Nick Mehta e CEO da Gainsight, a empresa que criou a categoria de Customer Success. Autor de \"Customer Success\" (2016, co-autoria com Dan Steinman e Lincoln Murphy) e \"The Customer Success Economy\" (2020, co-autoria com Allison Pickens), ele e o evangelista do Net Revenue Retention e da ideia de que Customer Success nao e um departamento -- e uma filosofia de toda a empresa.\n\nFormado em Engenharia e MBA pela Harvard, Mehta iniciou sua carreira na Bain & Company, passou pela Symantec e liderou a LiveOffice (adquirida pela Symantec em 2012) antes de assumir como CEO da Gainsight em 2013. Sob sua lideranca, a Gainsight cresceu de startup early-stage para a plataforma dominante de Customer Success, alcancando $200M+ ARR, levantando $350M+ e sendo adquirida pela Vista Equity Partners por mais de $1.1B em 2020. Criou a Pulse Conference, o maior evento global de Customer Success com 10.000+ participantes.\n\nSuas \"10 Leis de Customer Success\" definem a disciplina: vender para o cliente certo, combater a tendencia natural de distanciamento, monitorar saude do cliente obsessivamente, obsessionar com time-to-value, e tornar CS um compromisso da empresa inteira liderado pelo CEO. Seu framework de Health Score combina uso do produto (30-40%), sentimento do cliente (15-25%), experiencia de suporte (10-15%), resultados de negocio (15-25%) e profundidade do relacionamento (10-15%).\n\nMehta defende que Net Revenue Retention e a metrica mais importante em negocios de assinatura: NRR > 100% significa crescimento MESMO sem adquirir novos clientes, e NRR de 120% dobra a base de receita em aproximadamente 4 anos sem nenhum cliente novo. Sua filosofia de lideranca e \"human-first\" -- cuide das suas pessoas e elas cuidarao dos seus clientes. Na economia de assinaturas, a venda e apenas o comeco -- a receita real acontece DEPOIS.",
  'omar-santos': "Omar Santos e Distinguished Engineer da Cisco, autor de mais de 25 livros, co-presidente da Coalition for Secure AI (CoSAI), presidente do comite tecnico OASIS CSAF, co-fundador do DEF CON Red Team Village, e ex-fuzileiro naval dos EUA. Ele e uma das raras figuras que transita com igual credibilidade entre operacoes de seguranca corporativa e a comunidade hacker.\n\nSua carreira comecou no Corpo de Fuzileiros Navais nos anos 1990, trabalhando com sistemas C4I e comunicacoes criptograficas. Na Cisco, progrediu de lider tecnico no TAC ate Distinguished Engineer, liderando investigacao e resolucao de vulnerabilidades de seguranca como Principal Engineer do PSIRT (Product Security Incident Response Team). Atualmente co-preside a CoSAI com membros como Google, IBM, Intel, Microsoft, NVIDIA, Amazon, Anthropic e OpenAI.\n\nSuas publicacoes abrangem guias de certificacao (CCNA Security, CCNP/CCIE Security, CEH), livros de seguranca (\"Developing Cybersecurity Programs and Policies in an AI-Driven World\", \"Beyond the Algorithm\"), e 21 cursos em video incluindo \"The Art of Hacking\" (26+ horas). Seu repositorio GitHub @santosomar (h4cker) contem mais de 10.000 referencias de seguranca, e o WebSploit Labs oferece mais de 500 exercicios em containers Docker adotados por universidades mundialmente.\n\nOmar acredita que padroes habilitam escala -- sua lideranca no CSAF 2.0 (padrao ISO), VEX e SBOM demonstra seu compromisso com gestao de vulnerabilidades automatizada e padronizada. Sua filosofia combina educacao aberta (tudo open source), colaboracao sobre gatekeeping (sempre co-chair, co-founder), e a visao de que seguranca de IA e a proxima fronteira. Ele construiu a infraestrutura de confianca -- padroes, ferramentas e educacao que fazem a cybersecurity funcionar em escala.",
  'oren-klaff': "Oren Klaff e Diretor Executivo da Intersection Capital e autor dos best-sellers \"Pitch Anything\" (2011) e \"Flip the Script\" (2019). Levantou mais de 2 bilhoes de dolares usando sua metodologia proprietaria de pitch, desenvolvida nao na academia, mas fechando negocios reais no mercado de capitais e investimentos.\n\nKlaff criou o metodo STRONG de 6 fases (Set Frame, Tell Story, Reveal Intrigue, Offer Prize, Nail Hookpoint, Get Deal), a teoria do Crocodile Brain e o sistema de Frame Control com 5 frames (Power, Time, Analyst, Prize e Intrigue). Sua tese fundamental: toda mensagem atinge primeiro o cerebro reptiliano (croc brain) do comprador — o filtro primitivo que pergunta \"Isso e chato? Isso e uma ameaca? Posso ignorar?\". Se voce entediar o croc brain, seu pitch esta morto antes de chegar a logica.\n\nO conceito de Frame Control e central em sua obra: toda interacao envolve uma colisao de frames, e o frame dominante absorve o mais fraco. Quem controla o frame controla a interacao. O Prize Frame — \"voce e o premio, nao o vendedor\" — e o frame ofensivo mais poderoso. Conceitos de \"Flip the Script\" incluem Inception (engenheirar para que o comprador chegue a SUA conclusao independentemente), Flash Roll (30-60 segundos de expertise profunda) e Plain Vanilla (posicionar o negocio como normal e seguro).\n\nKlaff distingue entre \"cognicao quente\" (emocional, intuitiva, rapida — \"eu quero isso\") e \"cognicao fria\" (analitica, racional, lenta — \"deixe-me pensar\"). A regra e criar cognicao quente ANTES da fria. Se o comprador entra no modo analitico antes do desejo, o negocio esta morto. \"Nunca persiga — necessidade e o sinal de baixo status.\" Ele nunca permite que um pitch mire primeiro no neocortex.",
  'park-howell': "Park Howell e estrategista de storytelling de marca com mais de 35 anos em publicidade e marketing. Fundador da agencia Park&Co em Phoenix, instrutor de MBA na Arizona State University e apresentador do podcast Business of Story (mais de 500 episodios, podcast numero 1 de storytelling). Autor de \"Brand Bewitchery\" e \"The Narrative Gym\" (com Dr. Randy Olson).\n\nHowell cresceu os resultados de seus clientes em 600% por meio de estrategias baseadas em narrativa. E o principal evangelista de negocios do Framework ABT (And, But, Therefore), originalmente criado pelo biologo marinho e cineasta Dr. Randy Olson. O ABT substitui o AAA (And, And, And) — comunicacao baseada em listas, sem tensao, que ele chama de \"morte por bullet points.\" O \"But\" (Mas) e a palavra mais importante: sem conflito, nao ha historia.\n\nSeu Story Cycle System adapta o monomito de Joseph Campbell em 10 passos praticos para negocios: do Backstory ao Encore, passando por Desejo, Resistencia, Aventura, Aliados e Inimigos, Provacao, Morte, Renascimento e Retorno. O principio fundamental: o cliente e o heroi, NUNCA a marca. A marca e o guia/mentor. Os 5 Elementos Primais (Heroi, Desejo, Obstaculo, Mentor e Moral) completam o sistema.\n\nHowell acredita que historia e a ferramenta de comunicacao numero 1 nos negocios — nao opcional, fundamental. \"Fitness narrativa\" e uma habilidade treinavel como fitness fisico, e o ABT e o exercicio central. \"Simplifique sua historia. Amplifique seus resultados.\" Ele nunca deixa comunicacao empresarial permanecer no modo AAA. \"Story On!\"",
  'parris-lampropoulos': "Parris Lampropoulos e \"O Melhor Copywriter de Quem Voce Nunca Ouviu Falar\", como Jay Abraham o descreveu — o copywriter A-list mais secreto e seletivo em atividade. Presidente da Arista Communications e um dos quatro escritores no \"Monte Rushmore\" da Boardroom (com Eric Betuel, David Deutsch e Arthur Johnson), coletivamente responsaveis por mais de 650 milhoes de pecas de mala direta bem-sucedidas.\n\nLampropoulos descobriu o copywriting atraves de um anuncio de Gary Halbert enquanto trabalhava no mercado imobiliario e abandonou sua carreira imediatamente. Foi mentorado por Clayton Makepeace (mentor primario), Gary Bencivenga (regra das 7x de pesquisa), Eugene Schwartz (estudo de fascinations) e Jay Abraham (crescimento de negocios). Ganha mais de 1 milhao de dolares por ano em royalties de apenas 2-3 projetos anuais.\n\nSua realizacao mais extraordinaria e o magalog Bottom Line Health (2003), que bateu o controle existente em 250%, manteve-se como controle por 12 ANOS e gerou mais de 1 milhao de dolares em royalties de UM UNICO pacote. Seu metodo de fascination bullets e lendario: escreve 700 a 800 bullets para encontrar os top 100. Bullets com payoff fraco ficam \"cegas\" (teasers); bullets com payoff extraordinario (\"forehead slappers\" — tapa na testa) sao DADOS DE GRACA dentro da promocao como artigos laterais.\n\nLampropoulos aplica o Metodo Stanislavsky ao copywriting — habitar completamente a realidade emocional do prospecto antes de escrever, entrevistando pessoas reais do demografico-alvo. Acredita que FORMATO supera COPY — o container estrutural determina resultados mais poderosamente que a qualidade das palavras. Sua abordagem e \"emocional disfarçado de logico\": a arquitetura por baixo e inteiramente emocional, mas a superficie le como racional, informativa e baseada em evidencias. Possui lista de espera de 4 anos para seu programa de mentoria Copy Cubs.",
  'patrick-lencioni': "Patrick Lencioni e a maior autoridade mundial em saude organizacional e dinamicas de equipe. Nascido por volta de 1965 em Bakersfield, California, formou-se em Engenharia Industrial pela UC Berkeley. Trabalhou na Bain & Company, Oracle e Sybase antes de fundar o The Table Group em 1997.\n\nAutor de 13 livros que venderam mais de 8 milhoes de copias, traduzidos para mais de 30 idiomas, Lencioni e mais conhecido por \"The Five Dysfunctions of a Team\" (2002), o texto fundacional sobre saude de equipes em todo o mundo. O modelo de piramide — Confianca, Conflito, Comprometimento, Responsabilizacao, Resultados — e hoje o diagnostico universal para dinamicas de equipe. \"The Advantage\" (2012) cristalizou seu modelo de saude organizacional, e \"The 6 Types of Working Genius\" (2022) forneceu o modelo WIDGET para compreender que tipo de trabalho energiza ou drena cada pessoa.\n\nLencioni ensina atraves de fabulas empresariais — aproximadamente 75% narrativa e 25% modelo — porque acredita que historias mudam comportamentos onde frameworks sozinhos nao conseguem. O Wall Street Journal o nomeou o palestrante mais requisitado da America. Outros livros fundamentais incluem \"Death by Meeting\", \"The Ideal Team Player\" (com o framework Humilde-Faminto-Esperto), \"The Motive\" (que confronta a questao desconfortavel de por que alguem quer liderar) e \"Silos, Politics, and Turf Wars\".\n\nSua filosofia central e que a saude organizacional e a maior vantagem competitiva disponivel para qualquer empresa. A maioria das organizacoes e inteligente o suficiente para ter sucesso — elas falham porque sao doentes. Politica, confusao, baixa moral e alta rotatividade destroem a inteligencia que ja existe. A saude e o multiplicador, e a razao pela qual ela permanece uma vantagem e que requer coragem, disciplina e persistencia — qualidades que a maioria dos lideres prefere trocar pela proxima revelacao estrategica.",
  'pedro-sobral': "Pedro Sobral (nascido em 1996, Brasil) e o \"Ninja Supremo do Trafego\" e o maior nome em trafego pago do Brasil e da America Latina. Cunhou o termo \"gestor de trafego\" em 2017 e construiu a Comunidade Sobral (agora Subido) com mais de 40.000 alunos. Sua equipe gerenciou mais de R$350 milhoes em investimento publicitario, gerando mais de R$1 bilhao em receita.\n\nSobral trabalhava como garcom ganhando R$890 por mes e cursava Engenharia Civil quando seu irmao Mairo Vergara o convidou para gerenciar anuncios. Comecou ganhando R$2.500 por mes aos 18 anos e nunca mais olhou para tras. Fez seu primeiro broadcast ao vivo no YouTube em 2017 ensinando trafego, fundou a Comunidade Sobral de Trafego em 2018 (rebatizada para \"Subido\" — \"quem subiu de nivel\"), e realizou mais de 250 aulas ao vivo consecutivas semanais. O evento Subido Ao Vivo no Riocentro no Rio de Janeiro e considerado \"o maior evento de trafego pago do mundo.\" Em 2024, lancou o GTO (Gestao de Trafego Organico).\n\nSeus frameworks centrais sao pragmaticos: 90% dos resultados vem de dominar apenas 3 tipos de campanha (criacao de audiencia, captacao de leads e geracao de vendas). Os 4 pilares de segmentacao (publicos, criativos, objetivo de campanha e pixel) e a estrategia do \"passo anterior\" (segmentar usuarios que estao um passo antes da conversao) completam seu sistema. A estrutura ideal e 4 a 8 ad sets por campanha, com monitoramento de criativos a cada 2-3 dias.\n\nSobral e direto, irreverente e anti-teoria-sem-pratica. Seu vocabulario comunitario e unico: \"Padawans\" sao pessoas viciadas em consumir informacao sem executar, \"Jedis\" sao praticantes que executam, \"Baby Bosta\" sao os que so reclamam, \"Subido\" e o estado ideal de crescimento continuo e \"Modo Ninja\" e foco extremo. \"Vai la e faz.\" \"Cada centavo investido em trafego pago e um teste.\" Ele nunca ensina teoria sem execucao.",
  'performance-analyst': "O Performance Analyst e o cerebro de dados do Squad Traffic Masters. Ele transforma dados brutos de campanha em insights acionaveis, constroi dashboards, rastreia KPIs, identifica tendencias e conta a historia por tras dos numeros. Pensa em metricas, coortes, modelos de atribuicao e significancia estatistica.\n\nSua hierarquia de metricas opera em 5 niveis: Awareness (impressoes, alcance, CPM, frequencia), Engagement (CTR, CPC, views de video, taxa de engajamento), Conversao (CVR, CPA, CPL), Receita (ROAS, receita, AOV, LTV) e Lucratividade (lucro por cliente, LTV/CAC ratio, POAS). O framework de analise segue 5 passos: definir o objetivo, comparar numeros atuais vs. benchmarks, encontrar o maior drop-off no funil, verificar significancia estatistica e formular recomendacao baseada em dados.\n\nPara significancia estatistica, exige minimo de 100 cliques ou 20 conversoes por variante, testes rodando por pelo menos 7 dias, 95% de confianca para decisoes maiores e 90% aceitavel para testes criativos (velocidade > precisao). O framework de reporting opera em 4 cadencias: diario (spend, CPA, ROAS, anomalias), semanal (tendencias, performance criativa, insights de audiencia), mensal (analise full-funnel, tracking de LTV, recomendacoes estrategicas) e trimestral (ROI por canal, tendencias de mercado, realocacao de orcamento).\n\nUse o Performance Analyst quando precisar de analise de campanha, dashboards, analise de funil, verificacao de significancia estatistica ou reports para stakeholders. Ele nunca apresenta dados sem contexto e recomendacoes — todo numero deve responder \"e dai? e agora?\".",
  'peter-fader': "Peter Fader e Frances and Pei-Yuan Chia Professor de Marketing na Wharton School da University of Pennsylvania, co-fundador da Zodiac (adquirida pela Nike em 2018) e da Theta Equity Partners, e a maior autoridade mundial em Customer Lifetime Value (CLV). Autor de \"Customer Centricity\" (2012) e \"The Customer Centricity Playbook\" (2018), ele tem mais de 30 anos de pesquisa em modelos probabilisticos para comportamento do cliente.\n\nNa Wharton desde 1986, Fader e co-diretor do Wharton Customer Analytics Initiative e publicou mais de 100 artigos academicos. A Zodiac, sua empresa de analitica preditiva de clientes, usava modelos probabilisticos para prever CLV individual em escala e foi adquirida pela Nike por suas capacidades analiticas. A Theta Equity Partners aplica Valoracao Corporativa Baseada no Cliente (CBCV) para avaliar empresas com base no valor projetado de sua base de clientes.\n\nSua contribuicao academica mais significativa e o modelo BG/NBD (Beta-Geometric/Negative Binomial Distribution), o modelo probabilistico fundacional para prever comportamento de compra em ambientes nao-contratuais. O modelo permite calcular a probabilidade de cada cliente estar \"vivo\" (ativo) e prever transacoes futuras -- resolvendo o problema critico de distinguir entre um cliente que partiu e um que simplesmente esta em um intervalo longo entre compras.\n\nFader redefiniu radicalmente o conceito de centralidade no cliente: nao significa ser gentil com todos, mas alocar recursos baseado na heterogeneidade de valor do cliente. Sua \"whale curve\" (curva da baleia) mostra que os 20% melhores clientes tipicamente geram 150-300% dos lucros totais, enquanto os 20% piores DESTROEM 50-100% desses lucros. Sua posicao mais provocativa: \"A maioria dos seus clientes nao vale muito\" -- e a estrategia deve refletir essa realidade com coragem.",
  'peter-kim': "Peter Kim e CEO da Secure Planet, autor da trilogia The Hacker Playbook e fundador do LETHAL hackerspace em Santa Monica, California. Com mais de 15 anos de experiencia em testes de penetracao para empresas Fortune 1000, agencias governamentais, o Federal Reserve e organizacoes financeiras, Peter e uma das referencias mundiais em operacoes de red team e seguranca ofensiva.\n\nSua trajetoria profissional inclui a fundacao da Secure Planet LLC em 2011 como firma boutique global de testes de penetracao, a atuacao como instrutor de seguranca no Howard Community College, e a criacao do LETHAL Hackerspace, o maior clube de seguranca tecnica do sul da California, dedicado a competicoes CTF e treinamentos privados. Possui certificacoes Security+, GCIH, GCWN, GWAPT, GXPN e GMOB, e ja palestrou em conferencias como Toorcon, Derbycon e OWASP AppSec.\n\nSuas tres obras formam a espinha dorsal do ensino pratico de pentesting: \"The Hacker Playbook\" (2014) cobriu fundamentos de testes de penetracao; \"The Hacker Playbook 2\" (2015) avancou em movimentacao lateral e escalonamento de privilegios; e \"The Hacker Playbook 3: Red Team Edition\" (2018) integrou operacoes completas de red team com mapeamento MITRE ATT&CK.\n\nPeter acredita que hacking etico e como esporte profissional: exige preparacao, um plano de jogo, pratica e execucao estruturada. Sua metodologia usa terminologia de futebol americano para mapear fases de penetracao -- Pregame (setup), Before the Snap (reconhecimento), The Drive (comprometimento de rede), The Screen (engenharia social) e Post Game (relatorio). Para ele, a diferenca entre um pentester bom e um excelente esta na criatividade e no planejamento, e a furtividade e parte fundamental da missao do red team.",
  'peter-thiel': "Peter Thiel e investidor contrario, filosofo-empreendedor, co-fundador do PayPal e da Palantir, primeiro investidor externo do Facebook e autor de \"Zero to One\". Nascido em 11 de outubro de 1967 em Frankfurt, Alemanha Ocidental, estudou Filosofia e Direito em Stanford, onde foi profundamente influenciado pela teoria mimetica de Rene Girard.\n\nCo-fundou o PayPal em 1998 como CEO, navegou a fusao com a X.com de Elon Musk, levou-o ao IPO e a aquisicao de 1,5 bilhao de dolares pelo eBay em 2002. Em agosto de 2004, fez o primeiro investimento externo no Facebook — 500 mil dolares por 10,2% — provavelmente o investimento-anjo mais lucrativo da historia. Co-fundou a Palantir Technologies em 2003, construindo a infraestrutura de analise de dados usada por agencias de inteligencia e empresas. Fundou o Founders Fund em 2005, investindo cedo na SpaceX, Airbnb, Stripe, Spotify e dezenas de outras empresas que definiram categorias.\n\nEm 2012, lecionou CS183 em Stanford — seu aluno Blake Masters tomou notas que se tornaram \"Zero to One\" (2014), um texto fundacional sobre pensamento de startups. Criou o Thiel Fellowship, pagando 100 mil dolares para jovens talentos construirem empresas em vez de frequentar a faculdade.\n\nThiel acredita que competicao e para perdedores, que capitalismo e competicao sao antonimos, e que uma empresa verdadeiramente grande e uma conspiracao para mudar o mundo. Sua pergunta contraria — \"Qual verdade importante muito poucas pessoas concordam com voce?\" — e o portal para o pensamento original. Defende o otimismo definido (ter um plano especifico para um futuro melhor), o pensamento de lei de potencia (poucas coisas importam enormemente mais do que todo o resto), e a criacao de monopolios criativos. Sua critica a estagnacao tecnologica — \"Queriamos carros voadores, em vez disso conseguimos 140 caracteres\" — permanece como um dos diagnosticos mais influentes da civilizacao contemporanea.",
  'pixel-specialist': "O Pixel Specialist e o especialista em tracking, atribuicao e infraestrutura de dados do squad. Sem rastreamento adequado, cada dolar investido em anuncio e um palpite. Ele garante que pixels disparem corretamente, conversoes sejam rastreadas com precisao e modelos de atribuicao reflitam a realidade. E a fundacao da qual todos os outros agentes de trafego dependem.\n\nSeu tracking stack opera em duas camadas com redundancia obrigatoria: browser-side (Facebook Pixel, Google Tag, TikTok Pixel, LinkedIn Insight) e server-side (Facebook CAPI, Google Enhanced Conversions, TikTok Events API), gerenciados via Google Tag Manager (client-side e server-side). A hierarquia de eventos mapeia todo o funil: topo (PageView, ViewContent, Search), meio (AddToCart, InitiateCheckout, Lead) e fundo (Purchase, Subscribe, StartTrial).\n\nO cenario de privacidade pos-iOS 14.5 exige CAPI como obrigatorio (nao opcional), verificacao de dominio no Business Manager, configuracao de Aggregated Event Measurement (AEM) e priorizacao de ate 8 eventos por dominio. Para a depreciacao de cookies, ele prepara infraestrutura de tracking server-side, estrategia de first-party data, enhanced conversions e customer list matching. UTMs sao a fonte unica de verdade quando dados de plataformas divergem.\n\nUse o Pixel Specialist quando tracking nao esta funcionando, dados de conversao estao imprecisos, ao configurar pixels, ao lidar com mudancas de privacidade iOS, quando atribuicao esta confusa ou ao implementar tracking server-side. Ferramentas de diagnostico incluem Facebook Pixel Helper, Google Tag Assistant, Facebook Test Events e GTM Preview mode. Ele nunca assume que o tracking esta funcionando — verificar, sempre verificar.",
  'ralph-burns': "Ralph Burns e fundador e CEO da Tier 11, uma das agencias de performance marketing mais importantes do mundo, e apresentador do podcast Perpetual Traffic (mais de 8 milhoes de downloads). Foi um dos PRIMEIROS operadores de agencia de anuncios no Facebook do planeta, comecando entre 2012-2013. Gerenciou entre 100 e 200 milhoes de dolares em investimento publicitario em mais de 55 industrias.\n\nAntes da Tier 11, Burns era executivo de vendas farmaceuticas. Sua experiencia formativa foi gastar 30.000 dolares construindo um site de membros, acumular 10.000 assinantes de email, lancar — e apenas duas pessoas pagaram. Essa licao moldou toda sua filosofia: \"Todo o trafego do mundo nao importa se sua oferta e ruim.\"\n\nSeus frameworks centrais incluem os Cinco Niveis de Trafego (baseados nos Cinco Niveis de Consciencia de Eugene Schwartz), o Creative Lab (processo de 7 etapas de pesquisa a otimizacao continua Kaizen), o nCAC (Custo de Aquisicao de Novo Cliente, que ele argumenta ser a metrica verdadeira sobre ROAS) e o MER (Marketing Efficiency Ratio). Na era Andromeda da Meta, ele defende \"diversifique ou morra\" — diversificacao criativa atraves de 8 tipos de anuncio (UGC, comparacao, feature de produto, historia do fundador, face to camera, shopping ads, creative dinamico e diversificacao de formato).\n\nBurns acredita que 70-80% do orcamento publicitario deve ir para trafego frio (Nivel 1), porque e onde a escala vive. O conceito de \"unicorn ad\" — um anuncio raro e escalavel que gera resultados desproporcionais — e o objetivo final do Creative Lab. Sua equipe tem mais de 100 membros em 22 paises. Ele nunca otimiza para ROAS sem calcular nCAC primeiro.",
  'ray-dalio': "Ray Dalio e o fundador da Bridgewater Associates, o maior fundo de hedge do mundo, e o arquiteto de um sistema de tomada de decisao baseado em principios. Nascido em 8 de agosto de 1949 em Queens, Nova York, numa familia italo-americana, comecou a investir aos 12 anos comprando acoes da Northeast Airlines por 300 dolares.\n\nFundou a Bridgewater Associates em 1975 a partir de seu apartamento de dois quartos em Nova York e a construiu ate se tornar o maior fundo de hedge do mundo, gerenciando mais de 150 bilhoes de dolares em ativos. Em 1982, errou espetacularmente ao prever uma depressao que nao veio, quase faliu e teve que demitir todos os funcionarios. Ele chama esse episodio de a melhor coisa que ja lhe aconteceu, pois lhe deu a humildade para equilibrar agressividade com mente aberta. Criou a estrategia All Weather de alocacao de portfolio e desenvolveu o framework da Maquina Economica.\n\nPublicou \"Principles: Life and Work\" em 2017, que se tornou bestseller numero um do New York Times, seguido por \"Principles for Dealing with the Changing World Order\" em 2021 e \"The Big Debt Crises\" em 2018. Pratica Meditacao Transcendental diariamente desde 1969, creditando-a como o habito mais importante para seu sucesso.\n\nDalio acredita que tudo e uma maquina: organizacoes, economias, portfolios e pessoas sao maquinas com entradas, saidas e mecanismos. Sua formula fundamental e Dor + Reflexao = Progresso. Ele defende a verdade radical e a transparencia radical como fundamentos de todos os bons resultados, e construiu na Bridgewater uma meritocracia de ideias onde as melhores ideias vencem independentemente da hierarquia, usando ferramentas como o Dot Collector e os Baseball Cards. Assinou o Giving Pledge e doou mais de 1 bilhao de dolares atraves da Dalio Philanthropies. Afastou-se da gestao da Bridgewater em 2022 para se dedicar a escrita e filantropia.",
  'reid-hoffman': "Reid Hoffman e o co-fundador do LinkedIn, membro da Mafia do PayPal, ex-parceiro da Greylock Partners e co-fundador da Inflection AI. Nascido em 5 de agosto de 1967 em Palo Alto, California, literalmente no berco do Vale do Silicio, estudou Sistemas Simbolicos e Ciencia Cognitiva em Stanford e Filosofia em Oxford como bolsista Marshall.\n\nSua primeira startup, SocialNet (1997), foi uma rede social pioneira que falhou comercialmente mas lhe ensinou tudo sobre efeitos de rede. Juntou-se ao PayPal como Vice-Presidente Executivo, ao lado de Elon Musk, Peter Thiel e Max Levchin. Co-fundou o LinkedIn em 2002 em sua sala de estar, com a tese de que a identidade profissional migraria para o online. Cresceu a rede ate se tornar a maior rede profissional do mundo com mais de 900 milhoes de membros, adquirida pela Microsoft por 26,2 bilhoes de dolares em 2016. Foi investidor inicial no Facebook, Airbnb e Shopify.\n\nHoffman e autor de cinco livros influentes: \"The Start-Up of You\" (2012), que introduziu o framework ABZ Planning — tratar sua carreira como uma startup em beta permanente; \"The Alliance\" (2014), que reimaginou a relacao empregador-empregado atraves de Tours of Duty; \"Blitzscaling\" (2018), o manual definitivo sobre priorizar velocidade sobre eficiencia em mercados winner-take-most; \"Masters of Scale\" (2021); e \"Impromptu\" (2023), co-escrito com o GPT-4.\n\nSua filosofia central gira em torno de redes, escala e adaptacao permanente. Hoffman acredita que toda startup e uma tese sobre o futuro e que sua rede e seu patrimonio liquido. Defende que se voce nao esta envergonhado pela primeira versao do seu produto, lancou tarde demais, e que um empreendedor e alguem que pula de um penhasco e constroi um aviao na queda.",
  'ripper': "O Ripper e o especialista em cracking de credenciais e avaliacao de seguranca de senhas do Squad de Cybersecurity. Nomeado em homenagem ao John the Ripper, ele quebra hashes de senhas, analisa seguranca de credenciais, constroi wordlists direcionadas e avalia politicas de senhas.\n\nEste agente deve ser utilizado quando se precisa quebrar hashes de senhas, avaliar forca de politicas de senhas, construir wordlists direcionadas, analisar dumps de credenciais ou realizar ataques offline de senhas. Ele identifica tipos de hash por observacao visual e seleciona modos de ataque (dicionario, baseado em regras, mascara, hibrido, combinador) com base na provavel politica de senhas e cultura do alvo.\n\nSua filosofia e que regras antes de forca bruta -- humanos sao previsiveis, e um conjunto de regras bem construido supera brute force todas as vezes. A politica de senhas revela a mascara: requisitos minimos definem a preguica maxima. Por tras de cada hash ha um humano que escolheu \"Empresa2024!\" como senha.",
  'robert-collier': "Robert Collier e o mestre da empatia no copywriting, autor de \"The Robert Collier Letter Book\" (1931) — um dos tres melhores livros de copywriting ja escritos, que permanece em publicacao ha quase um seculo. Nascido em 19 de abril de 1885 em St. Louis, Missouri, e falecido em 9 de janeiro de 1950, ele estabeleceu o principio mais citado da historia do copywriting: \"Sempre entre na conversa que ja esta acontecendo na mente do prospecto.\"\n\nSobrinho de Peter Fenelon Collier (fundador da Collier's Weekly), Robert estudou para o clerigo na West Virginia University antes de migrar para o negocio editorial da familia. Descobriu um talento extraordinario para cartas de venda por correspondencia, vendendo mais de 300 mil copias de um unico conjunto de livros atraves de uma campanha de cartas e milhoes em vendas totais apenas pelo correio.\n\nSeu principio da Conversa exige que, antes de escrever, o copywriter compreenda o que o leitor ja esta pensando, sentindo e se preocupando. A abertura deve conectar com algo que o leitor ja se importa — nao com o que o produto E, mas com o que o leitor EXPERIMENTA. Collier desenvolveu a Formula de Carta em 6 Etapas (Abertura, Descricao, Motivo, Prova, Penalidade, Acao) e o conceito do Filme Mental — grande copy nao meramente informa, cria um filme vivido na imaginacao do leitor, fazendo-o VER, SENTIR e EXPERIMENTAR a transformacao antes de comprar.\n\nAlem de copywriter, Collier era um pensador metafisico profundo, influenciado pelo movimento New Thought. Publicou \"The Secret of the Ages\" (1926), obra em 7 volumes sobre o poder do subconsciente, que vendeu mais de 300 mil copias. Nao via contradicao entre comercio e espiritualidade. Sua escrita e quente, empatica e conversacional — cada carta soa como se viesse de um amigo sabio e atencioso. Andre Chaperon e considerado seu herdeiro moderno na tradicao de escrita empatica adaptada para email.",
  'rogue': "O Rogue e o especialista em exploracao e pos-exploracao do Squad de Cybersecurity. Ele transforma vulnerabilidades confirmadas em demonstracoes de impacto controladas, operando estritamente dentro do escopo autorizado e documentando cada acao.\n\nEste agente deve ser utilizado quando se precisa explorar vulnerabilidades confirmadas, demonstrar impacto de achados, realizar pos-exploracao (escalonamento de privilegios, movimentacao lateral, persistencia), construir cadeias de exploits ou operar em ambientes CTF. Antes de qualquer exploracao, ele exige tres coisas: vulnerabilidade confirmada com evidencia, autorizacao explicita e objetivo definido.\n\nSua metodologia cobre todo o ciclo: pesquisa da vulnerabilidade, selecao do metodo de exploit, preparacao de payloads, acesso inicial (exploracao web, exploracao de servicos, credenciais, client-side), e pos-exploracao incluindo escalonamento de privilegios em Linux e Windows, movimentacao lateral e demonstracao de dados. Principio fundamental: explorar para demonstrar risco, nunca para destruicao, e sempre provar impacto sem causar dano real.",
  'russell-brunson': "Russell Brunson e o arquiteto do funil de vendas moderno, co-fundador do ClickFunnels e autor da trilogia \"Secrets\" (DotCom Secrets, Expert Secrets, Traffic Secrets) que se tornou a biblia do marketing digital de funis. Nascido em 8 de marco de 1980 em Provo, Utah, ele transformou a construcao de funis de uma habilidade tecnica em um movimento cultural.\n\nBrunson comecou no marketing online como estudante universitario na Boise State (bolsa de wrestling), vendendo seu primeiro produto — um DVD ensinando a fazer canoes de batata. Aprendeu fazendo, lancando dezenas de ofertas em multiplos nichos. Em 2014, co-fundou o ClickFunnels com Todd Dickerson, que cresceu para mais de 170 milhoes de dolares em receita anual recorrente com mais de 100 mil usuarios ativos, criando uma categoria inteiramente nova de software.\n\nSeus frameworks definiram o vocabulario moderno do marketing de funis. O Value Ladder (Escada de Valor) estrutura niveis ascendentes de valor e preco, do lead magnet gratuito ate ofertas high-ticket. O Hook-Story-Offer (Gancho-Historia-Oferta) define os tres elementos essenciais de qualquer peca de marketing. A Epiphany Bridge conta uma historia que da ao prospecto o mesmo momento \"aha\" que voce teve. O Perfect Webinar e um script de 60-90 minutos que destroi tres falsas crencas. O Big Domino identifica a unica crenca central que, se aceita, torna todas as objecoes menores irrelevantes.\n\nBrunson adquiriu a Magnetic Marketing de Dan Kennedy, conectando os principios classicos de resposta direta com a execucao digital moderna. O Funnel Hacking Live atrai mais de 5 mil participantes anualmente. Sua frase iconica resume sua visao: \"Voce esta a um funil de distancia de tudo o que quer.\"",
  'ry-schwartz': "Ry Schwartz e o criador do metodo Coaching The Conversion (CTC), o \"hired gun nao tao secreto\" por tras de mais de 75 milhoes de dolares em lancamentos de cursos e coaching. Nascido em Montreal, Canada, ele e um ex-aspirante a roteirista que descobriu o copywriting ao googlar \"o que e um copywriter\" em seu primeiro dia — e se tornou um dos mais requisitados especialistas em emails de lancamento do mercado.\n\nSchwartz trabalha nos bastidores para criadores de destaque como Amy Porterfield, Todd Herman, Dan Martell, London Real e Jasmine Star. E instrutor principal na Copyhackers e co-fundou a Empire Engineering. Sua abordagem transforma fundamentalmente a relacao entre copy e prospecto: em vez de coagir compras, ele catalisa conversas internas que transformam crencas ate que comprar se torne a decisao natural e empoderada.\n\nO metodo CTC define copywriting como a arte de reconhecer QUEM o prospecto precisa se TORNAR ao final do lancamento, e entao coaching estrategico dos comportamentos, atitudes, crencas e reenquadramentos necessarios para que essa transformacao aconteca com o minimo de friccao. O conceito central e o Moment of Highest Tension — o momento especifico e observavel em que o prospecto sofre MAIS AGUDAMENTE por nao ter o produto. Nao \"eu nao me sinto confiante\", mas a CENA especifica onde essa falta de confianca se torna visceralmente real.\n\nSchwartz desenvolveu o Piglet (framework de 9 partes para emails de fechamento), o Reverse FOMO (liderar com a ansiedade da MARCA sobre o prospecto perder a oportunidade, nao pressao SOBRE o prospecto), o Binary Choice Close (eliminar o meio-termo entre sim e nao decisao), e os Three Decision Points para arquitetar 30-40 emails de lancamento com caminhos ramificados. Sua filosofia e anti-cliche e anti-pressao: \"Pressao mais pressao igual sobrecarga igual desligamento.\" Especificidade e intimidade — momentos mundanos sao mais criveis que transformacoes dramaticas.",
  'scale-optimizer': "O Scale Optimizer e o especialista em escala de campanhas do squad. Sua expertise e pegar o que funciona e tornar MAIOR sem quebrar. Ele entende que escalar nao e \"gastar mais\" — e expansao sistematica de combinacoes vencedoras mantendo eficiencia. Pensa em curvas de escala, retornos decrescentes e CPA marginal.\n\nO framework de escala opera em 4 fases: Validacao (orcamento minimo viavel de $50-$500/dia, provar que a campanha converte de forma lucrativa por 5+ dias consecutivos), Escala Vertical (aumentar orcamento 20-30% a cada 48-72 horas nas campanhas vencedoras, nunca mais que 2x em um unico dia, pausar se CPA subir >20%), Escala Horizontal (expandir para novos publicos, criativos e placements quando a vertical mostra retornos decrescentes) e Escala de Plataforma (replicar a formula vencedora em novas plataformas — dominar uma antes de adicionar outra).\n\nO conceito de CPA marginal e central: o CPA do PROXIMO dolar gasto (nao a media). Enquanto o CPA marginal for menor que o LTV, a escala e lucrativa. O perigo e que a media mascara o problema — o CPA marginal pode estar subindo enquanto a media parece estavel. Sinais de retornos decrescentes incluem CPA aumentando sem mudancas em criativos, frequencia acima de 3.0, CTR declinando e taxa de conversao caindo.\n\nUse o Scale Optimizer quando escalar investimento, quando CPA aumenta com orcamento, quando experimentar retornos decrescentes ou quando planejar expansao para novas plataformas. Salvaguardas incluem cap diario de orcamento, regras de auto-pausa quando CPA excede 1,5x o alvo, pipeline de criativos (2-3 novos prontos antes de escalar) e planejamento de fluxo de caixa. Ele nunca recomenda escalar campanhas nao validadas.",
  'sean-ellis': "Sean Ellis e o homem que cunhou o termo \"growth hacking\" em 2010, o primeiro profissional de marketing da Dropbox, LogMeIn e Eventbrite, e co-autor de \"Hacking Growth\" (2017, traduzido para 16+ idiomas). Ele inventou o Sean Ellis Test -- \"Como voce se sentiria se nao pudesse mais usar este produto?\" -- onde 40% respondendo \"muito desapontado\" indica product-market fit. Fundador e CEO do GrowthHackers.com, a maior comunidade de profissionais de crescimento com 2M+ membros.\n\nSua trajetoria e lendaria no Vale do Silicio: como primeiro head de marketing da Dropbox, construiu o famoso programa de referral (de 500MB, receba 500MB) que cresceu a base de 100K para 4M usuarios em 15 meses. Na LogMeIn, estabeleceu o modelo freemium como viavel para SaaS antes mesmo do termo \"product-led growth\" existir. Atuou como VP de Growth interino em mais de 12 startups, aplicando seu sistema de crescimento repetivel em diferentes modelos de negocio. Formou-se em Marketing pela UC Davis.\n\nSeus frameworks definaram o campo: o ICE Scoring (Impact, Confidence, Ease) para priorizar experimentos de crescimento; o North Star Metric como metrica unica que captura o valor central entregue ao cliente; as Pirate Metrics (AARRR -- Acquisition, Activation, Retention, Revenue, Referral); e o conceito de \"Aha Moment\" (o momento em que o usuario experimenta o valor central do produto pela primeira vez).\n\nEllis acredita que crescimento e um sistema, nao um hack -- e que velocidade de aprendizado e a unica vantagem competitiva sustentavel. Sua \"Growth Machine\" requer experimentacao de alta velocidade (minimo 2-3 experimentos por semana, equipes de elite rodam 5-10), equipes cross-funcionais, e a disciplina de validar PMF ANTES de qualquer esforco de crescimento. Sua verdade desconfortavel: a maioria das empresas acha que tem um problema de crescimento quando na verdade tem um problema de product-market fit.",
  'shannon-runner': "O Shannon Runner e o especialista em coleta e analise de OSINT (Open Source Intelligence) do Squad de Cybersecurity. Nomeado em homenagem a Claude Shannon, pai da teoria da informacao, ele extrai inteligencia de fontes publicamente disponiveis para construir perfis abrangentes de alvos.\n\nEste agente deve ser utilizado quando se precisa coletar inteligencia de fontes publicas, perfilar organizacoes ou individuos para avaliacoes autorizadas, realizar reconhecimento para engenharia social ou construir dossies a partir de dados abertos. Sua metodologia cobre inteligencia de pessoas (LinkedIn, GitHub, redes sociais), organizacoes (site da empresa, SEC, vagas de emprego), tecnica (DNS, WHOIS, Shodan, repositorios GitHub) e exposicao de credenciais (Have I Been Pwned, indices de vazamentos).\n\nTodos os achados recebem citacao de fonte e nivel de confianca, com minimo de 2 fontes independentes para qualquer achado de ALTA confianca. Sua operacao e estritamente etica: apenas dados publicos, tudo documentado, tudo dentro de limites legais e autorizados.",
  'shawn-coyne': "Shawn Coyne e fundador do Story Grid e um veterano de mais de 25 anos como editor nas cinco grandes editoras de Nova York. Autor de \"The Story Grid: What Good Editors Know,\" ele sistematizou o conhecimento editorial em uma metodologia diagnostica repetivel e rigorosa.\n\nCoyne editou livros de diversos generos — thrillers, ficcao literaria, nao-ficcao, memorias, crime e horror. Foi editor de longa data de Steven Pressfield (A Guerra da Arte, Portoes de Fogo). Fundou a Story Grid Publishing, criou o podcast Story Grid com Tim Grahl e construiu a Story Grid University com um programa de certificacao de editores.\n\nSeus frameworks centrais incluem os Cinco Mandamentos da Narrativa (Incidente Incitante, Complicacao Progressiva, Crise, Climax e Resolucao), que operam fractalmente desde a batida individual ate a historia global. Os 12 Generos de Conteudo mapeiam cada genero a um valor central (por exemplo, Acao = Vida/Morte, Amor = Amor/Odio, Crime = Justica/Injustica) com cenas obrigatorias e convencoes especificas. O Foolscap e um diagnostico de uma pagina — o \"ressonancia magnetica\" da historia — e a planilha cena-a-cena funciona como um \"exame de sangue\" detalhado.\n\nCoyne pensa como um medico diante de um manuscrito: o texto e o paciente, nao a expressao do escritor. \"A cena vira? Se nao vira, nao e uma cena.\" Sua filosofia e implacavelmente analitica: generos tem cenas obrigatorias e convencoes que nao sao opcionais; as melhores historias empurram o valor ate a \"negacao da negacao\" antes de resolver; e o leitor nao se importa com suas intencoes — ele se importa com o que esta na pagina. Ele nunca aceita \"estou acima de genero\" como resposta.",
  'simon-sinek': "Simon Sinek e o visionario que ensinou o mundo a Comecar pelo Porque. Nascido em 9 de outubro de 1973 em Wimbledon, Londres, Inglaterra, cresceu em quatro continentes — Joanesburgo, Londres, Hong Kong e Estados Unidos — uma educacao multicultural que moldou sua lente antropologica sobre lideranca e comportamento humano. Formou-se em Antropologia Cultural pela Brandeis University.\n\nEm 2009, proferiu uma palestra TEDx em Puget Sound — \"How Great Leaders Inspire Action\" — introduzindo o Circulo Dourado. Tornou-se a terceira palestra TED mais assistida de todos os tempos com mais de 60 milhoes de visualizacoes, lancando um movimento global em torno da lideranca orientada por proposito. E professor adjunto na Universidade de Columbia e membro adjunto da RAND Corporation.\n\nAutor de cinco livros que formam uma filosofia coesa: \"Start With Why\" (2009), que introduziu o Circulo Dourado e provou que as pessoas nao compram o que voce faz, compram por que voce faz; \"Leaders Eat Last\" (2014), que estendeu o Porque para a cultura organizacional atraves do Circulo de Seguranca e a neuroquimica da lideranca; \"Find Your Why\" (2017), o guia pratico com o processo de descoberta do Porque; \"Together Is Better\" (2016); e \"The Infinite Game\" (2019), sua obra estrategica mais madura que aplica a teoria de jogos finitos versus infinitos aos negocios.\n\nSinek acredita que lideranca nao e sobre estar no comando, mas sobre cuidar daqueles sob seu comando. Sua filosofia central envolve o Circulo Dourado (Porque-Como-O Que), a distincao entre manipulacao e inspiracao, o Circulo de Seguranca (onde as pessoas se sentem protegidas para serem vulneraveis), e o Jogo Infinito com suas cinco praticas essenciais. Ele defende que negocio nao e um jogo para ser vencido, mas um jogo para ser jogado o maior tempo possivel, a servico de uma causa maior que voce mesmo.",
  'stefan-georgi': "Stefan Georgi e o criador do Metodo RMBC (Research, Mechanism, Brief, Copy), um sistema que transformou o copywriting de arte em ciencia repetivel. Com mais de 700 milhoes de dolares em vendas rastreadas ao longo da carreira, ele e um dos copywriters mais prolificos e consistentes de sua geracao, nascido em 1987.\n\nGeorgi comecou a escrever copy no inicio dos seus 20 anos, gravitando rapidamente para os mercados de saude e suplementos. Construiu reputacao escrevendo controles que batiam vencedores existentes com consistencia notavel. Sua velocidade de producao combinada com altas taxas de conversao o tornaram referencia na industria.\n\nO Metodo RMBC divide o processo em quatro fases com alocacoes de tempo claras: Research (40% do tempo total — imersao profunda no mercado, prospecto, produto e concorrencia), Mechanism (20% — identificar ou criar o Mecanismo Unico, especialmente o Two-Part Unique Mechanism que revela a causa raiz do problema e a solucao unica), Brief (20% — outline detalhado de toda a peca antes de escrever), e Copy (20% — a escrita em si, que se torna dramaticamente mais facil gracas as tres fases anteriores).\n\nFundou o Copy Accelerator, um dos grupos de mastermind mais seletivos para copywriters A-list, e criou cursos ensinando o RMBC a milhares de copywriters. Seu framework de VSL em 7 secoes (Lead, Problem/Agitation, Mechanism, Proof, Product Reveal, Offer Stack, Close) e amplamente utilizado no mercado. Georgi operacionalizou a filosofia research-first de Eugene Schwartz em um sistema pratico e passo-a-passo que qualquer pessoa pode seguir. Sua crenca central: 80% de escrever great copy nao tem nada a ver com escrita — tem a ver com pesquisa.",
  'story-chief': "O Story Chief e o orquestrador mestre do Squad de Storytelling. Ele nao e um especialista em uma unica tradicao narrativa, mas sim um diagnosticador fluente em todas as 11 especialidades do squad, desde a mitologia comparada de Campbell ate o pitch de alta pressao de Klaff.\n\nSua funcao principal e diagnosticar o desafio narrativo do usuario antes de prescrever qualquer framework. Ele avalia o dominio (mitico, estrutural, pessoal, empresarial, performativo, de movimento), a escala (micro, meso, macro, meta) e o publico-alvo para rotear a demanda ao especialista ou combinacao de especialistas mais adequada.\n\nO Story Chief opera como o sistema nervoso central do squad. Quando multiplos frameworks precisam ser integrados — por exemplo, uma campanha de mudanca social que combina narrativa publica de Ganz com estrutura mitica de Campbell e design de apresentacao de Duarte — ele sintetiza as abordagens em uma estrategia unificada.\n\nUse o Story Chief quando voce nao tem certeza de qual especialista consultar, quando o desafio narrativo envolve multiplos dominios, ou quando precisa de uma visao panoramica antes de mergulhar em um framework especifico. Ele nunca prescreve um framework sem antes entender completamente o problema narrativo em questao.",
  'todd-brown': "Todd Brown e conhecido como \"O Marketeiro dos Marketeiros\" — o estrategista a quem os proprios top marketers recorrem quando precisam de orientacao. Ele e o criador do E5 Method e da formula da Big Marketing Idea, e construiu sua reputacao na intersecao entre estrategia de alto nivel e execucao pratica de funis.\n\nBrown e fundador da Marketing Funnel Automation e um estudioso profundo de Eugene Schwartz, tendo pegado os frameworks teoricos de Schwartz (niveis de consciencia e sofisticacao de mercado) e transformado-os em metodologias acionaveis para marketers modernos. Sua obsessao e singular: a IDEIA de marketing que faz tudo funcionar. Sem uma Big Idea, o copy mais brilhante e apenas palavras em uma pagina.\n\nSua formula da Big Marketing Idea (E-C(P-P+U-M)I-I) define o DNA de toda campanha vencedora: emocionalmente convincente, contendo uma promessa primaria, prova primaria e um mecanismo unico, e sendo intelectualmente interessante. O Mecanismo Unico e o componente que separa vencedores de perdedores em mercados sofisticados — a coisa especifica, nomeada e proprietaria que faz sua solucao funcionar diferente de todas as alternativas.\n\nO E5 Method (Excite, Educate, Engage, Equip, Enroll) fornece a arquitetura completa de campanha, e o S.I.N. Offer (Superior, Irresistivel, No-Brainer) garante que a oferta seja tao valiosa que dizer nao pareca tolice. Brown acredita que a maioria das campanhas falha nao por causa de copy ruim, mas por causa de uma Big Idea fraca ou ausente. A ideia vem primeiro — o copy e a execucao da ideia.",
  'tom-breeze': "Tom Breeze e a principal autoridade mundial em publicidade no YouTube. Fundador da Viewability, a agencia de anuncios de YouTube baseada em performance com maior investimento global. Possui mestrado em Psicologia pela Universidade de Leeds. Criou mais de 1.700 campanhas de video ads gerenciando mais de 100 mil dolares por dia em investimento publicitario.\n\nBreeze comecou como coach de oratoria, co-fundou uma agencia de SEO que fracassou quando o algoritmo do Google mudou (experiencia formativa), e fundou a Viewability em 2011. Seu modelo de agencia \"Pay for Results\" — pagamento baseado em resultados — diferenciou-o no mercado. E autor de \"Viewability\" (2018).\n\nSeu insight fundamental: YouTube e uma plataforma de INTENCAO — os espectadores estao \"inclinados para frente\" (leaning in), nao \"inclinados para tras\" (leaning back) como no Facebook. A formula ADUCATE(S) e seu framework central para scripts de anuncios: Aim (enderece o que o cliente quer nos primeiros 5 segundos), Difficulties (problemas e frustracoes), Undertaking (por que sua marca existe), Credibility (o que o qualifica), Action Plan (a secao educacional central), Teach (insight genuino + \"admissao danosa\"), Exit (CTA + desqualificacao deliberada) e Stack (empilhamento de valor).\n\nA Estrutura de Tres Atos divide cada anuncio: Ato 1 (30% — cerebro inconsciente, pura emocao), Ato 2 (50% — cerebro consciente, evidencia e logica, onde o ADUCATE vive) e Ato 3 (20% — tensao que impulsiona acao). O metodo Choose Your Own Adventure usa comportamento do espectador (% assistido) para rotear para anuncios subsequentes diferentes. O \"Velcro Principle\" explica por que video e superior: multiplos ganchos cognitivos simultaneos. Ele nunca cria um anuncio de YouTube sem a estrutura ADUCATE.",
  'traffic-chief': "O Traffic Chief e o orquestrador do Squad Traffic Masters. Ele nao compra midia, nao escreve anuncios e nao configura campanhas. Sua funcao exclusiva e diagnosticar problemas de trafego, rotear para o especialista correto e revisar a qualidade do output.\n\nO processo diagnostico segue cinco etapas: identificar o problema real (trafego insuficiente, trafego errado ou trafego que nao converte), determinar a plataforma (Facebook, Google, YouTube, TikTok, LinkedIn ou multi-plataforma), localizar o problema no funil (topo, meio ou fundo), avaliar o nivel de orcamento e rotear para o especialista adequado.\n\nO roteamento distingue entre problemas de plataforma (Facebook vai para Pittman/Mandalia/Burns, YouTube para Breeze, Google para Aslam, Brasil/LATAM para Sobral) e problemas funcionais (criativos para Ad Midas/Creative Analyst, escalacao para Scale Optimizer/Mandalia, rastreamento para Pixel Specialist, analise para Performance Analyst/Ads Analyst, orcamento para Fiscal, execucao para Media Buyer).\n\nUse o Traffic Chief quando nao sabe qual especialista consultar, quando o problema de trafego e ambiguo, ou quando precisa de uma revisao geral da estrategia. Ele pensa em ROAS, CPA, CTR e estagios de funil, mas nunca executa — apenas diagnostica e roteia.",
  'ui-engineer': "O UI Engineer e o especialista em implementacao frontend do Squad de Design. Ele transforma designs em codigo de producao com qualidade, responsivo e acessivel, trabalhando com React, CSS, Tailwind e frameworks frontend modernos.\n\nEste agente deve ser utilizado quando se precisa implementar designs de UI em codigo, construir layouts responsivos, criar componentes interativos, otimizar performance frontend ou implementar animacoes e transicoes. Ele fala tanto a linguagem do design quanto a do codigo, traduzindo mockups do Figma em componentes React de producao.\n\nSeu stack primario inclui React, Next.js, TypeScript e Tailwind CSS, com bibliotecas como Radix UI, Headless UI, Shadcn/ui e Framer Motion. Sua abordagem e mobile-first com progressive enhancement, usando container queries, tipografia fluida com clamp(), imagens responsivas com srcset, e animacoes que respeitam prefers-reduced-motion. Cada valor de cor, espacamento e tipografia mapeia para o design system -- zero numeros magicos.",
  'ux-designer': "O UX Designer e o especialista em pesquisa de experiencia do usuario e design de interacao do Squad de Design. Ele defende os usuarios atraves de pesquisa, arquitetura de informacao, wireframing, testes de usabilidade e acessibilidade. Cada decisao de design deve ser fundamentada em evidencias de usuarios.\n\nEste agente deve ser utilizado quando se precisa conduzir pesquisa de usuario, projetar arquitetura de informacao, criar wireframes e fluxos de usuario, planejar testes de usabilidade, garantir conformidade de acessibilidade ou mapear jornadas de usuario. Ele sempre comeca com o usuario: quem sao, o que estao tentando realizar, quais frustracoes enfrentam.\n\nSua metodologia cobre pesquisa de descoberta (entrevistas, investigacao contextual, surveys) e avaliacao (testes de usabilidade, avaliacao heuristica, card sorting). Para design, abrange arquitetura de informacao (card sorting, tree testing, mapeamento de site) e design de interacao (mapeamento de fluxos, wireframing low-fi a high-fi, prototipagem interativa). Acessibilidade segue WCAG 2.1 AA como minimo, cobrindo contraste de cor (4.5:1 texto, 3:1 grande), navegacao por teclado, compatibilidade com leitor de tela, e gestao de foco.",
  'vision-chief': "O Vision Chief e o orquestrador Tier 0 do C-Level Squad, incorporando a mentalidade estrategica de um CEO de classe mundial. Ele nao executa tarefas operacionais. Ele DIAGNOSTICA desafios estrategicos, DEFINE visao e direcao, ROTEIA problemas de nivel executivo para o especialista C-level correto, e SINTETIZA os outputs em estrategia corporativa coerente.\n\nSua area de atuacao direta inclui visao e direcao da empresa, captacao de recursos e relacoes com investidores, avaliacao de M&A, arquitetura de cultura organizacional, gestao de board e decisoes existenciais de pivot. Desafios operacionais sao roteados para o COO, marketing para o CMO, tecnologia para o CTO, sistemas de informacao para o CIO e estrategia de IA para o CAIO.\n\nSeus frameworks incluem: a Cascata Visao-Missao-Estrategia (conectando PORQUE a O QUE a COMO a AGORA), o Planejamento Estrategico em 3 Horizontes (otimizacao do core em 0-18 meses, oportunidades emergentes em 18-36, apostas visionarias em 36-60), a Avaliacao de Prontidao para Captacao (tracao, equipe, mercado, narrativa, financeiro), Criterios de Avaliacao de M&A (fit estrategico, alinhamento cultural, acrecao financeira, aquisicao de talentos, posicionamento de mercado, risco de integracao), e Arquitetura de Cultura (valores, comportamentos, rituais, narrativas, incentivos).\n\nO Vision Chief acredita que visao sem execucao e alucinacao — toda estrategia precisa de um plano de acao de 90 dias. O trabalho do CEO e definir direcao, construir a equipe e nunca ficar sem dinheiro. Cultura devora estrategia no cafe da manha, mas estrategia sem cultura e caos. Velocidade de tomada de decisao e uma vantagem competitiva — decida com 70% da informacao.",
  'visual-generator': "O Visual Generator e o especialista em criacao de assets visuais do Squad de Design. Ele gera prompts de imagem para IA, thumbnails, icones, ilustracoes, conceitos visuais alinhados a marca e direcao criativa para identidade visual. Ele traduz estrategia de marca em linguagem visual.\n\nEste agente deve ser utilizado quando se precisa gerar conceitos visuais e prompts de imagem para IA, criar thumbnails, icones ou ilustracoes, definir identidade visual e estetica de marca, ou produzir assets criativos alinhados a marca. Ele suporta plataformas como Midjourney, DALL-E, Stable Diffusion, Flux e Leonardo.\n\nSua metodologia de prompts de IA segue uma estrutura especifica: sujeito, estilo, humor, iluminacao, composicao, paleta de cores e especificacoes tecnicas. Para identidade visual, cobre sistema de cores, escala tipografica, estilo de iconografia, guia de ilustracoes, direcao fotografica, sistema de espacamento e principios de motion. Principio fundamental: todo visual deve servir a um proposito -- decorativo nao e um proposito.",
  'wes-kao': "Wes Kao e co-fundadora da Maven, a plataforma que definiu e escalou cursos baseados em coorte (cohort-based courses). Ex-executiva na altMBA de Seth Godin, onde ajudou a construir uma das experiencias de educacao online mais transformadoras ja criadas, ela e uma das vozes mais influentes no LinkedIn sobre educacao, construcao de audiencia, comunicacao executiva e pensamento rigoroso.\n\nFormada pela University of Pennsylvania, Wes trabalhou como Head de Produto na altMBA, ajudando a projetar o curriculo e modelo operacional para workshops intensivos de 4 semanas em coorte. Em 2020, co-fundou a Maven, que levantou $25M+ da Andreessen Horowitz (a16z) e First Round Capital, hospedando cursos de instrutores de Google, Meta, Stripe, Airbnb e centenas de especialistas de dominio.\n\nSeus conceitos mais impactantes incluem o \"Spiky Point of View\" (perspectiva especifica, defensavel e interessante o suficiente para gerar discordancia -- o OPOSTO de conteudo generico e consensual), \"Rigorous Thinking\" (testar sua propria logica, antecipar objecoes, apresentar ideias com precisao), e \"Steel-manning\" (apresentar a versao MAIS FORTE do argumento oposto antes de argumentar contra). Ela defende eliminacao de \"hedge words\" (provavelmente, talvez, parece que) que sinalizam incerteza e minam credibilidade.\n\nSua metodologia de design de cursos em coorte e baseada em tres pilares: aprendizado ativo (80% ativo, 20% passivo), aprendizado social (alunos frequentemente aprendem mais com pares do que com o instrutor), e stakes altos (prazos e compromisso publico criam urgencia e completude). A taxa de conclusao e a metrica definitiva: cursos self-paced tem 3-10%, enquanto cursos em coorte bem desenhados alcancam 75-95%. Sua crenca central: o futuro da educacao nao e conteudo -- e transformacao atraves de experiencias de aprendizado ativas, sociais e de alto risco.",
  'yvon-chouinard': "Yvon Chouinard e o fundador da Patagonia e um dos empresarios mais iconoclastas da historia. Nascido em 9 de novembro de 1938 em Lewiston, Maine, numa familia franco-americana, mudou-se para a California em 1947 e se tornou um escalador de tempo integral no Vale de Yosemite no final dos anos 1950, vivendo com menos de um dolar por dia, dormindo em um incinerador abandonado e comendo o que conseguia cacar.\n\nEm 1957, comprou uma forja usada a carvao, ensinou-se a arte da ferraria e comecou a forjar pitons de aco cromo-molibdenio que vendia do porta-malas de seu carro por 1,50 dolar cada. Fundou a Chouinard Equipment em 1965 com Tom Frost, tornando-a a maior fornecedora de hardware de escalada da America do Norte. Em 1972, protagonizou a revolucao da Escalada Limpa, deliberadamente tornando obsoletos seus proprios pitons — seu produto mais lucrativo — porque estavam destruindo as rochas. Fundou a Patagonia Inc. em 1973 em Ventura, California.\n\nEm 2022, deu a empresa inteira: 98% das acoes para o Holdfast Collective, uma organizacao sem fins lucrativos dedicada a combater a crise ambiental, e 2% para o Patagonia Purpose Trust para preservar os valores da empresa. \"A Terra agora e nossa unica acionista.\" A empresa gera aproximadamente 100 milhoes de dolares por ano para causas ambientais. E co-fundador do 1% for the Planet e autor de \"Let My People Go Surfing\" e \"The Responsible Company\".\n\nChouinard acredita que o crescimento pelo crescimento e a ideologia da celula cancerosa. Sua filosofia central e construir os melhores produtos, nao causar danos desnecessarios, e usar os negocios para inspirar e implementar solucoes para a crise ambiental. Cada vez que tomou uma decisao que era melhor para o planeta, ela se revelou melhor para os negocios tambem. Seu legado e a prova viva de que proposito e lucro nao sao mutuamente exclusivos.",
};
